                                 </div>
                               )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>
              {isEditing && (
                <div className="flex gap-2">
                  <button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 font-black uppercase"><ArrowLeftRight size={14} className="inline mr-2"/> Switch Size Format</button>
                  <button type="button" onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]})} className="text-[10px] bg-indigo-600 text-white px-4 py-2 rounded-xl font-black uppercase hover:bg-indigo-700 transition-all">+ Add Color</button>
                </div>
              )}
            </div>
            <div className="border border-slate-200 rounded-3xl overflow-hidden shadow-sm bg-white">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r">Color Variant</th>
                    {getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}
                    <th className="p-4 bg-slate-100">Sum</th>
                    {isEditing && <th className="p-4 w-12"></th>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-4 text-left font-black text-slate-700 border-r">
                        {isEditing ? (
                          <input className="w-full border rounded p-1 font-bold text-sm" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/>
                        ) : row.color}
                      </td>
                      {['s','m','l','xl','xxl','xxxl'].map(key => (
                        <td key={key} className="p-4 border-r">
                          {isEditing ? (
                            <input type="number" className="w-16 border rounded p-1 text-center font-black" value={(row as any)[key]} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; (bd[idx] as any)[key] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/>
                          ) : (order.size_breakdown?.[idx]?.[key as keyof SizeBreakdown] || 0)}
                        </td>
                      ))}
                      <td className="p-4 font-black text-slate-900 bg-slate-50/50 tabular-nums">{getRowTotal(row)}</td>
                      {isEditing && (
                        <td className="p-4">
                          <button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600 transition-colors">
                            <Trash2 size={20}/>
                          </button>
                        </td>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm">
              <span className="block text-[11px] text-slate-400 uppercase font-black mb-3">Master production notes</span>
              {isEditing ? (
                <textarea className="w-full border border-slate-200 rounded-2xl p-4 h-48 font-medium text-sm" value={editFormData.description} onChange={e => setEditFormData({...editFormData, description: e.target.value})}/>
              ) : (
                <p className="text-xl text-slate-800 font-black whitespace-pre-wrap leading-relaxed">{order.description || 'N/A'}</p>
              )}
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-3xl border border-indigo-100 shadow-inner">
              <h4 className="font-black text-indigo-400 uppercase text-[10px] flex items-center gap-2 mb-4">
                <Paperclip size={14}/> Technical documents
              </h4>
              <div className="space-y-3">
                {(isEditing ? editFormData.attachments : order.attachments)?.map((att, i) => (
                  <div key={i} className="flex items-center justify-between p-4 bg-white rounded-xl border border-indigo-50 group hover:shadow-md transition-all">
                    <a href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-4 flex-1">
                      {att.type === 'image' ? <ImageIcon size={20} className="text-indigo-400" /> : <FileText size={20} className="text-indigo-400" />}
                      <span className="text-sm font-black text-slate-700 truncate">{att.name}</span>
                    </a>
                    {isEditing && (
                      <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500 transition-colors">
                        <Trash2 size={20}/>
                      </button>
                    )}
                  </div>
                ))}
                {isEditing && (
                  <div className="mt-4 border-2 border-dashed border-indigo-100 rounded-2xl p-6 text-center relative hover:bg-white transition-all cursor-pointer">
                    <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/>
                    <Upload size={32} className="mx-auto text-indigo-400"/>
                    <p className="text-[10px] font-black text-indigo-600 uppercase mt-2 tracking-widest">Add technical files</p>
                  </div>
                )}
                {selectedFiles.length > 0 && isEditing && (
                  <div className="mt-2 space-y-1">
                    {selectedFiles.map((f, idx) => (
                      <div key={idx} className="text-[10px] font-bold text-indigo-500 bg-white px-2 py-1 rounded border border-indigo-100 flex justify-between items-center">
                        {f.name}
                        <button type="button" onClick={() => setSelectedFiles(prev => prev.filter((_, i) => i !== idx))}><X size={10}/></button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col">
            <h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6">
              <Clock size={16}/> Lifecycle status log
            </h4>
            <div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">
              {modalLogs.map(log => (
                <div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2 transition-all hover:border-indigo-400">
                  <div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">
                    {new Date(log.created_at).toLocaleDateString()}<br/>
                    <span className="text-indigo-400 opacity-60 font-bold">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                  </div>
                  <div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-200">
                    <p className="text-slate-700 font-bold leading-snug">{log.message}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 border-t bg-slate-50 flex justify-between items-center">
          <div className="flex gap-2">
            {!isEditing && (
              <button onClick={() => { if(confirm("Permanently delete this order?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all">
                <Trash2 size={24}/>
              </button>
            )}
            {isEditing && (
              <button onClick={() => { setIsEditing(false); setEditFormData({...order}); setLinkedStyle(null); setSelectedFiles([]); }} className="px-6 py-3 bg-white text-slate-400 border border-slate-200 rounded-xl font-black uppercase text-xs hover:bg-slate-100 transition-all">
                Cancel
              </button>
            )}
          </div>
          <div className="flex items-center gap-4">
            <button onClick={handlePrintMaterialForecast} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-600 rounded-xl font-black uppercase text-[10px] flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all">
              <Calculator size={16}/> Print Material Forecast
            </button>
            <button onClick={handlePrint} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all"><Printer size={16}/> Print Job Sheet</button>
            {!isEditing && <button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs hover:bg-slate-700 transition-all">Close</button>}
            {isEditing && (
              <button 
                onClick={handleSave} 
                disabled={isUploading} 
                className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all flex items-center gap-2"
              >
                {isUploading ? <Loader2 className="animate-spin" size={16}/> : <Save size={18}/>}
                {isUploading ? 'Saving...' : 'Save Changes'}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, fetchUnits, fetchBarcodes, triggerOrderEmail, fetchOrderLogs } from '../services/db';
import { Order, Unit, OrderStatus, BarcodeStatus, formatOrderNumber, OrderLog } from '../types';
import { BarChart3, PieChart, PlusCircle, ClipboardList, Printer } from 'lucide-react';
import { DashboardStats } from '../components/admin/DashboardStats';
import { MasterOrderList } from '../components/admin/MasterOrderList';
import { LaunchOrderModal } from '../components/admin/LaunchOrderModal';
import { AdminOrderDetailsModal } from '../components/admin/AdminOrderDetailsModal';

export const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'reports'>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
  const [liveStockCount, setLiveStockCount] = useState(0);
  const [activeOrderCount, setActiveOrderCount] = useState(0);
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [isLaunchModalOpen, setIsLaunchModalOpen] = useState(false);
  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [reportLoading, setReportLoading] = useState(false);

  const loadData = async () => {
    const [fetchedOrders, fetchedUnits, fetchedStock] = await Promise.all([
        fetchOrders(), 
        fetchUnits(),
        fetchBarcodes(BarcodeStatus.COMMITTED_TO_STOCK)
    ]);
    setOrders(fetchedOrders);
    setUnits(fetchedUnits);
    setLiveStockCount(fetchedStock.length);
    setActiveOrderCount(fetchedOrders.filter(o => o.status !== OrderStatus.COMPLETED).length);
  };

  useEffect(() => { loadData(); }, [activeTab]);

  const handleSendEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerOrderEmail(orderId, false);
    setEmailLoading(null);
    alert(result.message);
  };

  const handlePrintUnitReport = async () => {
    setReportLoading(true);
    try {
      const inProgressOrders = orders.filter(o => o.status === OrderStatus.IN_PROGRESS);
      const assignedOrders = orders.filter(o => o.status === OrderStatus.ASSIGNED);

      // Fetch all logs to filter for those belonging to in-progress orders
      const allLogs = await fetchOrderLogs();
      const inProgressOrderIds = inProgressOrders.map(o => o.id);
      const relevantLogs = allLogs.filter(log => inProgressOrderIds.includes(log.order_id));

      const win = window.open('', 'UnitReport', 'width=1000,height=800');
      if (win) {
        const logRows = relevantLogs.map(log => {
          const order = inProgressOrders.find(o => o.id === log.order_id);
          return `
            <tr>
              <td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">${order ? formatOrderNumber(order) : 'UNK'}</td>
              <td style="padding: 8px; border: 1px solid #ddd; font-size: 11px;">${new Date(log.created_at).toLocaleString()}</td>
              <td style="padding: 8px; border: 1px solid #ddd; font-weight: 500;">${log.message}</td>
            </tr>
          `;
        }).join('');

        const assignedRows = assignedOrders.map(order => `
          <tr>
            <td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">${formatOrderNumber(order)}</td>
            <td style="padding: 8px; border: 1px solid #ddd;">${order.style_number}</td>
            <td style="padding: 8px; border: 1px solid #ddd; text-align: center;">${order.quantity}</td>
            <td style="padding: 8px; border: 1px solid #ddd; text-align: center;">${order.target_delivery_date}</td>
          </tr>
        `).join('');

        win.document.write(`
          <html>
          <head>
            <title>Unit Production Report</title>
            <style>
              body { font-family: sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; }
              .header { border-bottom: 4px solid #000; padding-bottom: 20px; margin-bottom: 30px; text-align: center; }
              .brand { font-size: 28px; font-weight: 900; }
              .title { font-size: 16px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-top: 5px; }
              .section-title { font-size: 14px; font-weight: 900; background: #f1f5f9; padding: 10px; border-left: 5px solid #4f46e5; margin: 30px 0 15px 0; text-transform: uppercase; }
              table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; }
              th { background: #f8fafc; text-align: left; padding: 10px; border: 1px solid #ddd; text-transform: uppercase; font-size: 10px; }
              .footer { margin-top: 40px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #eee; padding-top: 20px; }
            </style>
          </head>
          <body>
            <div class="header">
              <div class="brand">TINTURA SST</div>
              <div class="title">Manufacturing Unit Status Report</div>
              <div style="font-size: 12px; margin-top: 10px;">Generated: ${new Date().toLocaleString()}</div>
            </div>

            <div class="section-title">Recent Activity (In-Progress Jobs)</div>
            ${relevantLogs.length === 0 ? '<p style="color: #94a3b8; font-style: italic;">No recent updates found for in-progress orders.</p>' : `
            <table>
              <thead>
                <tr>
                  <th width="180">Order Ref</th>
                  <th width="180">Update Time</th>
                  <th>Timeline Message</th>
                </tr>
              </thead>
              <tbody>${logRows}</tbody>
            </table>
            `}

            <div class="section-title">Pending Queue (Assigned Jobs)</div>
            ${assignedOrders.length === 0 ? '<p style="color: #94a3b8; font-style: italic;">No orders in assigned queue.</p>' : `
            <table>
              <thead>
                <tr>
                  <th>Order Ref</th>
                  <th>Style Reference</th>
                  <th style="text-align: center;">Batch Vol</th>
                  <th style="text-align: center;">Target Date</th>
                </tr>
              </thead>
              <tbody>${assignedRows}</tbody>
            </table>
            `}

            <div class="footer">
              End of Document. This report tracks active floor activity across the facility.
            </div>
            <script>window.onload = () => { window.print(); };</script>
          </body>
          </html>
        `);
        win.document.close();
      }
    } catch (err) {
      console.error(err);
      alert("Failed to generate report.");
    } finally {
      setReportLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">
          {activeTab === 'overview' ? 'Executive Dashboard' : 'Analytics & Reports'}
        </h2>
        <div className="flex items-center gap-2">
            <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('overview')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'overview' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><BarChart3 size={18}/> Overview</button>
                <button onClick={() => setActiveTab('reports')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><PieChart size={18}/> Reports</button>
            </div>
            {activeTab === 'overview' && (
                <div className="flex gap-2">
                  <button 
                    onClick={handlePrintUnitReport} 
                    disabled={reportLoading}
                    className="bg-white border-2 border-indigo-600 text-indigo-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-50 shadow-md transition-all active:scale-95 disabled:opacity-50"
                  >
                    {reportLoading ? <Loader2 size={20} className="animate-spin" /> : <ClipboardList size={20} />}
                    <span>Unit Report</span>
                  </button>
                  <button onClick={() => setIsLaunchModalOpen(true)} className="bg-indigo-600 text-white px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95">
                    <PlusCircle size={20} /><span>Launch New Order</span>
                  </button>
                </div>
            )}
        </div>
      </div>

      {activeTab === 'overview' ? (
        <div className="space-y-6 animate-fade-in">
            <DashboardStats liveStockCount={liveStockCount} activeOrderCount={activeOrderCount} />
            <MasterOrderList 
              orders={orders} 
              units={units} 
              onRefresh={loadData} 
              onViewDetails={setDetailsModal} 
              onSendEmail={handleSendEmail} 
              emailLoading={emailLoading}
            />
        </div>
      ) : (
        <div className="bg-white p-20 rounded-2xl border border-slate-200 text-center text-slate-400 animate-fade-in">
           <PieChart size={48} className="mx-auto mb-4 opacity-20"/>
           <p className="text-lg font-bold">Reporting Suite</p>
           <p className="text-sm">Detailed production analytics and performance KPIs are currently being compiled.</p>
        </div>
      )}

      <LaunchOrderModal 
        isOpen={isLaunchModalOpen} 
        onClose={() => setIsLaunchModalOpen(false)} 
        units={units} 
        onSuccess={loadData} 
      />

      {detailsModal && (
        <AdminOrderDetailsModal 
          order={detailsModal} 
          units={units} 
          onClose={() => setDetailsModal(null)} 
          onRefresh={loadData} 
        />
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, fetchUnits, fetchBarcodes, triggerOrderEmail, fetchOrderLogs } from '../services/db';
import { Order, Unit, OrderStatus, BarcodeStatus, formatOrderNumber, OrderLog } from '../types';
// Added Loader2 to the imports from lucide-react
import { BarChart3, PieChart, PlusCircle, ClipboardList, Printer, Loader2 } from 'lucide-react';
import { DashboardStats } from '../components/admin/DashboardStats';
import { MasterOrderList } from '../components/admin/MasterOrderList';
import { LaunchOrderModal } from '../components/admin/LaunchOrderModal';
import { AdminOrderDetailsModal } from '../components/admin/AdminOrderDetailsModal';

export const AdminDashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'reports'>('overview');
  const [orders, setOrders] = useState<Order[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
