                      <td style="padding: 10px; width: 160px; color: #64748b; font-weight: bold; border-right: 1px solid #e2e8f0;">${new Date(log.created_at).toLocaleString()}</td>
                      <td style="padding: 10px; color: #1e293b; font-weight: 500;">${log.message}</td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `;
        }).join('');

        const assignedRows = assignedOrders.map(order => `
          <tr>
            <td style="padding: 10px; border: 1px solid #ddd; font-weight: bold;">${formatOrderNumber(order)}</td>
            <td style="padding: 10px; border: 1px solid #ddd;">${order.style_number}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center; font-weight: bold;">${order.quantity}</td>
            <td style="padding: 10px; border: 1px solid #ddd; text-align: center;">${order.target_delivery_date}</td>
          </tr>
        `).join('');

        win.document.write(`
          <html>
          <head>
            <title>Unit Production Report</title>
            <style>
              body { font-family: sans-serif; padding: 40px; color: #1e293b; line-height: 1.5; background: #fff; }
              .header { border-bottom: 4px solid #000; padding-bottom: 20px; margin-bottom: 30px; text-align: center; }
              .brand { font-size: 28px; font-weight: 900; letter-spacing: 1px; }
              .title { font-size: 16px; font-weight: bold; color: #64748b; text-transform: uppercase; margin-top: 5px; }
              .section-title { font-size: 14px; font-weight: 900; background: #f1f5f9; padding: 10px 15px; border-left: 6px solid #1e293b; margin: 40px 0 20px 0; text-transform: uppercase; letter-spacing: 1px; }
              table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 12px; }
              th { background: #f8fafc; text-align: left; padding: 12px; border: 1px solid #ddd; text-transform: uppercase; font-size: 10px; color: #64748b; }
              .footer { margin-top: 50px; text-align: center; font-size: 10px; color: #94a3b8; border-top: 1px solid #eee; padding-top: 20px; }
              @media print { body { padding: 20px; } .section-title { -webkit-print-color-adjust: exact; } }
            </style>
          </head>
          <body>
            <div class="header">
              <div class="brand">TINTURA SST</div>
              <div class="title">Manufacturing Unit Executive Report</div>
              <div style="font-size: 11px; margin-top: 10px; font-weight: bold; color: #94a3b8;">DISPATCHED: ${new Date().toLocaleString()}</div>
            </div>

            <div class="section-title">Recent Timeline Activity (Last 5 Global Updates)</div>
            ${recentLogs.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">No recent floor activity logs recorded for in-progress jobs.</p>' : logSectionsHtml}

            <div class="section-title">Queue Status (Assigned & Unstarted Jobs)</div>
            ${assignedOrders.length === 0 ? '<p style="color: #94a3b8; font-style: italic; text-align: center; padding: 20px;">Assigned queue is currently empty.</p>' : `
            <table>
              <thead>
                <tr>
                  <th width="150">Order Ref</th>
                  <th>Style Reference</th>
                  <th width="100" style="text-align: center;">Batch Vol</th>
                  <th width="120" style="text-align: center;">Target Date</th>
                </tr>
              </thead>
              <tbody>${assignedRows}</tbody>
            </table>
            `}

            <div class="footer">
              This report is generated automatically by Tintura SST HQ. 
              <br/>For internal manufacturing supervision only.
            </div>
            <script>window.onload = () => { setTimeout(() => { window.print(); }, 500); };</script>
          </body>
          </html>
        `);
        win.document.close();
      }
    } catch (err) {
      console.error(err);
      alert("Critical: Failed to compile unit report.");
    } finally {
      setReportLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center gap-4">
        <h2 className="text-3xl font-black text-slate-800 tracking-tight">
          {activeTab === 'overview' ? 'Executive Dashboard' : 'Analytics & Reports'}
        </h2>
        <div className="flex items-center gap-2">
            <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('overview')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'overview' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><BarChart3 size={18}/> Overview</button>
                <button onClick={() => setActiveTab('reports')} className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><PieChart size={18}/> Reports</button>
            </div>
            {activeTab === 'overview' && (
                <div className="flex gap-2">
                  <button 
                    onClick={handlePrintUnitReport} 
                    disabled={reportLoading}
                    className="bg-white border-2 border-indigo-600 text-indigo-600 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-50 shadow-md transition-all active:scale-95 disabled:opacity-50"
                  >
                    {reportLoading ? <Loader2 size={20} className="animate-spin" /> : <ClipboardList size={20} />}
                    <span>Unit Report</span>
                  </button>
                  <button onClick={() => setIsLaunchModalOpen(true)} className="bg-indigo-600 text-white px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95">
                    <PlusCircle size={20} /><span>Launch New Order</span>
                  </button>
                </div>
            )}
        </div>
      </div>

      {activeTab === 'overview' ? (
        <div className="space-y-6 animate-fade-in">
            <DashboardStats liveStockCount={liveStockCount} activeOrderCount={activeOrderCount} />
            <MasterOrderList 
              orders={orders} 
              units={units} 
              onRefresh={loadData} 
              onViewDetails={setDetailsModal} 
              onSendEmail={handleSendEmail} 
              emailLoading={emailLoading}
            />
        </div>
      ) : (
        <div className="bg-white p-20 rounded-2xl border border-slate-200 text-center text-slate-400 animate-fade-in">
           <PieChart size={48} className="mx-auto mb-4 opacity-20"/>
           <p className="text-lg font-bold">Reporting Suite</p>
           <p className="text-sm">Detailed production analytics and performance KPIs are currently being compiled.</p>
        </div>
      )}

      <LaunchOrderModal 
        isOpen={isLaunchModalOpen} 
        onClose={() => setIsLaunchModalOpen(false)} 
        units={units} 
        onSuccess={loadData} 
      />

      {detailsModal && (
        <AdminOrderDetailsModal 
          order={detailsModal} 
          units={units} 
          onClose={() => setDetailsModal(null)} 
          onRefresh={loadData} 
        />
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { fetchStyles, upsertStyle, fetchStyleTemplate, deleteStyle, uploadOrderAttachment } from '../services/db';
import { Style, StyleTemplate, Attachment, TechPackItem, ConsumptionType } from '../types';
import { 
  Plus, Search, Grid, Copy, Trash2, Settings, ArrowLeftRight, CheckSquare, Square, FileUp, Table, BookOpen, ChevronRight, Edit3, Printer, X, FileSpreadsheet
} from 'lucide-react';

// Imported modular components
import { StyleFullView } from '../components/style-db/StyleFullView';
import { AuditMatrixModal } from '../components/style-db/AuditMatrixModal';
import { BulkUpdateModal } from '../components/style-db/BulkUpdateModal';
import { BulkImportModal } from '../components/style-db/BulkImportModal';
import { EditorModal } from '../components/style-db/EditorModal';
import { BulkAttributeUpdateModal } from '../components/style-db/BulkAttributeUpdateModal';

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<Style[]>([]);
  const [template, setTemplate] = useState<StyleTemplate | null>(null);
  const [viewMode, setViewMode] = useState<'catalog' | 'compare'>('catalog');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<Style | null>(null);
  const [viewingStyle, setViewingStyle] = useState<Style | null>(null);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [compareList, setCompareList] = useState<Style[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [garmentTypeOptions, setGarmentTypeOptions] = useState(['Pant', 'Trackpant', 'Shorts', 'T-shirt']);
  const [demographicOptions, setDemographicOptions] = useState(['Men', 'Boys']);
  const [isAuditViewOpen, setIsAuditViewOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<{ category?: string, field?: string } | null>(null);

  // Bulk Mode States
  const [isBulkMode, setIsBulkMode] = useState(false);
  const [selectedStyleIds, setSelectedStyleIds] = useState<string[]>([]);
  const [isBulkUpdateModalOpen, setIsBulkUpdateModalOpen] = useState(false);
  const [isBulkImportModalOpen, setIsBulkImportModalOpen] = useState(false);
  const [isBulkAttributeUpdateOpen, setIsBulkAttributeUpdateOpen] = useState(false);
  const [bulkImportData, setBulkImportData] = useState<any[]>([]);
  const bulkFileRef = useRef<HTMLInputElement>(null);

  // Bulk Selection Filters
  const [bulkSelFilter, setBulkSelFilter] = useState({ garment: '', demographic: '', category: '' });

  // Revised Bulk Update Form Structure
  const [bulkUpdateMeta, setBulkUpdateMeta] = useState<{
    strategy: 'overwrite' | 'append';
  }>({
    strategy: 'overwrite'
  });

  const [bulkFieldValues, setBulkFieldValues] = useState<Record<string, {
    isEnabled: boolean;
  } & TechPackItem>>({});

  const loadData = async () => {
    const [s, t] = await Promise.all([fetchStyles(), fetchStyleTemplate()]);
    setStyles(s);
    setTemplate(t);
    const existingGarments = Array.from(new Set([...garmentTypeOptions, ...s.map(style => style.garment_type).filter(Boolean) as string[]]));
    const existingDemos = Array.from(new Set([...demographicOptions, ...s.map(style => style.demographic).filter(Boolean) as string[]]));
    setGarmentTypeOptions(existingGarments);
    setDemographicOptions(existingDemos);

    if (t) {
      const initialValues: Record<string, any> = {};
      t.config.forEach(cat => {
        cat.fields.forEach(f => {
          initialValues[`${cat.name}|${f}`] = { isEnabled: false, text: '', attachments: [] };
        });
      });
      setBulkFieldValues(initialValues);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredStyles = styles.filter(s => 
    s.style_number.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.garment_type && s.garment_type.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const handleSaveStyle = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    setIsUploading(true);
    const payload: Partial<Style> = { ...isEditing };
    if (!payload.id || payload.id === "") delete payload.id;
    const { error } = await upsertStyle(payload);
    setIsUploading(false);
    if (!error) { 
      setIsEditing(null); 
      setEditTarget(null);
      loadData(); 
    } else { 
      alert(error); 
    }
  };

  const handleNewStyle = () => {
    setIsEditing({ 
      id: '', style_number: '', category: 'Casuals', packing_type: 'pouch', pcs_per_box: 0, 
      style_text: '', garment_type: 'T-shirt', demographic: 'Men', 
      available_colors: [''], available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL'], 
      size_type: 'letter', tech_pack: {} 
    });
    setEditTarget(null);
  };

  const handleCopyStyle = (sourceStyle: Style) => {
    const copy = JSON.parse(JSON.stringify(sourceStyle));
    copy.id = ''; 
    copy.style_number = `${sourceStyle.style_number} (Copy)`;
    setIsEditing(copy);
    setEditTarget(null);
  };

  const handleDelete = async (id: string) => { 
    if (confirm("Permanently delete this style?")) { await deleteStyle(id); loadData(); setViewingStyle(null); } 
  };

  const handleFileUpload = async (category: string, field: string, files: FileList | null, vIdx?: number, svIdx?: number) => {
    if (!files || !isEditing) return;
    setIsUploading(true);
    const updated = { ...isEditing };
    if (!updated.tech_pack[category]) updated.tech_pack[category] = {};
    if (!updated.tech_pack[category][field]) updated.tech_pack[category][field] = { text: '', attachments: [] };

    let target: Attachment[];
    if (vIdx !== undefined) {
      const variant = updated.tech_pack[category][field].variants![vIdx];
      if (svIdx !== undefined) target = variant.sizeVariants![svIdx].attachments;
      else target = variant.attachments;
    } else {
      target = updated.tech_pack[category][field].attachments;
    }

    const filesArr = Array.from(files) as File[];
    for (const file of filesArr) {
      const url = await uploadOrderAttachment(file);
      if (url) target.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
    }
    setIsEditing(updated);
    setIsUploading(false);
  };

  const handleCSVImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      const splitCSV = (row: string) => {
          const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
          return row.split(regex).map(val => {
              let cleaned = val.trim();
              if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
                  cleaned = cleaned.substring(1, cleaned.length - 1);
              }
              return cleaned;
          });
      };
      const headers = splitCSV(lines[0]).map(h => h.trim());
      const parsedData = lines.slice(1).map(line => {
        const values = splitCSV(line);
        if (values.length < headers.length) return null;
        const entry: any = {};
        headers.forEach((header, i) => entry[header] = values[i]);
        return entry;
      }).filter(Boolean);
      setBulkImportData(parsedData);
      setIsBulkImportModalOpen(true);
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleExecuteBulkImport = async () => {
    setIsUploading(true);
    try {
      for (const row of bulkImportData) {
        const styleNum = row['Style No.'] || row['Style No'] || row['StyleNo'];
        const gType = row['GarmentType'] || row['Garment Type'] || row['Garment'];
        const demo = row['Demographic'] || row['Demo'];
        const cat = row['Category'] || row['Cat'];
        const desc = row['Short description'] || row['Description'] || row['Short Description'];
        const cols = row['Available colours'] || row['Available colors'] || row['Colours'] || row['Colors'];
        const sizes = row['size variants'] || row['Size variants'] || row['Sizes'];
        const fabricValue = row['fabric'] || row['Fabric'];

        const newStyle: Partial<Style> = {
          style_number: styleNum || 'NEW-STYLE',
          garment_type: gType || 'T-shirt',
          demographic: demo || 'Men',
          category: cat || 'Casuals',
          style_text: desc || '',
          available_colors: (cols || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          available_sizes: (sizes || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          packing_type: 'pouch',
          pcs_per_box: 1,
          tech_pack: {},
          size_type: (sizes || '').match(/[a-zA-Z]/) ? 'letter' : 'number'
        };

        if (fabricValue) {
          const fabricNote = `Fabrication: ${fabricValue}`;
          newStyle.style_text = newStyle.style_text ? `${newStyle.style_text}\n${fabricNote}` : fabricNote;
        }
        await upsertStyle(newStyle);
      }
      alert(`Successfully created ${bulkImportData.length} new styles.`);
      setIsBulkImportModalOpen(false);
      setIsBulkMode(false);
      loadData();
    } catch (err) {
      alert("Import failed: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const handleBulkUpdate = async () => {
    if (selectedStyleIds.length === 0) return;
    setIsUploading(true);
    try {
      const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
      const enabledUpdates = (Object.entries(bulkFieldValues) as [string, typeof bulkFieldValues[string]][]).filter(([_, val]) => val.isEnabled);
      if (enabledUpdates.length === 0) {
        alert("Please select at least one field to update.");
        setIsUploading(false);
        return;
      }

      for (const style of selectedStyles) {
        const updatedStyle = JSON.parse(JSON.stringify(style));
        const { strategy } = bulkUpdateMeta;

        for (const [key, fieldData] of enabledUpdates) {
          const [category, field] = key.split('|');
          if (!updatedStyle.tech_pack[category]) updatedStyle.tech_pack[category] = {};

          const mergeText = (current: string, next: string) => strategy === 'overwrite' ? next : (current ? current + '\n' + next : next);
          const mergeAttachments = (current: Attachment[], next: Attachment[]) => strategy === 'overwrite' ? next : [...(current || []), ...next];

          // Use the TechPackItem structure directly from bulkFieldValues
          const bulkItem = { ...fieldData };
          delete (bulkItem as any).isEnabled;

          const currentItem = updatedStyle.tech_pack[category][field] || { text: '', attachments: [] };

          if (!bulkItem.variants) {
            // Global Update
            currentItem.text = mergeText(currentItem.text, bulkItem.text);
            currentItem.attachments = mergeAttachments(currentItem.attachments, bulkItem.attachments);
            if (bulkItem.consumption_type) currentItem.consumption_type = bulkItem.consumption_type;
            if (bulkItem.consumption_val !== undefined) currentItem.consumption_val = bulkItem.consumption_val;
            if (strategy === 'overwrite') delete (currentItem as any).variants;
          } else {
            // Variant-Based Update
            if (strategy === 'overwrite') {
               currentItem.variants = [];
               delete (currentItem as any).text;
               delete (currentItem as any).attachments;
            } else if (!currentItem.variants) {
               currentItem.variants = [];
            }

            bulkItem.variants.forEach(bulkVar => {
              // Filter colors to only those the style possesses
              const validColors = bulkVar.colors.filter(c => updatedStyle.available_colors?.includes(c));
              if (validColors.length === 0) return; // Skip if no colors match union selection

              let targetVar = currentItem.variants!.find(v => JSON.stringify(v.colors.sort()) === JSON.stringify(validColors.sort()));
              if (!targetVar) {
                targetVar = { colors: validColors, text: '', attachments: [] };
                currentItem.variants!.push(targetVar);
              }

              if (!bulkVar.sizeVariants) {
                targetVar.text = mergeText(targetVar.text, bulkVar.text);
                targetVar.attachments = mergeAttachments(targetVar.attachments, bulkVar.attachments);
                if (bulkVar.consumption_type) targetVar.consumption_type = bulkVar.consumption_type;
                if (bulkVar.consumption_val !== undefined) targetVar.consumption_val = bulkVar.consumption_val;
                if (strategy === 'overwrite') delete (targetVar as any).sizeVariants;
              } else {
                if (strategy === 'overwrite') {
                  targetVar.sizeVariants = [];
                  delete (targetVar as any).text;
                  delete (targetVar as any).attachments;
                } else if (!targetVar.sizeVariants) {
                  targetVar.sizeVariants = [];
                }

                bulkVar.sizeVariants.forEach(bulkSizeVar => {
                  const validSizes = bulkSizeVar.sizes.filter(s => updatedStyle.available_sizes?.includes(s));
                  if (validSizes.length === 0) return;

                  let targetSizeVar = targetVar!.sizeVariants!.find(sv => JSON.stringify(sv.sizes.sort()) === JSON.stringify(validSizes.sort()));
                  if (!targetSizeVar) {
                    targetSizeVar = { sizes: validSizes, text: '', attachments: [] };
                    targetVar!.sizeVariants!.push(targetSizeVar);
                  }

                  targetSizeVar.text = mergeText(targetSizeVar.text, bulkSizeVar.text);
                  targetSizeVar.attachments = mergeAttachments(targetSizeVar.attachments, bulkSizeVar.attachments);
                  if (bulkSizeVar.consumption_type) targetSizeVar.consumption_type = bulkSizeVar.consumption_type;
                  if (bulkSizeVar.consumption_val !== undefined) targetSizeVar.consumption_val = bulkSizeVar.consumption_val;
                });
              }
            });
          }
          updatedStyle.tech_pack[category][field] = currentItem;
        }
        await upsertStyle(updatedStyle);
      }
      alert("Bulk update completed successfully.");
      setIsBulkUpdateModalOpen(false);
      setIsBulkMode(false);
      setSelectedStyleIds([]);
      loadData();
    } catch (err) {
      alert("Error during bulk update: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const toggleSelectStyle = (id: string) => {
    setSelectedStyleIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const applyBulkFilterSelection = (isSelecting: boolean) => {
    const matchingIds = styles.filter(s => {
      const matchesGarment = !bulkSelFilter.garment || s.garment_type === bulkSelFilter.garment;
      const matchesDemographic = !bulkSelFilter.demographic || s.demographic === bulkSelFilter.demographic;
      const matchesCategory = !bulkSelFilter.category || s.category === bulkSelFilter.category;
      return matchesGarment && matchesDemographic && matchesCategory;
    }).map(s => s.id);
    if (isSelecting) setSelectedStyleIds(prev => Array.from(new Set([...prev, ...matchingIds])));
    else setSelectedStyleIds(prev => prev.filter(id => !matchingIds.includes(id)));
  };

  const handleMatrixCellClick = (style: Style, catName: string, fieldName?: string) => {
    setIsEditing(style);
    setEditTarget({ category: catName, field: fieldName });
    setIsAuditViewOpen(false);
  };

  const checkCompleteness = (style: Style, cat: string, field: string) => {
    const item = style.tech_pack[cat]?.[field];
    if (!item) return false;
    return !!( (item.text && item.text.trim() !== '') || (item.attachments && item.attachments.length > 0) || (item.variants && item.variants.length > 0) );
  };

  const handlePrint = (style: Style) => {
    const win = window.open('', 'StylePrint', 'width=1000,height=800');
    if (!win || !template) return;
    const techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
        const fields = cat.fields.map(f => {
            const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
            let contentHtml = '';
            if (item.variants) {
                contentHtml = item.variants.map(v => {
                    let sizeHtml = '';
                    if (v.sizeVariants) {
                        sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                            <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                    ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:18px;">SIZE: ${sz}</span>`).join('')}
                                </div>
                                <div style="font-size:20px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                            </div>
                        `).join('')}</div>`;
                    }
                    return `<div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;"><div style="margin-bottom:10px;">${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div><div style="font-size:22px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>${sizeHtml}</div>`;
                }).join('');
            } else contentHtml = `<div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">${item.text || '---'}</div>`;
            return `
                <div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;">
                    <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                    ${contentHtml}
                </div>`;
        }).join('');
        return `
            <div style="margin-top:40px; page-break-before:always;">
                <h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name}</h3>
                <div style="padding:10px;">${fields}</div>
            </div>`;
    }).join('');
    win.document.write(`
      <html>
        <head>
          <title>Tech Pack - ${style.style_number}</title>
          <style>
            body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; }
            .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; }
            .brand { font-size: 32px; font-weight: 900; text-transform: uppercase; margin: 0; }
            .title { font-size: 18px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #666; }
            .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; }
            .box { padding: 15px; border: 2px solid #333; border-radius: 6px; }
            .label { font-size: 11px; text-transform: uppercase; color: #666; font-weight: bold; }
            .value { font-size: 16px; font-weight: bold; }
            .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; padding-bottom: 5px; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Technical Package (Style Blueprint)</div>
          </div>
          <div class="grid">
            <div class="box"><span class="label">Style Number</span><div class="value">${style.style_number}</div></div>
            <div class="box"><span class="label">Category</span><div class="value">${style.category}</div></div>
            <div class="box"><span class="label">Garment Type</span><div class="value">${style.category}</div></div>
            <div class="box"><span class="label">Demographic</span><div class="value">${style.demographic}</div></div>
            <div class="box"><span class="label">Packing Type</span><div class="value">${style.packing_type} (${style.pcs_per_box} pcs)</div></div>
            <div class="box"><span class="label">Date Generated</span><div class="value">${new Date().toLocaleDateString()}</div></div>
          </div>
          <div class="section-title">Summary & Notes</div>
          <div style="padding: 20px; border: 2px solid #333; min-height: 60px; background:#fcfcfc; border-radius:6px; font-size:16px;">
            ${style.style_text || "No technical notes provided."}
          </div>
          ${techPackHtml}
          <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
        </body>
      </html>`);
    win.document.close();
  };

  const unionColors = Array.from(new Set(styles.flatMap(s => s.available_colors || []))).filter(Boolean).sort();
  const unionSizes = Array.from(new Set(styles.flatMap(s => s.available_sizes || []))).filter(Boolean).sort();

  if (viewingStyle) return <StyleFullView style={viewingStyle} template={template} onBack={() => setViewingStyle(null)} onEdit={() => { setIsEditing(viewingStyle); setViewingStyle(null); }} onPrint={() => handlePrint(viewingStyle)} onDelete={() => handleDelete(viewingStyle.id)} />;

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row justify-between xl:items-center gap-4">
        <div><h2 className="text-3xl font-black text-slate-800 flex items-center gap-3"><div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><BookOpen size={28}/></div>Style Technical Database</h2><p className="text-slate-500 text-sm mt-1">Master Tech-Packs and Design Blueprint Management</p></div>
        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setViewMode('catalog')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'catalog' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid size={18}/> Catalog</button>
            <button onClick={() => setViewMode('compare')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'compare' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ArrowLeftRight size={18}/> Compare</button>
          </div>
          <div className="h-8 w-px bg-slate-200 mx-2"></div>

          <button onClick={() => setIsBulkAttributeUpdateOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-green-600 hover:border-green-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Sync Specific Values via CSV"><FileSpreadsheet size={20}/> Sync Values (CSV)</button>

          <button onClick={() => setIsAuditViewOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 hover:border-indigo-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Data Completeness Matrix"><Table size={20}/> Matrix Audit</button>
          <button onClick={() => { setIsBulkMode(!isBulkMode); setSelectedStyleIds([]); }} className={`p-3 rounded-xl border transition-all flex items-center gap-2 font-bold text-sm ${isBulkMode ? 'bg-orange-600 text-white border-orange-600 shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-orange-500 hover:text-orange-600'}`}><CheckSquare size={20}/> {isBulkMode ? 'Exit Bulk Mode' : 'Bulk Selection'}</button>
          <button onClick={() => setIsConfigOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 rounded-xl transition-all"><Settings size={20}/></button>
          <button onClick={handleNewStyle} className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><Plus size={20}/> New Style</button>
        </div>
      </div>

      <div className="relative"><input type="text" placeholder="Search by Style Number, Category, or Garment Type..." className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-500 outline-none transition-all font-bold shadow-sm bg-white text-black" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/><Search className="absolute left-4 top-4 text-slate-400" size={24}/></div>

      {isBulkMode && (
        <div className="bg-slate-900/5 p-6 rounded-3xl border-2 border-dashed border-indigo-200 animate-fade-in">
           <div className="flex flex-col md:flex-row items-end gap-4">
              <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4">
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Garment Type Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.garment} onChange={e => setBulkSelFilter({...bulkSelFilter, garment: e.target.value})}><option value="">All Garment Types</option>{garmentTypeOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Demographic Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.demographic} onChange={e => setBulkSelFilter({...bulkSelFilter, demographic: e.target.value})}><option value="">All Demographics</option>{demographicOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.category} onChange={e => setBulkSelFilter({...bulkSelFilter, category: e.target.value})}><option value="">All Categories</option><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
              </div>
              <div className="flex gap-2 shrink-0"><button onClick={() => applyBulkFilterSelection(true)} className="px-5 py-3 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center gap-2"><CheckSquare size={16}/> Select All Matching</button><button onClick={() => applyBulkFilterSelection(false)} className="px-5 py-3 bg-white text-slate-500 border border-slate-200 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2"><Square size={16}/> Deselect All Matching</button></div>
           </div>
        </div>
      )}

      {viewMode === 'catalog' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in relative pb-24">
          {filteredStyles.map(style => {
            const isSelected = selectedStyleIds.includes(style.id);
            return (
              <div key={style.id} className={`bg-white rounded-2xl border shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col ${isBulkMode && isSelected ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200'}`}>
                <div className="p-6 flex-1 cursor-pointer relative" onClick={() => isBulkMode ? toggleSelectStyle(style.id) : setViewingStyle(style)}>
                  {isBulkMode && <div className="absolute top-4 right-4 z-10">{isSelected ? <CheckSquare className="text-indigo-600"/> : <Square className="text-slate-300"/>}</div>}
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                      <div className="bg-slate-100 px-3 py-1 rounded-full text-[10px] font-black text-slate-500 uppercase tracking-widest">{style.garment_type}</div>
                      <div className="bg-indigo-50 px-3 py-1 rounded-full text-[10px] font-black text-indigo-500 uppercase tracking-widest">{style.demographic}</div>
                    </div>
                    {!isBulkMode && <div className="flex gap-2" onClick={e => e.stopPropagation()}><button onClick={() => handlePrint(style)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Printer size={16}/></button><button onClick={() => handleDelete(style.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"><Trash2 size={16}/></button></div>}
                  </div>
                  <div className="flex items-center justify-between group/title"><h3 className="text-2xl font-black text-slate-800 tracking-tight mb-2 group-hover/title:text-indigo-600 transition-colors">{style.style_number}</h3><ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600 transition-all transform group-hover:translate-x-1" /></div>
                  <p className="text-slate-500 text-xs font-medium line-clamp-2 leading-relaxed mb-4">{style.style_text || 'No description provided.'}</p>
                </div>
                {!isBulkMode && (
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex gap-2">
                    <button onClick={() => { setIsEditing(style); setEditTarget(null); }} className="flex-1 py-2.5 bg-white border border-slate-200 rounded-xl text-xs font-black text-slate-700 hover:border-indigo-500 hover:text-indigo-600 transition-all flex items-center justify-center gap-2"><Edit3 size={14}/> Edit</button>
                    <button onClick={() => handleCopyStyle(style)} className="p-2.5 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-indigo-600 hover:border-indigo-600 transition-all" title="Create Copy"><Copy size={16}/></button>
                    <button onClick={() => { if (compareList.find(s => s.id === style.id)) setCompareList(prev => prev.filter(s => s.id !== style.id)); else { setCompareList(prev => [...prev, style]); setViewMode('compare'); } }} className={`p-2.5 rounded-xl border transition-all ${compareList.find(s => s.id === style.id) ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-500 hover:text-indigo-600'}`}><ArrowLeftRight size={18}/></button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {isBulkMode && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-slide-up">
           <div className="bg-slate-900 text-white rounded-full px-8 py-4 shadow-2xl flex items-center gap-6 border border-white/10">
              <div className="flex flex-col"><span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Bulk Actions</span><span className="text-xl font-black">{selectedStyleIds.length} Selected</span></div>
              <div className="h-10 w-px bg-white/20"></div>
              <div className="flex items-center gap-3">
                {selectedStyleIds.length > 0 && <button onClick={() => setIsBulkUpdateModalOpen(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><Edit3 size={18}/> Edit technical fields</button>}
                <button onClick={() => bulkFileRef.current?.click()} className="bg-orange-600 hover:bg-orange-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><FileUp size={18}/> Create Bulk (CSV)</button>
                <input type="file" ref={bulkFileRef} accept=".csv" className="hidden" onChange={handleCSVImport} />
              </div>
              <button onClick={() => { setSelectedStyleIds([]); setIsBulkMode(false); }} className="text-slate-400 hover:text-white transition-colors ml-2"><X/></button>
           </div>
        </div>
      )}

      {viewMode === 'compare' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-x-auto min-h-[600px] animate-fade-in">{compareList.length === 0 ? (<div className="p-20 text-center text-slate-400"><ArrowLeftRight size={48} className="mx-auto mb-4 opacity-20"/><p className="text-xl font-bold">Desk Empty</p><button onClick={() => setViewMode('catalog')} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold">Back to Catalog</button></div>) : (<div className="p-8 inline-flex gap-8">{compareList.map(style => (<div key={style.id} className="w-96 shrink-0 bg-slate-50/50 rounded-3xl border border-slate-200 flex flex-col shadow-inner overflow-hidden"><div className="p-6 bg-white border-b border-slate-200 sticky top-0 z-10"><div className="flex justify-between items-start"><h3 className="text-2xl font-black text-slate-800">{style.style_number}</h3><button onClick={() => setCompareList(prev => prev.filter(s => s.id !== style.id))} className="p-1 text-slate-300 hover:text-red-500 transition-colors"><X size={20}/></button></div><div className="mt-4 flex flex-wrap gap-2"><span className="text-[10px] font-black bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full uppercase">{style.category}</span><span className="text-[10px] font-black bg-slate-100 text-slate-700 px-3 py-1 rounded-full uppercase">{style.garment_type}</span></div></div><div className="p-6 space-y-8 overflow-y-auto">{template?.config.filter(c => c.name !== "General Info").map(cat => (<div key={cat.name}><h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest border-b border-indigo-100 pb-2 mb-4">{cat.name}</h4><div className="space-y-6">{cat.fields.map(field => { const item = style.tech_pack[cat.name]?.[field] || { text: '---', attachments: [] }; return (<div key={field}><div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{field}</div>{!item.variants ? (<div className="text-sm font-medium text-slate-700 whitespace-pre-wrap">{item.text}</div>) : (<div className="space-y-4">{item.variants.map((v, vIdx) => (<div key={vIdx} className="bg-white border rounded-xl p-3 shadow-sm"><div className="flex flex-wrap gap-1 mb-2">{v.colors.map(c => <span key={c} className="bg-indigo-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded uppercase">{c}</span>)}</div><div className="text-xs text-slate-700">{v.text}</div></div>))}</div>)}</div>); })}</div></div>))}</div></div>))}</div>)}</div>
      )}

      {isEditing && (
        <EditorModal 
          isEditing={isEditing} styles={styles} template={template} 
          setIsEditing={setIsEditing} handleSaveStyle={handleSaveStyle} handleCopyStyle={handleCopyStyle} 
          handleFileUpload={handleFileUpload} editTarget={editTarget}
          garmentTypeOptions={garmentTypeOptions} setGarmentTypeOptions={setGarmentTypeOptions}
          demographicOptions={demographicOptions} setDemographicOptions={setDemographicOptions}
          isUploading={isUploading}
        />
      )}

      {isAuditViewOpen && (
        <AuditMatrixModal 
          styles={styles} template={template} onClose={() => setIsAuditViewOpen(false)} 
          onCellClick={handleMatrixCellClick} checkCompleteness={checkCompleteness} 
        />
      )}

      {isBulkUpdateModalOpen && (
        <BulkUpdateModal 
          styles={styles} template={template} selectedStyleIds={selectedStyleIds} 
          bulkUpdateMeta={bulkUpdateMeta} setBulkUpdateMeta={setBulkUpdateMeta} 
          bulkFieldValues={bulkFieldValues} setBulkFieldValues={setBulkFieldValues}
          isUploading={isUploading} setIsUploading={setIsUploading}
          onClose={() => setIsBulkUpdateModalOpen(false)} onExecute={handleBulkUpdate}
          unionColors={unionColors}
          unionSizes={unionSizes}
        />
      )}

      {isBulkImportModalOpen && (
        <BulkImportModal 
          bulkImportData={bulkImportData} isUploading={isUploading} 
          onClose={() => setIsBulkImportModalOpen(false)} onExecute={handleExecuteBulkImport} 
        />
      )}

      {isBulkAttributeUpdateOpen && (
        <BulkAttributeUpdateModal 
          styles={styles} 
          template={template} 
          onClose={() => setIsBulkAttributeUpdateOpen(false)} 
          onRefresh={loadData}
        />
      )}
    </div>
  );
};

import React from 'react';
import { X, RefreshCcw, FilePlus, CheckSquare, Square, Info, Save, Loader2, Plus, Split, Scan, ImageIcon, Trash2 } from 'lucide-react';
import { Style, StyleTemplate, Attachment, TechPackItem } from '../../types';
import { ConsumptionInput } from './ConsumptionInput';
import { uploadOrderAttachment } from '../../services/db';

interface BulkUpdateModalProps {
  styles: Style[];
  template: StyleTemplate | null;
  selectedStyleIds: string[];
  bulkUpdateMeta: {
    strategy: 'overwrite' | 'append';
  };
  setBulkUpdateMeta: (meta: any) => void;
  bulkFieldValues: Record<string, { isEnabled: boolean } & TechPackItem>;
  setBulkFieldValues: (vals: any) => void;
  isUploading: boolean;
  setIsUploading: (val: boolean) => void;
  onClose: () => void;
  onExecute: () => void;
  unionColors: string[];
  unionSizes: string[];
}

export const BulkUpdateModal: React.FC<BulkUpdateModalProps> = ({ 
  styles, 
  template, 
  selectedStyleIds, 
  bulkUpdateMeta, 
  setBulkUpdateMeta, 
  bulkFieldValues, 
  setBulkFieldValues, 
  isUploading, 
  setIsUploading, 
  onClose, 
  onExecute,
  unionColors,
  unionSizes
}) => {

  const handleFieldChange = (key: string, updates: Partial<TechPackItem>) => {
    setBulkFieldValues((prev: any) => ({
      ...prev,
      [key]: { ...prev[key], ...updates }
    }));
  };

  const handleSplitColor = (key: string) => {
    const current = bulkFieldValues[key];
    if (!current.variants) {
      handleFieldChange(key, {
        variants: [{ colors: [], text: current.text || '', attachments: current.attachments || [], consumption_type: current.consumption_type, consumption_val: current.consumption_val }]
      });
    } else {
      handleFieldChange(key, {
        variants: [...current.variants, { colors: [], text: '', attachments: [] }]
      });
    }
  };

  const handleAddSizeGroup = (key: string, vIdx: number) => {
    const current = { ...bulkFieldValues[key] };
    const variant = current.variants![vIdx];
    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }
    setBulkFieldValues((prev: any) => ({ ...prev, [key]: current }));
  };

  const handleUnsplit = (key: string) => {
    const current = bulkFieldValues[key];
    if (current.variants) {
      handleFieldChange(key, {
        text: current.variants[0].text,
        attachments: current.variants[0].attachments,
        consumption_type: current.variants[0].consumption_type,
        consumption_val: current.variants[0].consumption_val,
        variants: undefined
      });
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-6xl overflow-hidden animate-scale-up border border-slate-200 flex flex-col max-h-[95vh]">
        <div className="p-8 border-b bg-orange-50 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-2xl font-black text-orange-900 uppercase tracking-tight">Bulk Blueprint Synchronizer</h3>
            <p className="text-orange-700 text-xs font-bold uppercase tracking-widest mt-1">Applying changes to {selectedStyleIds.length} styles</p>
          </div>
          <button onClick={onClose} className="text-orange-300 hover:text-orange-600 transition-colors p-2"><X size={32}/></button>
        </div>

        <div className="p-8 flex-1 overflow-y-auto space-y-8 bg-slate-50/50">
           <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="flex-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Merge Strategy</label>
                <div className="flex bg-orange-100/50 p-1 rounded-xl border border-orange-100 max-w-md">
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'overwrite'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'overwrite' ? 'bg-orange-600 text-white shadow-md' : 'text-orange-500 hover:bg-orange-100'}`}>
                    <RefreshCcw size={14}/> Overwrite
                  </button>
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'append'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'append' ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-500 hover:bg-indigo-50'}`}>
                    <FilePlus size={14}/> Append to existing
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-3 text-indigo-500 bg-indigo-50 p-4 rounded-2xl border border-indigo-100 max-w-sm">
                <Info size={24}/>
                <p className="text-[10px] font-bold uppercase leading-relaxed">Splits are based on a union of all database attributes. Attributes not present in a specific style will be ignored during sync.</p>
              </div>
           </div>

           {template?.config.map(cat => (
             <div key={cat.name} className="space-y-4">
                <div className="flex items-center gap-3 px-4">
                  <div className="h-px flex-1 bg-slate-200"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{cat.name}</span>
                  <div className="h-px flex-1 bg-slate-200"></div>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {cat.fields.map(f => {
                    const fieldKey = `${cat.name}|${f}`;
                    const fieldData = bulkFieldValues[fieldKey];
                    if (!fieldData) return null;
                    const isSplit = !!fieldData.variants;

                    return (
                      <div key={f} className={`bg-white rounded-3xl border transition-all duration-300 ${fieldData.isEnabled ? 'border-indigo-500 ring-4 ring-indigo-50 shadow-xl' : 'border-slate-200 opacity-60 grayscale'}`}>
                         <div className="p-6 flex items-center justify-between border-b border-slate-50">
                            <div className="flex items-center gap-4">
                               <button 
                                  onClick={() => setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: { ...prev[fieldKey], isEnabled: !prev[fieldKey].isEnabled } }))}
                                  className={`p-2 rounded-xl transition-all ${fieldData.isEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                               >
                                  {fieldData.isEnabled ? <CheckSquare size={24}/> : <Square size={24}/>}
                               </button>
                               <div>
                                  <h5 className="font-black text-slate-800 uppercase tracking-tight">{f}</h5>
                                  <p className="text-[10px] text-slate-400 font-bold uppercase">Toggle to sync this attribute</p>
                               </div>
                            </div>

                            {fieldData.isEnabled && (
                              <div className="flex items-center gap-4">
                                {!isSplit ? (
                                  <>
                                    <ConsumptionInput 
                                      type={fieldData.consumption_type}
                                      value={fieldData.consumption_val}
                                      onChange={(t, v) => handleFieldChange(fieldKey, { consumption_type: t, consumption_val: v })}
                                      onClear={() => handleFieldChange(fieldKey, { consumption_type: undefined, consumption_val: undefined })}
                                    />
                                    <button type="button" onClick={() => handleSplitColor(fieldKey)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                                  </>
                                ) : (
                                  <button type="button" onClick={() => handleUnsplit(fieldKey)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                                )}
                              </div>
                            )}
                         </div>

                         {fieldData.isEnabled && (
                           <div className="p-6 space-y-6 animate-fade-in bg-slate-50/20">
                              {!isSplit ? (
                                <div className="space-y-4">
                                  <textarea 
                                    className="w-full border-2 border-slate-100 rounded-2xl p-4 h-32 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium bg-white shadow-sm"
                                    placeholder={bulkUpdateMeta.strategy === 'append' ? `Content to append...` : `Content to overwrite...`}
                                    value={fieldData.text || ''}
                                    onChange={e => handleFieldChange(fieldKey, { text: e.target.value })}
                                  />
                                  <div className="flex flex-wrap gap-2">
                                    {fieldData.attachments?.map((a: Attachment, idx: number) => (
                                      <div key={idx} className="flex items-center gap-1.5 bg-indigo-50 px-3 py-1.5 rounded-lg text-[9px] font-black text-indigo-700 border border-indigo-100">
                                        <ImageIcon size={10}/> {a.name} <button onClick={() => handleFieldChange(fieldKey, { attachments: fieldData.attachments.filter((_: any, i: number) => i !== idx) })}><X size={10}/></button>
                                      </div>
                                    ))}
                                    <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-4 py-2 rounded-xl text-[10px] font-black cursor-pointer flex items-center gap-2 transition-all">
                                      <Plus size={14}/> Add File
                                      <input 
                                        type="file" multiple className="hidden" 
                                        onChange={async (e) => {
                                          if (!e.target.files) return;
                                          setIsUploading(true);
                                          const newAtts = [];
                                          const files = Array.from(e.target.files) as File[];
                                          for (const file of files) {
                                            const url = await uploadOrderAttachment(file);
                                            if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                          }
                                          handleFieldChange(fieldKey, { attachments: [...(fieldData.attachments || []), ...newAtts] });
                                          setIsUploading(false);
                                        }}
                                      />
                                    </label>
                                  </div>
                                </div>
                              ) : (
                                <div className="space-y-6">
                                  {fieldData.variants?.map((v, vIdx) => (
                                    <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group/var">
                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants?.splice(vIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover/var:opacity-100 transition-opacity"><X size={16}/></button>

                                      <div className="mb-6 flex flex-col md:flex-row md:items-start justify-between gap-6">
                                        <div className="flex-1">
                                          <div className="flex items-center gap-3 mb-3">
                                            <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Global Attribute Union (Colors)</label>
                                            {!v.sizeVariants && (
                                              <ConsumptionInput 
                                                type={v.consumption_type}
                                                value={v.consumption_val}
                                                onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx] = { ...v, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].consumption_type; delete updated.variants![vIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />
                                            )}
                                          </div>
                                          <div className="flex flex-wrap gap-1.5 max-h-32 overflow-y-auto p-1">
                                            {unionColors.map(color => {
                                              const isSel = v.colors.includes(color);
                                              return (
                                                <button key={color} type="button" onClick={() => { const updated = { ...fieldData }; const varObj = updated.variants![vIdx]; if (isSel) varObj.colors = varObj.colors.filter(c => c !== color); else varObj.colors.push(color); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSel ? 'bg-indigo-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'}`}>{color}</button>
                                              );
                                            })}
                                          </div>
                                        </div>
                                        {!v.sizeVariants && (
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                                        )}
                                      </div>

                                      {!v.sizeVariants ? (
                                        <div className="space-y-4">
                                          <textarea 
                                            className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50/50"
                                            placeholder="Instructions for selected color union..."
                                            value={v.text}
                                            onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                          />
                                          <div className="flex flex-wrap gap-2">
                                            {v.attachments.map((a, aIdx) => (
                                              <div key={aIdx} className="flex items-center gap-1 bg-indigo-50 text-indigo-700 px-2 py-1 rounded text-[9px] font-black border border-indigo-100">
                                                {a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button>
                                              </div>
                                            ))}
                                            <label className="bg-white border-2 border-dashed border-slate-200 text-slate-400 px-3 py-1 rounded-lg text-[10px] font-black cursor-pointer hover:bg-slate-50 transition-all">
                                              + File
                                              <input type="file" multiple className="hidden" onChange={async (e) => {
                                                if (!e.target.files) return;
                                                setIsUploading(true);
                                                const newAtts = [];
                                                const files = Array.from(e.target.files) as File[];
                                                for (const file of files) {
                                                  const url = await uploadOrderAttachment(file);
                                                  if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                }
                                                const updated = { ...fieldData };
                                                updated.variants![vIdx].attachments = [...(updated.variants![vIdx].attachments || []), ...newAtts];
                                                setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                setIsUploading(false);
                                              }}/>
                                            </label>
                                          </div>
                                        </div>
                                      ) : (
                                        <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2">
                                          <div className="flex justify-between items-center"><h6 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Nested Size Sub-Splits</h6><button type="button" onClick={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500">Discard Splits</button></div>
                                          {v.sizeVariants.map((sv, svIdx) => (
                                            <div key={svIdx} className="p-4 bg-blue-50/20 rounded-2xl border border-blue-100 space-y-4 relative group/size">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants?.splice(svIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                                                <div className="flex-1">
                                                  <label className="block text-[9px] font-black text-blue-400 uppercase mb-2">Apply to Sizes (Union Selection)</label>
                                                  <div className="flex flex-wrap gap-1">
                                                    {unionSizes.map(sz => {
                                                      const isSzSel = sv.sizes.includes(sz);
                                                      return (
                                                        <button key={sz} type="button" onClick={() => { const updated = { ...fieldData }; const sVar = updated.variants![vIdx].sizeVariants![svIdx]; if (isSzSel) sVar.sizes = sVar.sizes.filter(s => s !== sz); else sVar.sizes.push(sz); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSzSel ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-blue-300 border border-blue-100 hover:bg-blue-50'}`}>{sz}</button>
                                                      );
                                                    })}
                                                  </div>
                                                </div>
                                                <ConsumptionInput 
                                                  type={sv.consumption_type}
                                                  value={sv.consumption_val}
                                                  onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                  onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_type; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                />
                                              </div>

                                              <textarea 
                                                className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[60px]"
                                                placeholder="Instructions for selected size union..."
                                                value={sv.text}
                                                onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />

                                              <div className="flex flex-wrap gap-2">
                                                {sv.attachments.map((a, aIdx) => (
                                                  <div key={aIdx} className="flex items-center gap-1 bg-white border border-blue-50 px-2 py-1 rounded text-[9px] font-black text-blue-700">{a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button></div>
                                                ))}
                                                <label className="bg-white border-2 border-dashed border-blue-100 text-blue-300 px-3 py-1 rounded-lg text-[9px] font-black cursor-pointer hover:bg-blue-50 transition-all">+ File <input type="file" multiple className="hidden" onChange={async (e) => {
                                                  if (!e.target.files) return;
                                                  setIsUploading(true);
                                                  const newAtts = [];
                                                  const files = Array.from(e.target.files) as File[];
                                                  for (const file of files) {
                                                    const url = await uploadOrderAttachment(file);
                                                    if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                  }
                                                  const updated = { ...fieldData };
                                                  updated.variants![vIdx].sizeVariants![svIdx].attachments = [...(updated.variants![vIdx].sizeVariants![svIdx].attachments || []), ...newAtts];
                                                  setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                  setIsUploading(false);
                                                }}/></label>
                                              </div>
                                            </div>
                                          ))}
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50">+ Add Size Sub-Split</button>
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                  <button type="button" onClick={() => handleSplitColor(fieldKey)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 transition-all">+ Add Bulk Color Group Variant</button>
                                </div>
                              )}
                           </div>
                         )}
                      </div>
                    );
                  })}
                </div>
             </div>
           ))}
        </div>

        <div className="p-8 border-t bg-white flex justify-between items-center shadow-2xl shrink-0">
          <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
          <button 
            onClick={onExecute} 
            disabled={isUploading}
            className="px-12 py-4 bg-orange-600 text-white rounded-2xl font-black shadow-2xl shadow-orange-200 flex items-center gap-3 active:scale-95 disabled:opacity-50 uppercase text-xs"
          >
            {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Save size={20}/>} Sync Selected Blueprint Fields
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { Layers, Palette, Ruler, Trash2, Plus, Split, X, Scan, ImageIcon } from 'lucide-react';
import { Style, StyleCategory } from '../../types';
import { ConsumptionInput } from './ConsumptionInput';

interface CategoryEditorProps {
  category: StyleCategory;
  isEditing: Style | null;
  setIsEditing: (style: Style | null) => void;
  handleFileUpload: (category: string, field: string, files: FileList | null, variantIndex?: number, sizeIndex?: number) => void;
  targetFocus: { category?: string, field?: string } | null;
}

export const CategoryEditor: React.FC<CategoryEditorProps> = ({ 
  category, 
  isEditing, 
  setIsEditing, 
  handleFileUpload,
  targetFocus
}) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (targetFocus?.category === category.name) {
      if (targetFocus.field) {
        const fieldEl = document.getElementById(`field-${category.name}-${targetFocus.field}`);
        fieldEl?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else {
        containerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }
    }
  }, [targetFocus, category.name]);

  if (!isEditing) return null;

  const isPackingReq = category.name.toLowerCase().includes('packing');
  const isPreProduction = category.name.toLowerCase().includes('pre production');
  const availableColors = (isEditing.available_colors || []).filter(c => c.trim() !== '');
  const availableSizes = (isEditing.available_sizes || []).filter(s => s.trim() !== '');

  const handleSplitColor = (fieldName: string) => {
    const updated = { ...isEditing };
    if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {};
    const current = updated.tech_pack[category.name][fieldName] || { text: '', attachments: [] };

    if (!current.variants) {
      current.variants = [{ colors: [], text: current.text, attachments: current.attachments, consumption_type: current.consumption_type, consumption_val: current.consumption_val }];
    } else {
      current.variants.push({ colors: [], text: '', attachments: [] });
    }

    updated.tech_pack[category.name][fieldName] = current;
    setIsEditing(updated);
  };

  const handleAddSizeGroup = (fieldName: string, vIdx: number) => {
    const updated = { ...isEditing };
    const variant = updated.tech_pack[category.name][fieldName].variants![vIdx];

    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }

    setIsEditing(updated);
  };

  const handleUnsplit = (fieldName: string) => {
    if (!confirm("Merge all variants into one global instruction?")) return;
    const updated = { ...isEditing };
    const current = updated.tech_pack[category.name][fieldName];
    if (current && current.variants) {
      current.text = current.variants[0].text;
      current.attachments = current.variants[0].attachments;
      current.consumption_type = current.variants[0].consumption_type;
      current.consumption_val = current.variants[0].consumption_val;
      delete current.variants;
    }
    setIsEditing(updated);
  };

  return (
    <div ref={containerRef} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm mb-6">
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Layers size={18} className="text-indigo-600"/>
          <h4 className="font-black text-slate-700 text-xs uppercase tracking-widest">{category.name}</h4>
        </div>
      </div>

      <div className="p-6 space-y-8">
        {isPreProduction && (
          <div id={`field-${category.name}-preprod`} className="grid grid-cols-1 md:grid-cols-2 gap-8 p-6 bg-slate-50/50 rounded-2xl border border-slate-100 shadow-inner mb-4">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-4">
                <Palette size={16} className="text-indigo-600"/>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Blueprint Colours</label>
              </div>
              <div className="space-y-2 max-h-48 overflow-y-auto pr-2">
                {(isEditing.available_colors || ['']).map((color, idx) => (
                  <div key={idx} className="flex gap-2 group">
                    <input className="flex-1 border-2 border-slate-200 rounded-xl p-3 bg-white text-slate-900 font-bold focus:border-indigo-500 outline-none transition-all text-sm" placeholder="Type colour..." value={color} onChange={e => { const newCols = [...(isEditing.available_colors || [])]; newCols[idx] = e.target.value; setIsEditing({...isEditing, available_colors: newCols}); }} />
                    <button type="button" onClick={() => { const newCols = (isEditing.available_colors || []).filter((_, i) => i !== idx); setIsEditing({...isEditing, available_colors: newCols.length > 0 ? newCols : ['']}); }} className="p-3 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                  </div>
                ))}
              </div>
              <button type="button" onClick={() => setIsEditing({...isEditing, available_colors: [...(isEditing.available_colors || []), '']})} className="w-full mt-4 py-2.5 border-2 border-dashed border-indigo-200 text-indigo-600 font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-white flex items-center justify-center gap-2"><Plus size={14}/> Add Colour Row</button>
            </div>
            <div className="flex flex-col">
              <div className="flex justify-between items-center mb-4"><div className="flex items-center gap-2"><Ruler size={16} className="text-indigo-600"/><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Size variants</label></div><div className="flex bg-slate-200 p-1 rounded-lg"><button type="button" onClick={() => setIsEditing({...isEditing, size_type: 'letter', available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL']})} className={`px-3 py-1 rounded-md text-[9px] font-black uppercase transition-all ${isEditing.size_type === 'letter' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>ABC</button><button type="button" onClick={() => setIsEditing({...isEditing, size_type: 'number', available_sizes: ['65', '70', '75', '80', '85', '90']})} className={`px-3 py-1 rounded-md text-[9px] font-black uppercase transition-all ${isEditing.size_type === 'number' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>123</button></div></div>
              <div className="flex-1 flex flex-wrap content-start gap-2 p-3 bg-white rounded-xl border border-slate-200 min-h-[100px]">{isEditing.available_sizes?.map((sz, idx) => (<div key={idx} className="bg-indigo-600 text-white px-3 py-1.5 rounded-lg text-xs font-black flex items-center gap-2 shadow-sm">{sz}<button type="button" onClick={() => { const newSizes = isEditing.available_sizes?.filter((_, i) => i !== idx); setIsEditing({...isEditing, available_sizes: newSizes}); }} className="text-white/50 hover:text-white transition-colors"><X size={12}/></button></div>))}</div>
              <button type="button" onClick={() => { const newVal = prompt(`Enter new size:`); if (newVal) setIsEditing({...isEditing, available_sizes: [...(isEditing.available_sizes || []), newVal]}); }} className="w-full mt-4 py-2.5 border-2 border-dashed border-indigo-200 text-indigo-600 font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-white flex items-center justify-center gap-2"><Plus size={14}/> Add custom size</button>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-12">
          {isPackingReq && (
            <>
              <div id={`field-${category.name}-packing_type`} className="space-y-3"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Type of Packing</label><select className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm cursor-pointer" value={isEditing.packing_type} onChange={e => setIsEditing({...isEditing, packing_type: e.target.value})}><option value="pouch">Pouch</option><option value="cover">Cover</option><option value="box">Box</option></select></div>
              <div id={`field-${category.name}-pcs_per_box`} className="space-y-3"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">No of pieces / Box</label><input type="number" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm" value={isEditing.pcs_per_box} onChange={e => setIsEditing({...isEditing, pcs_per_box: parseInt(e.target.value) || 0})}/></div>
            </>
          )}

          {category.fields.map(field => {
            const item = isEditing.tech_pack[category.name]?.[field] || { text: '', attachments: [] };
            const isSplit = !!item.variants;

            return (
              <div key={field} id={`field-${category.name}-${field}`} className="space-y-4 col-span-full bg-slate-50/30 p-6 rounded-3xl border border-slate-100 transition-all">
                <div className="flex justify-between items-center px-1">
                  <div className="flex items-center gap-3">
                    <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">{field}</label>
                    {!isSplit && (
                      <ConsumptionInput 
                        type={item.consumption_type} 
                        value={item.consumption_val} 
                        onChange={(t, v) => {
                          const updated = { ...isEditing };
                          if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {};
                          updated.tech_pack[category.name][field] = { ...item, consumption_type: t, consumption_val: v };
                          setIsEditing(updated);
                        }}
                        onClear={() => {
                          const updated = { ...isEditing };
                          delete updated.tech_pack[category.name][field].consumption_type;
                          delete updated.tech_pack[category.name][field].consumption_val;
                          setIsEditing(updated);
                        }}
                      />
                    )}
                  </div>
                  {!isSplit ? (
                    <button type="button" onClick={() => handleSplitColor(field)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                  ) : (
                    <button type="button" onClick={() => handleUnsplit(field)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                  )}
                </div>

                {!isSplit ? (
                  <div className="space-y-3 animate-fade-in">
                    <textarea className="w-full border-2 border-slate-100 rounded-2xl p-5 text-sm font-medium focus:border-indigo-500 outline-none min-h-[100px] bg-white transition-all text-black" value={item.text} placeholder={`Global technical instructions for ${field.toLowerCase()}...`} onChange={e => { const updated = { ...isEditing }; if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {}; updated.tech_pack[category.name][field] = { ...item, text: e.target.value }; setIsEditing(updated); }} />
                    <div className="flex flex-wrap gap-2">{item.attachments.map((att, idx) => (<div key={idx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-lg text-xs font-bold text-indigo-700"> <ImageIcon size={14}/> <span className="truncate max-w-[100px]">{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].attachments.splice(idx, 1); setIsEditing(updated); }} className="hover:text-red-500"><X size={14}/></button></div>))} <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 hover:bg-indigo-50 text-slate-400 hover:text-indigo-600 px-4 py-2 rounded-xl text-xs font-bold transition-all cursor-pointer flex items-center gap-2"><Plus size={14}/> Add Attachment <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files)}/></label></div>
                  </div>
                ) : (
                  <div className="space-y-8 animate-fade-in">
                    {item.variants?.map((variant, vIdx) => (
                      <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group">
                        <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants?.splice(vIdx, 1); setIsEditing(updated); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"><X size={16}/></button>

                        <div className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
                          <div className="flex-1">
                            <div className="flex items-center gap-3 mb-3">
                              <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Target Color Group</label>
                              <div className="flex gap-1 ml-2">
                                <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].colors = [...availableColors]; setIsEditing(updated); }} className="text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 hover:bg-indigo-100 transition-colors">All</button>
                                <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].colors = []; setIsEditing(updated); }} className="text-[8px] font-black uppercase text-slate-500 bg-white px-2 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                              </div>
                              {!variant.sizeVariants && (
                                <ConsumptionInput 
                                  type={variant.consumption_type} 
                                  value={variant.consumption_val} 
                                  onChange={(t, v) => {
                                    const updated = { ...isEditing };
                                    updated.tech_pack[category.name][field].variants![vIdx] = { ...variant, consumption_type: t, consumption_val: v };
                                    setIsEditing(updated);
                                  }}
                                  onClear={() => {
                                    const updated = { ...isEditing };
                                    delete updated.tech_pack[category.name][field].variants![vIdx].consumption_type;
                                    delete updated.tech_pack[category.name][field].variants![vIdx].consumption_val;
                                    setIsEditing(updated);
                                  }}
                                />
                              )}
                            </div>
                            <div className="flex flex-wrap gap-2">{availableColors.map(color => { const isSelected = variant.colors.includes(color); return (<button type="button" key={color} onClick={() => { const updated = { ...isEditing }; const v = updated.tech_pack[category.name][field].variants![vIdx]; if (isSelected) v.colors = v.colors.filter(c => c !== color); else v.colors.push(color); setIsEditing(updated); }} className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}>{color}</button>); })} {availableColors.length === 0 && <span className="text-[10px] text-slate-300 italic">No colors defined at top</span>}</div>
                          </div>
                          {!variant.sizeVariants && (
                            <button type="button" onClick={() => handleAddSizeGroup(field, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                          )}
                        </div>

                        {!variant.sizeVariants ? (
                          <div className="space-y-4">
                            <textarea className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none min-h-[80px] bg-slate-50/50 transition-all text-black" value={variant.text} placeholder="Instructions for these colors..." onChange={e => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].text = e.target.value; setIsEditing(updated); }} />
                            <div className="flex flex-wrap gap-2">{variant.attachments.map((att, attIdx) => (<div key={attIdx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-2 py-1 rounded-lg text-[10px] font-bold text-indigo-700"><span>{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].attachments.splice(attIdx, 1); setIsEditing(updated); }} className="hover:text-red-500"><X size={12}/></button></div>))}<label className="bg-white border border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all cursor-pointer flex items-center gap-2"><Plus size={12}/> File <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files, vIdx)}/></label></div>
                          </div>
                        ) : (
                          <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2 animate-fade-in">
                             <div className="flex justify-between items-center mb-2"><h5 className="text-[11px] font-black text-blue-500 uppercase tracking-widest">Nested Size Groups</h5><button type="button" onClick={() => { if(confirm("Discard all size splits?")) { const updated = { ...isEditing }; delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants; setIsEditing(updated); } }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500 transition-colors">Discard Splits</button></div>

                             {variant.sizeVariants.map((sv, svIdx) => (
                               <div key={svIdx} className="p-5 bg-blue-50/30 rounded-3xl border border-blue-100 space-y-4 relative group/size">
                                 <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants?.splice(svIdx, 1); setIsEditing(updated); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border border-red-50 opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                 <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                   <div>
                                     <div className="flex items-center gap-3 mb-2">
                                       <label className="block text-[9px] font-black text-blue-400 uppercase tracking-widest">Apply to Sizes</label>
                                       <div className="flex gap-1">
                                         <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].sizes = [...availableSizes]; setIsEditing(updated); }} className="text-[7px] font-black uppercase text-blue-600 bg-white px-1.5 py-0.5 rounded border border-blue-100 hover:bg-blue-50 transition-colors">All</button>
                                         <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].sizes = []; setIsEditing(updated); }} className="text-[7px] font-black uppercase text-slate-400 bg-white px-1.5 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                       </div>
                                     </div>
                                     <div className="flex flex-wrap gap-1.5">
                                       {availableSizes.map(sz => {
                                         const isSzSelected = sv.sizes.includes(sz);
                                         return (
                                           <button
                                             type="button"
                                             key={sz}
                                             onClick={() => {
                                               const updated = { ...isEditing };
                                               const sVar = updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx];
                                               if (isSzSelected) sVar.sizes = sVar.sizes.filter(s => s !== sz);
                                               else sVar.sizes.push(sz);
                                               setIsEditing(updated);
                                             }}
                                             className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase transition-all ${isSzSelected ? 'bg-blue-600 text-white' : 'bg-white text-blue-300 border border-blue-50 hover:bg-blue-50'}`}
                                           >
                                             {sz}
                                           </button>
                                         );
                                       })}
                                     </div>
                                   </div>
                                   <ConsumptionInput 
                                    type={sv.consumption_type} 
                                    value={sv.consumption_val} 
                                    onChange={(t, v) => {
                                      const updated = { ...isEditing };
                                      updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: v };
                                      setIsEditing(updated);
                                    }}
                                    onClear={() => {
                                      const updated = { ...isEditing };
                                      delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].consumption_type;
                                      delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].consumption_val;
                                      setIsEditing(updated);
                                    }}
                                  />
                                 </div>

                                 <textarea className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[70px] text-black transition-all" value={sv.text} placeholder={`Specific instructions for the selected sizes...`} onChange={e => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].text = e.target.value; setIsEditing(updated); }}/>

                                 <div className="flex flex-wrap gap-2">
                                    {sv.attachments.map((att, attIdx) => (<div key={attIdx} className="flex items-center gap-2 bg-white border border-blue-50 px-2 py-1 rounded-lg text-[9px] font-bold text-blue-700"><span>{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].attachments.splice(attIdx, 1); setIsEditing(updated); }} className="text-red-400"><X size={10}/></button></div>))}
                                    <label className="bg-white border-2 border-dashed border-blue-100 hover:border-blue-400 text-blue-300 px-3 py-1 rounded-xl text-[9px] font-black cursor-pointer flex items-center gap-2"><Plus size={12}/> File <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files, vIdx, svIdx)}/></label>
                                 </div>
                               </div>
                             ))}

                             <button type="button" onClick={() => handleAddSizeGroup(field, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50 hover:text-blue-500 transition-all">+ Add Nested Size Group</button>
                          </div>
                        )}
                      </div>
                    ))}
                    <button type="button" onClick={() => handleSplitColor(field)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 hover:text-indigo-400 transition-all">+ Add Color Variant Group</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { X, RefreshCcw, FilePlus, CheckSquare, Square, Info, Save, Loader2, Plus, Split, Scan, ImageIcon, Trash2 } from 'lucide-react';
import { Style, StyleTemplate, Attachment, TechPackItem } from '../../types';
import { ConsumptionInput } from './ConsumptionInput';
import { uploadOrderAttachment } from '../../services/db';

interface BulkUpdateModalProps {
  styles: Style[];
  template: StyleTemplate | null;
  selectedStyleIds: string[];
  bulkUpdateMeta: {
    strategy: 'overwrite' | 'append';
  };
  setBulkUpdateMeta: (meta: any) => void;
  bulkFieldValues: Record<string, { isEnabled: boolean } & TechPackItem>;
  setBulkFieldValues: (vals: any) => void;
  isUploading: boolean;
  setIsUploading: (val: boolean) => void;
  onClose: () => void;
  onExecute: () => void;
  unionColors: string[];
  unionSizes: string[];
}

export const BulkUpdateModal: React.FC<BulkUpdateModalProps> = ({ 
  styles, 
  template, 
  selectedStyleIds, 
  bulkUpdateMeta, 
  setBulkUpdateMeta, 
  bulkFieldValues, 
  setBulkFieldValues, 
  isUploading, 
  setIsUploading, 
  onClose, 
  onExecute,
  unionColors,
  unionSizes
}) => {

  const handleFieldChange = (key: string, updates: Partial<TechPackItem>) => {
    setBulkFieldValues((prev: any) => ({
      ...prev,
      [key]: { ...prev[key], ...updates }
    }));
  };

  const handleSplitColor = (key: string) => {
    const current = bulkFieldValues[key];
    if (!current.variants) {
      handleFieldChange(key, {
        variants: [{ colors: [], text: current.text || '', attachments: current.attachments || [], consumption_type: current.consumption_type, consumption_val: current.consumption_val }]
      });
    } else {
      handleFieldChange(key, {
        variants: [...current.variants, { colors: [], text: '', attachments: [] }]
      });
    }
  };

  const handleAddSizeGroup = (key: string, vIdx: number) => {
    const current = { ...bulkFieldValues[key] };
    const variant = current.variants![vIdx];
    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }
    setBulkFieldValues((prev: any) => ({ ...prev, [key]: current }));
  };

  const handleUnsplit = (key: string) => {
    const current = bulkFieldValues[key];
    if (current.variants) {
      handleFieldChange(key, {
        text: current.variants[0].text,
        attachments: current.variants[0].attachments,
        consumption_type: current.variants[0].consumption_type,
        consumption_val: current.variants[0].consumption_val,
        variants: undefined
      });
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-6xl overflow-hidden animate-scale-up border border-slate-200 flex flex-col max-h-[95vh]">
        <div className="p-8 border-b bg-orange-50 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-2xl font-black text-orange-900 uppercase tracking-tight">Bulk Blueprint Synchronizer</h3>
            <p className="text-orange-700 text-xs font-bold uppercase tracking-widest mt-1">Applying changes to {selectedStyleIds.length} styles</p>
          </div>
          <button onClick={onClose} className="text-orange-300 hover:text-orange-600 transition-colors p-2"><X size={32}/></button>
        </div>

        <div className="p-8 flex-1 overflow-y-auto space-y-8 bg-slate-50/50">
           <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="flex-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Merge Strategy</label>
                <div className="flex bg-orange-100/50 p-1 rounded-xl border border-orange-100 max-w-md">
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'overwrite'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'overwrite' ? 'bg-orange-600 text-white shadow-md' : 'text-orange-500 hover:bg-orange-100'}`}>
                    <RefreshCcw size={14}/> Overwrite
                  </button>
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'append'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'append' ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-500 hover:bg-indigo-50'}`}>
                    <FilePlus size={14}/> Append to existing
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-3 text-indigo-500 bg-indigo-50 p-4 rounded-2xl border border-indigo-100 max-w-sm">
                <Info size={24}/>
                <p className="text-[10px] font-bold uppercase leading-relaxed">Splits are based on a union of all database attributes. Attributes not present in a specific style will be ignored during sync.</p>
              </div>
           </div>

           {template?.config.map(cat => (
             <div key={cat.name} className="space-y-4">
                <div className="flex items-center gap-3 px-4">
                  <div className="h-px flex-1 bg-slate-200"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{cat.name}</span>
                  <div className="h-px flex-1 bg-slate-200"></div>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {cat.fields.map(f => {
                    const fieldKey = `${cat.name}|${f}`;
                    const fieldData = bulkFieldValues[fieldKey];
                    if (!fieldData) return null;
                    const isSplit = !!fieldData.variants;

                    return (
                      <div key={f} className={`bg-white rounded-3xl border transition-all duration-300 ${fieldData.isEnabled ? 'border-indigo-500 ring-4 ring-indigo-50 shadow-xl' : 'border-slate-200 opacity-60 grayscale'}`}>
                         <div className="p-6 flex items-center justify-between border-b border-slate-50">
                            <div className="flex items-center gap-4">
                               <button 
                                  onClick={() => setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: { ...prev[fieldKey], isEnabled: !prev[fieldKey].isEnabled } }))}
                                  className={`p-2 rounded-xl transition-all ${fieldData.isEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                               >
                                  {fieldData.isEnabled ? <CheckSquare size={24}/> : <Square size={24}/>}
                               </button>
                               <div>
                                  <h5 className="font-black text-slate-800 uppercase tracking-tight">{f}</h5>
                                  <p className="text-[10px] text-slate-400 font-bold uppercase">Toggle to sync this attribute</p>
                               </div>
                            </div>

                            {fieldData.isEnabled && (
                              <div className="flex items-center gap-4">
                                {!isSplit ? (
                                  <>
                                    <ConsumptionInput 
                                      type={fieldData.consumption_type}
                                      value={fieldData.consumption_val}
                                      onChange={(t, v) => handleFieldChange(fieldKey, { consumption_type: t, consumption_val: v })}
                                      onClear={() => handleFieldChange(fieldKey, { consumption_type: undefined, consumption_val: undefined })}
                                    />
                                    <button type="button" onClick={() => handleSplitColor(fieldKey)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                                  </>
                                ) : (
                                  <button type="button" onClick={() => handleUnsplit(fieldKey)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                                )}
                              </div>
                            )}
                         </div>

                         {fieldData.isEnabled && (
                           <div className="p-6 space-y-6 animate-fade-in bg-slate-50/20">
                              {!isSplit ? (
                                <div className="space-y-4">
                                  <textarea 
                                    className="w-full border-2 border-slate-100 rounded-2xl p-4 h-32 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium bg-white shadow-sm"
                                    placeholder={bulkUpdateMeta.strategy === 'append' ? `Content to append...` : `Content to overwrite...`}
                                    value={fieldData.text || ''}
                                    onChange={e => handleFieldChange(fieldKey, { text: e.target.value })}
                                  />
                                  <div className="flex flex-wrap gap-2">
                                    {fieldData.attachments?.map((a: Attachment, idx: number) => (
                                      <div key={idx} className="flex items-center gap-1.5 bg-indigo-50 px-3 py-1.5 rounded-lg text-[9px] font-black text-indigo-700 border border-indigo-100">
                                        <ImageIcon size={10}/> {a.name} <button onClick={() => handleFieldChange(fieldKey, { attachments: fieldData.attachments.filter((_: any, i: number) => i !== idx) })}><X size={10}/></button>
                                      </div>
                                    ))}
                                    <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-4 py-2 rounded-xl text-[10px] font-black cursor-pointer flex items-center gap-2 transition-all">
                                      <Plus size={14}/> Add File
                                      <input 
                                        type="file" multiple className="hidden" 
                                        onChange={async (e) => {
                                          if (!e.target.files) return;
                                          setIsUploading(true);
                                          const newAtts = [];
                                          const files = Array.from(e.target.files) as File[];
                                          for (const file of files) {
                                            const url = await uploadOrderAttachment(file);
                                            if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                          }
                                          handleFieldChange(fieldKey, { attachments: [...(fieldData.attachments || []), ...newAtts] });
                                          setIsUploading(false);
                                        }}
                                      />
                                    </label>
                                  </div>
                                </div>
                              ) : (
                                <div className="space-y-6">
                                  {fieldData.variants?.map((v, vIdx) => (
                                    <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group/var">
                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants?.splice(vIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover/var:opacity-100 transition-opacity"><X size={16}/></button>

                                      <div className="mb-6 flex flex-col md:flex-row md:items-start justify-between gap-6">
                                        <div className="flex-1">
                                          <div className="flex items-center gap-3 mb-3">
                                            <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Global Attribute Union (Colors)</label>
                                            <div className="flex gap-1 ml-2">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = [...unionColors]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 hover:bg-indigo-100 transition-colors">All</button>
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-slate-500 bg-white px-2 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                            </div>
                                            {!v.sizeVariants && (
                                              <ConsumptionInput 
                                                type={v.consumption_type}
                                                value={v.consumption_val}
                                                onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx] = { ...v, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].consumption_type; delete updated.variants![vIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />
                                            )}
                                          </div>
                                          <div className="flex flex-wrap gap-1.5 max-h-32 overflow-y-auto p-1">
                                            {unionColors.map(color => {
                                              const isSel = v.colors.includes(color);
                                              return (
                                                <button key={color} type="button" onClick={() => { const updated = { ...fieldData }; const varObj = updated.variants![vIdx]; if (isSel) varObj.colors = varObj.colors.filter(c => c !== color); else varObj.colors.push(color); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSel ? 'bg-indigo-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'}`}>{color}</button>
                                              );
                                            })}
                                          </div>
                                        </div>
                                        {!v.sizeVariants && (
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                                        )}
                                      </div>

                                      {!v.sizeVariants ? (
                                        <div className="space-y-4">
                                          <textarea 
                                            className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50/50"
                                            placeholder="Instructions for selected color union..."
                                            value={v.text}
                                            onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                          />
                                          <div className="flex flex-wrap gap-2">
                                            {v.attachments.map((a, aIdx) => (
                                              <div key={aIdx} className="flex items-center gap-1 bg-indigo-50 text-indigo-700 px-2 py-1 rounded text-[9px] font-black border border-indigo-100">
                                                {a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button>
                                              </div>
                                            ))}
                                            <label className="bg-white border-2 border-dashed border-slate-200 text-slate-400 px-3 py-1 rounded-lg text-[10px] font-black cursor-pointer hover:bg-slate-50 transition-all">
                                              + File
                                              <input type="file" multiple className="hidden" onChange={async (e) => {
                                                if (!e.target.files) return;
                                                setIsUploading(true);
                                                const newAtts = [];
                                                const files = Array.from(e.target.files) as File[];
                                                for (const file of files) {
                                                  const url = await uploadOrderAttachment(file);
                                                  if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                }
                                                const updated = { ...fieldData };
                                                updated.variants![vIdx].attachments = [...(updated.variants![vIdx].attachments || []), ...newAtts];
                                                setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                setIsUploading(false);
                                              }}/>
                                            </label>
                                          </div>
                                        </div>
                                      ) : (
                                        <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2">
                                          <div className="flex justify-between items-center"><h6 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Nested Size Sub-Splits</h6><button type="button" onClick={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500">Discard Splits</button></div>
                                          {v.sizeVariants.map((sv, svIdx) => (
                                            <div key={svIdx} className="p-4 bg-blue-50/20 rounded-2xl border border-blue-100 space-y-4 relative group/size">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants?.splice(svIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                                                <div className="flex-1">
                                                  <div className="flex items-center gap-3 mb-2">
                                                    <label className="block text-[9px] font-black text-blue-400 uppercase tracking-widest">Apply to Sizes (Union Selection)</label>
                                                    <div className="flex gap-1">
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = [...unionSizes]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-blue-600 bg-white px-1.5 py-0.5 rounded border border-blue-100 hover:bg-blue-50 transition-colors">All</button>
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-slate-400 bg-white px-1.5 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                                    </div>
                                                  </div>
                                                  <div className="flex flex-wrap gap-1">
                                                    {unionSizes.map(sz => {
                                                      const isSzSel = sv.sizes.includes(sz);
                                                      return (
                                                        <button key={sz} type="button" onClick={() => { const updated = { ...fieldData }; const sVar = updated.variants![vIdx].sizeVariants![svIdx]; if (isSzSel) sVar.sizes = sVar.sizes.filter(s => s !== sz); else sVar.sizes.push(sz); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSzSel ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-blue-300 border border-blue-100 hover:bg-blue-50'}`}>{sz}</button>
                                                      );
                                                    })}
                                                  </div>
                                                </div>
                                                <ConsumptionInput 
                                                  type={sv.consumption_type}
                                                  value={sv.consumption_val}
                                                  onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                  onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_type; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                />
                                              </div>

                                              <textarea 
                                                className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[60px]"
                                                placeholder="Instructions for selected size union..."
                                                value={sv.text}
                                                onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />

                                              <div className="flex flex-wrap gap-2">
                                                {sv.attachments.map((a, aIdx) => (
                                                  <div key={aIdx} className="flex items-center gap-1 bg-white border border-blue-50 px-2 py-1 rounded text-[9px] font-black text-blue-700">{a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button></div>
                                                ))}
                                                <label className="bg-white border-2 border-dashed border-blue-100 text-blue-300 px-3 py-1 rounded-lg text-[9px] font-black cursor-pointer hover:bg-blue-50 transition-all">+ File <input type="file" multiple className="hidden" onChange={async (e) => {
                                                  if (!e.target.files) return;
                                                  setIsUploading(true);
                                                  const newAtts = [];
                                                  const files = Array.from(e.target.files) as File[];
                                                  for (const file of files) {
                                                    const url = await uploadOrderAttachment(file);
                                                    if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                  }
                                                  const updated = { ...fieldData };
                                                  updated.variants![vIdx].sizeVariants![svIdx].attachments = [...(updated.variants![vIdx].sizeVariants![svIdx].attachments || []), ...newAtts];
                                                  setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                  setIsUploading(false);
                                                }}/></label>
                                              </div>
                                            </div>
                                          ))}
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50">+ Add Size Sub-Split</button>
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                  <button type="button" onClick={() => handleSplitColor(fieldKey)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 transition-all">+ Add Bulk Color Group Variant</button>
                                </div>
                              )}
                           </div>
                         )}
                      </div>
                    );
                  })}
                </div>
             </div>
           ))}
        </div>

        <div className="p-8 border-t bg-white flex justify-between items-center shadow-2xl shrink-0">
          <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
          <button 
            onClick={onExecute} 
            disabled={isUploading}
            className="px-12 py-4 bg-orange-600 text-white rounded-2xl font-black shadow-2xl shadow-orange-200 flex items-center gap-3 active:scale-95 disabled:opacity-50 uppercase text-xs"
          >
            {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Save size={20}/>} Sync Selected Blueprint Fields
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { fetchStyles, upsertStyle, fetchStyleTemplate, deleteStyle, uploadOrderAttachment } from '../services/db';
import { Style, StyleTemplate, Attachment, TechPackItem, ConsumptionType } from '../types';
import { 
  Plus, Search, Grid, Copy, Trash2, Settings, ArrowLeftRight, CheckSquare, Square, FileUp, Table, BookOpen, ChevronRight, Edit3, Printer, X, FileSpreadsheet
} from 'lucide-react';

// Imported modular components
import { StyleFullView } from '../components/style-db/StyleFullView';
import { AuditMatrixModal } from '../components/style-db/AuditMatrixModal';
import { BulkUpdateModal } from '../components/style-db/BulkUpdateModal';
import { BulkImportModal } from '../components/style-db/BulkImportModal';
import { EditorModal } from '../components/style-db/EditorModal';
import { BulkAttributeUpdateModal } from '../components/style-db/BulkAttributeUpdateModal';

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<Style[]>([]);
  const [template, setTemplate] = useState<StyleTemplate | null>(null);
  const [viewMode, setViewMode] = useState<'catalog' | 'compare'>('catalog');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<Style | null>(null);
  const [viewingStyle, setViewingStyle] = useState<Style | null>(null);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [compareList, setCompareList] = useState<Style[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [garmentTypeOptions, setGarmentTypeOptions] = useState(['Pant', 'Trackpant', 'Shorts', 'T-shirt']);
  const [demographicOptions, setDemographicOptions] = useState(['Men', 'Boys']);
  const [isAuditViewOpen, setIsAuditViewOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<{ category?: string, field?: string } | null>(null);

  // Bulk Mode States
  const [isBulkMode, setIsBulkMode] = useState(false);
  const [selectedStyleIds, setSelectedStyleIds] = useState<string[]>([]);
  const [isBulkUpdateModalOpen, setIsBulkUpdateModalOpen] = useState(false);
  const [isBulkImportModalOpen, setIsBulkImportModalOpen] = useState(false);
  const [isBulkAttributeUpdateOpen, setIsBulkAttributeUpdateOpen] = useState(false);
  const [bulkImportData, setBulkImportData] = useState<any[]>([]);
  const bulkFileRef = useRef<HTMLInputElement>(null);

  // Bulk Selection Filters
  const [bulkSelFilter, setBulkSelFilter] = useState({ garment: '', demographic: '', category: '' });

  // Revised Bulk Update Form Structure
  const [bulkUpdateMeta, setBulkUpdateMeta] = useState<{
    strategy: 'overwrite' | 'append';
  }>({
    strategy: 'overwrite'
  });

  const [bulkFieldValues, setBulkFieldValues] = useState<Record<string, {
    isEnabled: boolean;
  } & TechPackItem>>({});

  const loadData = async () => {
    const [s, t] = await Promise.all([fetchStyles(), fetchStyleTemplate()]);
    setStyles(s);
    setTemplate(t);
    const existingGarments = Array.from(new Set([...garmentTypeOptions, ...s.map(style => style.garment_type).filter(Boolean) as string[]]));
    const existingDemos = Array.from(new Set([...demographicOptions, ...s.map(style => style.demographic).filter(Boolean) as string[]]));
    setGarmentTypeOptions(existingGarments);
    setDemographicOptions(existingDemos);

    if (t) {
      const initialValues: Record<string, any> = {};
      t.config.forEach(cat => {
        cat.fields.forEach(f => {
          initialValues[`${cat.name}|${f}`] = { isEnabled: false, text: '', attachments: [] };
        });
      });
      setBulkFieldValues(initialValues);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredStyles = styles.filter(s => 
    s.style_number.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.garment_type && s.garment_type.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const handleSaveStyle = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    setIsUploading(true);
    const payload: Partial<Style> = { ...isEditing };
    if (!payload.id || payload.id === "") delete payload.id;
    const { error } = await upsertStyle(payload);
    setIsUploading(false);
    if (!error) { 
      setIsEditing(null); 
      setEditTarget(null);
      loadData(); 
    } else { 
      alert(error); 
    }
  };

  const handleNewStyle = () => {
    setIsEditing({ 
      id: '', style_number: '', category: 'Casuals', packing_type: 'pouch', pcs_per_box: 0, 
      style_text: '', garment_type: 'T-shirt', demographic: 'Men', 
      available_colors: [''], available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL'], 
      size_type: 'letter', tech_pack: {} 
    });
    setEditTarget(null);
  };

  const handleCopyStyle = (sourceStyle: Style) => {
    const copy = JSON.parse(JSON.stringify(sourceStyle));
    copy.id = ''; 
    copy.style_number = `${sourceStyle.style_number} (Copy)`;
    setIsEditing(copy);
    setEditTarget(null);
  };

  const handleDelete = async (id: string) => { 
    if (confirm("Permanently delete this style?")) { await deleteStyle(id); loadData(); setViewingStyle(null); } 
  };

  const handleFileUpload = async (category: string, field: string, files: FileList | null, vIdx?: number, svIdx?: number) => {
    if (!files || !isEditing) return;
    setIsUploading(true);
    const updated = { ...isEditing };
    if (!updated.tech_pack[category]) updated.tech_pack[category] = {};
    if (!updated.tech_pack[category][field]) updated.tech_pack[category][field] = { text: '', attachments: [] };

    let target: Attachment[];
    if (vIdx !== undefined) {
      const variant = updated.tech_pack[category][field].variants![vIdx];
      if (svIdx !== undefined) target = variant.sizeVariants![svIdx].attachments;
      else target = variant.attachments;
    } else {
      target = updated.tech_pack[category][field].attachments;
    }

    const filesArr = Array.from(files) as File[];
    for (const file of filesArr) {
      const url = await uploadOrderAttachment(file);
      if (url) target.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
    }
    setIsEditing(updated);
    setIsUploading(false);
  };

  const handleCSVImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      const splitCSV = (row: string) => {
          const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
          return row.split(regex).map(val => {
              let cleaned = val.trim();
              if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
                  cleaned = cleaned.substring(1, cleaned.length - 1);
              }
              return cleaned;
          });
      };
      const headers = splitCSV(lines[0]).map(h => h.trim());
      const parsedData = lines.slice(1).map(line => {
        const values = splitCSV(line);
        if (values.length < headers.length) return null;
        const entry: any = {};
        headers.forEach((header, i) => entry[header] = values[i]);
        return entry;
      }).filter(Boolean);
      setBulkImportData(parsedData);
      setIsBulkImportModalOpen(true);
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleExecuteBulkImport = async () => {
    setIsUploading(true);
    try {
      for (const row of bulkImportData) {
        const styleNum = row['Style No.'] || row['Style No'] || row['StyleNo'];
        const gType = row['GarmentType'] || row['Garment Type'] || row['Garment'];
        const demo = row['Demographic'] || row['Demo'];
        const cat = row['Category'] || row['Cat'];
        const desc = row['Short description'] || row['Description'] || row['Short Description'];
        const cols = row['Available colours'] || row['Available colors'] || row['Colours'] || row['Colors'];
        const sizes = row['size variants'] || row['Size variants'] || row['Sizes'];
        const fabricValue = row['fabric'] || row['Fabric'];

        const newStyle: Partial<Style> = {
          style_number: styleNum || 'NEW-STYLE',
          garment_type: gType || 'T-shirt',
          demographic: demo || 'Men',
          category: cat || 'Casuals',
          style_text: desc || '',
          available_colors: (cols || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          available_sizes: (sizes || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          packing_type: 'pouch',
          pcs_per_box: 1,
          tech_pack: {},
          size_type: (sizes || '').match(/[a-zA-Z]/) ? 'letter' : 'number'
        };

        if (fabricValue) {
          const fabricNote = `Fabrication: ${fabricValue}`;
          newStyle.style_text = newStyle.style_text ? `${newStyle.style_text}\n${fabricNote}` : fabricNote;
        }
        await upsertStyle(newStyle);
      }
      alert(`Successfully created ${bulkImportData.length} new styles.`);
      setIsBulkImportModalOpen(false);
      setIsBulkMode(false);
      loadData();
    } catch (err) {
      alert("Import failed: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const handleBulkUpdate = async () => {
    if (selectedStyleIds.length === 0) return;
    setIsUploading(true);
    try {
      const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
      const enabledUpdates = (Object.entries(bulkFieldValues) as [string, typeof bulkFieldValues[string]][]).filter(([_, val]) => val.isEnabled);
      if (enabledUpdates.length === 0) {
        alert("Please select at least one field to update.");
        setIsUploading(false);
        return;
      }

      for (const style of selectedStyles) {
        const updatedStyle = JSON.parse(JSON.stringify(style));
        const { strategy } = bulkUpdateMeta;

        for (const [key, fieldData] of enabledUpdates) {
          const [category, field] = key.split('|');
          if (!updatedStyle.tech_pack[category]) updatedStyle.tech_pack[category] = {};

          const mergeText = (current: string, next: string) => strategy === 'overwrite' ? next : (current ? current + '\n' + next : next);
          const mergeAttachments = (current: Attachment[], next: Attachment[]) => strategy === 'overwrite' ? next : [...(current || []), ...next];

          // Use the TechPackItem structure directly from bulkFieldValues
          const bulkItem = { ...fieldData };
          delete (bulkItem as any).isEnabled;

          const currentItem = updatedStyle.tech_pack[category][field] || { text: '', attachments: [] };

          if (!bulkItem.variants) {
            // Global Update
            currentItem.text = mergeText(currentItem.text, bulkItem.text);
            currentItem.attachments = mergeAttachments(currentItem.attachments, bulkItem.attachments);
            if (bulkItem.consumption_type) currentItem.consumption_type = bulkItem.consumption_type;
            if (bulkItem.consumption_val !== undefined) currentItem.consumption_val = bulkItem.consumption_val;
            if (strategy === 'overwrite') delete (currentItem as any).variants;
          } else {
            // Variant-Based Update
            if (strategy === 'overwrite') {
               currentItem.variants = [];
               delete (currentItem as any).text;
               delete (currentItem as any).attachments;
            } else if (!currentItem.variants) {
               currentItem.variants = [];
            }

            bulkItem.variants.forEach(bulkVar => {
              // Filter colors to only those the style possesses
              const validColors = bulkVar.colors.filter(c => updatedStyle.available_colors?.includes(c));
              if (validColors.length === 0) return; // Skip if no colors match union selection

              let targetVar = currentItem.variants!.find(v => JSON.stringify(v.colors.sort()) === JSON.stringify(validColors.sort()));
              if (!targetVar) {
                targetVar = { colors: validColors, text: '', attachments: [] };
                currentItem.variants!.push(targetVar);
              }

              if (!bulkVar.sizeVariants) {
                targetVar.text = mergeText(targetVar.text, bulkVar.text);
                targetVar.attachments = mergeAttachments(targetVar.attachments, bulkVar.attachments);
                if (bulkVar.consumption_type) targetVar.consumption_type = bulkVar.consumption_type;
                if (bulkVar.consumption_val !== undefined) targetVar.consumption_val = bulkVar.consumption_val;
                if (strategy === 'overwrite') delete (targetVar as any).sizeVariants;
              } else {
                if (strategy === 'overwrite') {
                  targetVar.sizeVariants = [];
                  delete (targetVar as any).text;
                  delete (targetVar as any).attachments;
                } else if (!targetVar.sizeVariants) {
                  targetVar.sizeVariants = [];
                }

                bulkVar.sizeVariants.forEach(bulkSizeVar => {
                  const validSizes = bulkSizeVar.sizes.filter(s => updatedStyle.available_sizes?.includes(s));
                  if (validSizes.length === 0) return;

                  let targetSizeVar = targetVar!.sizeVariants!.find(sv => JSON.stringify(sv.sizes.sort()) === JSON.stringify(validSizes.sort()));
                  if (!targetSizeVar) {
                    targetSizeVar = { sizes: validSizes, text: '', attachments: [] };
                    targetVar!.sizeVariants!.push(targetSizeVar);
                  }

                  targetSizeVar.text = mergeText(targetSizeVar.text, bulkSizeVar.text);
                  targetSizeVar.attachments = mergeAttachments(targetSizeVar.attachments, bulkSizeVar.attachments);
                  if (bulkSizeVar.consumption_type) targetSizeVar.consumption_type = bulkSizeVar.consumption_type;
                  if (bulkSizeVar.consumption_val !== undefined) targetSizeVar.consumption_val = bulkSizeVar.consumption_val;
                });
              }
            });
          }
          updatedStyle.tech_pack[category][field] = currentItem;
        }
        await upsertStyle(updatedStyle);
      }
      alert("Bulk update completed successfully.");
      setIsBulkUpdateModalOpen(false);
      setIsBulkMode(false);
      setSelectedStyleIds([]);
      loadData();
    } catch (err) {
      alert("Error during bulk update: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const toggleSelectStyle = (id: string) => {
    setSelectedStyleIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const applyBulkFilterSelection = (isSelecting: boolean) => {
    const matchingIds = styles.filter(s => {
      const matchesGarment = !bulkSelFilter.garment || s.garment_type === bulkSelFilter.garment;
      const matchesDemographic = !bulkSelFilter.demographic || s.demographic === bulkSelFilter.demographic;
      const matchesCategory = !bulkSelFilter.category || s.category === bulkSelFilter.category;
      return matchesGarment && matchesDemographic && matchesCategory;
    }).map(s => s.id);
    if (isSelecting) setSelectedStyleIds(prev => Array.from(new Set([...prev, ...matchingIds])));
    else setSelectedStyleIds(prev => prev.filter(id => !matchingIds.includes(id)));
  };

  const handleMatrixCellClick = (style: Style, catName: string, fieldName?: string) => {
    setIsEditing(style);
    setEditTarget({ category: catName, field: fieldName });
    setIsAuditViewOpen(false);
  };

  const checkCompleteness = (style: Style, cat: string, field: string) => {
    const item = style.tech_pack[cat]?.[field];
    if (!item) return false;
    return !!( (item.text && item.text.trim() !== '') || (item.attachments && item.attachments.length > 0) || (item.variants && item.variants.length > 0) );
  };

  const handlePrint = (style: Style) => {
    const win = window.open('', 'StylePrint', 'width=1000,height=800');
    if (!win || !template) return;

    // Helper to render attachments in a grid for the printout
    const renderAttachmentsHtml = (attachments: Attachment[]) => {
      if (!attachments || attachments.length === 0) return '';
      const images = attachments.filter(a => a.type === 'image');
      const docs = attachments.filter(a => a.type === 'document');

      let html = '<div style="margin-top: 15px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px;">';
      images.forEach(img => {
        html += `
          <div style="border: 1px solid #e2e8f0; border-radius: 8px; overflow: hidden; break-inside: avoid; background: #fff;">
            <img src="${img.url}" style="width: 100%; display: block;"/>
            <div style="padding: 6px; font-size: 8px; font-weight: bold; background: #fff; text-align: center; color: #64748b; border-top: 1px solid #e2e8f0;">${img.name}</div>
          </div>`;
      });
      html += '</div>';

      if (docs.length > 0) {
        html += '<div style="margin-top: 8px; font-size: 9px; color: #4f46e5; font-weight: bold; padding-left: 5px;">';
        docs.forEach(doc => {
          html += `<div>• DOCUMENT: ${doc.name}</div>`;
        });
        html += '</div>';
      }
      return html;
    };

    const techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
        const fields = cat.fields.map(f => {
            const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
            let contentHtml = '';
            if (item.variants) {
                contentHtml = item.variants.map(v => {
                    let sizeHtml = '';
                    if (v.sizeVariants) {
                        sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                            <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px; break-inside:avoid;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                    ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:16px;">SIZE: ${sz}</span>`).join('')}
                                    ${sv.consumption_type ? `<span style="background:#f1f5f9; color:#1e293b; padding:4px 10px; border-radius:6px; font-weight:bold; font-size:12px;">Ratio: ${sv.consumption_val} ${sv.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</span>` : ''}
                                </div>
                                <div style="font-size:18px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                                ${renderAttachmentsHtml(sv.attachments)}
                            </div>
                        `).join('')}</div>`;
                    }
                    return `
                      <div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;">
                        <div style="margin-bottom:10px; display: flex; justify-content: space-between; align-items: center;">
                          <div>${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div>
                          ${v.consumption_type ? `<div style="font-size: 10px; font-weight: bold; color: #4f46e5;">RATIO: ${v.consumption_val} ${v.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                        </div>
                        <div style="font-size:20px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>
                        ${renderAttachmentsHtml(v.attachments)}
                        ${sizeHtml}
                      </div>`;
                }).join('');
            } else {
              contentHtml = `
                <div style="break-inside:avoid;">
                  <div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">
                    ${item.text || '---'}
                    ${item.consumption_type ? `<div style="margin-top: 10px; font-size: 12px; font-weight: bold; color: #4f46e5; background: #fff; padding: 5px 10px; border-radius: 6px; display: inline-block; border: 1px solid #e2e8f0;">Global Ratio: ${item.consumption_val} ${item.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                  </div>
                  ${renderAttachmentsHtml(item.attachments)}
                </div>`;
            }
            return `
                <div style="margin-bottom:30px; border-bottom:1px solid #eee; padding-bottom:15px; break-inside:avoid;">
                    <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:6px; letter-spacing: 1px;">${f}</div>
                    ${contentHtml}
                </div>`;
        }).join('');
        return `
            <div style="margin-top:40px; page-break-before:always;">
                <h3 style="background:#1e293b; color:#fff; padding:12px 20px; font-size:14px; text-transform:uppercase; letter-spacing:2px; border-radius: 8px;">${cat.name}</h3>
                <div style="padding:15px;">${fields}</div>
            </div>`;
    }).join('');

    win.document.write(`
      <html>
        <head>
          <title>Tech Pack - ${style.style_number}</title>
          <style>
            body { font-family: 'Segoe UI', system-ui, -apple-system, Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; line-height: 1.4; background: #fff; }
            .header { text-align: center; border-bottom: 5px solid #1e293b; padding-bottom: 25px; margin-bottom: 35px; }
            .brand { font-size: 36px; font-weight: 900; text-transform: uppercase; margin: 0; color: #1e293b; }
            .title { font-size: 18px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #64748b; letter-spacing: 2px; }
            .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; }
            .box { padding: 15px; border: 2px solid #e2e8f0; border-radius: 12px; background: #fcfcfc; }
            .label { font-size: 10px; text-transform: uppercase; color: #94a3b8; font-weight: 900; letter-spacing: 1px; }
            .value { font-size: 16px; font-weight: 900; color: #1e293b; margin-top: 4px; }
            .section-title { font-size: 20px; font-weight: 900; border-bottom: 4px solid #1e293b; padding-bottom: 8px; margin-top: 45px; margin-bottom: 20px; text-transform: uppercase; letter-spacing: 1px; color: #1e293b; }
            .summary-box { padding: 25px; border: 2px solid #e2e8f0; min-height: 80px; background:#f8fafc; border-radius:15px; font-size:18px; font-weight: bold; color: #475569; line-height: 1.5; white-space: pre-wrap; }
            @media print {
              body { padding: 20px; }
              @page { margin: 1.5cm; }
            }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Master Technical Specification Package</div>
          </div>

          <div class="grid">
            <div class="box"><span class="label">Style Number</span><div class="value">${style.style_number}</div></div>
            <div class="box"><span class="label">Garment Category</span><div class="value">${style.category}</div></div>
            <div class="box"><span class="label">Style Specification</span><div class="value">${style.garment_type || 'N/A'}</div></div>
            <div class="box"><span class="label">Market Segment</span><div class="value">${style.demographic || 'N/A'}</div></div>
            <div class="box"><span class="label">Packing Specs</span><div class="value">${style.packing_type} (${style.pcs_per_box} pcs)</div></div>
            <div class="box"><span class="label">Issue Date</span><div class="value">${new Date().toLocaleDateString()}</div></div>
          </div>

          <div class="section-title">Color & Size Blueprint</div>
          <div style="display: flex; gap: 20px; margin-bottom: 40px;">
            <div style="flex: 1; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
              <span class="label">Approved Palette</span>
              <div style="margin-top: 10px; display: flex; flex-wrap: wrap; gap: 6px;">
                ${(style.available_colors || []).filter(c => c).map(c => `<span style="background:#f1f5f9; color:#1e293b; font-size:10px; font-weight:bold; padding:4px 10px; border-radius:6px; border: 1px solid #e2e8f0; text-transform: uppercase;">${c}</span>`).join('')}
              </div>
            </div>
            <div style="flex: 1; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
              <span class="label">Size Grid (${style.size_type})</span>
              <div style="margin-top: 10px; display: flex; flex-wrap: wrap; gap: 6px;">
                ${(style.available_sizes || []).map(s => `<span style="background:#4f46e5; color:#fff; font-size:10px; font-weight:bold; padding:4px 10px; border-radius:6px; text-transform: uppercase;">${s}</span>`).join('')}
              </div>
            </div>
          </div>

          <div class="section-title">Global Construction Summary</div>
          <div class="summary-box">
            ${style.style_text || "Standard technical construction procedures apply. No specific summary provided."}
          </div>

          ${techPackHtml}

          <div style="margin-top: 60px; text-align: center; border-top: 1px solid #eee; padding-top: 30px;">
            <div style="font-size: 10px; color: #94a3b8; text-transform: uppercase; font-weight: bold; letter-spacing: 1px;">
              Internal Document Control: Tintura SST Automated Engineering System
            </div>
            <div style="font-size: 8px; color: #cbd5e1; margin-top: 5px;">
              Blueprint ID: ${style.id} | Page 1 of Content
            </div>
          </div>

          <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
        </body>
      </html>`);
    win.document.close();
  };

  const unionColors = Array.from(new Set(styles.flatMap(s => s.available_colors || []))).filter(Boolean).sort();
  const unionSizes = Array.from(new Set(styles.flatMap(s => s.available_sizes || []))).filter(Boolean).sort();

  if (viewingStyle) return <StyleFullView style={viewingStyle} template={template} onBack={() => setViewingStyle(null)} onEdit={() => { setIsEditing(viewingStyle); setViewingStyle(null); }} onPrint={() => handlePrint(viewingStyle)} onDelete={() => handleDelete(viewingStyle.id)} />;

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row justify-between xl:items-center gap-4">
        <div><h2 className="text-3xl font-black text-slate-800 flex items-center gap-3"><div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><BookOpen size={28}/></div>Style Technical Database</h2><p className="text-slate-500 text-sm mt-1">Master Tech-Packs and Design Blueprint Management</p></div>
        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setViewMode('catalog')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'catalog' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid size={18}/> Catalog</button>
            <button onClick={() => setViewMode('compare')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'compare' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ArrowLeftRight size={18}/> Compare</button>
          </div>
          <div className="h-8 w-px bg-slate-200 mx-2"></div>

          <button onClick={() => setIsBulkAttributeUpdateOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-green-600 hover:border-green-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Sync Specific Values via CSV"><FileSpreadsheet size={20}/> Sync Values (CSV)</button>

          <button onClick={() => setIsAuditViewOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 hover:border-indigo-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Data Completeness Matrix"><Table size={20}/> Matrix Audit</button>
          <button onClick={() => { setIsBulkMode(!isBulkMode); setSelectedStyleIds([]); }} className={`p-3 rounded-xl border transition-all flex items-center gap-2 font-bold text-sm ${isBulkMode ? 'bg-orange-600 text-white border-orange-600 shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-orange-500 hover:text-orange-600'}`}><CheckSquare size={20}/> {isBulkMode ? 'Exit Bulk Mode' : 'Bulk Selection'}</button>
          <button onClick={() => setIsConfigOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 rounded-xl transition-all"><Settings size={20}/></button>
          <button onClick={handleNewStyle} className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><Plus size={20}/> New Style</button>
        </div>
      </div>

      <div className="relative"><input type="text" placeholder="Search by Style Number, Category, or Garment Type..." className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-500 outline-none transition-all font-bold shadow-sm bg-white text-black" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/><Search className="absolute left-4 top-4 text-slate-400" size={24}/></div>

      {isBulkMode && (
        <div className="bg-slate-900/5 p-6 rounded-3xl border-2 border-dashed border-indigo-200 animate-fade-in">
           <div className="flex flex-col md:flex-row items-end gap-4">
              <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4">
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Garment Type Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.garment} onChange={e => setBulkSelFilter({...bulkSelFilter, garment: e.target.value})}><option value="">All Garment Types</option>{garmentTypeOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Demographic Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.demographic} onChange={e => setBulkSelFilter({...bulkSelFilter, demographic: e.target.value})}><option value="">All Demographics</option>{demographicOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.category} onChange={e => setBulkSelFilter({...bulkSelFilter, category: e.target.value})}><option value="">All Categories</option><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
              </div>
              <div className="flex gap-2 shrink-0"><button onClick={() => applyBulkFilterSelection(true)} className="px-5 py-3 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center gap-2"><CheckSquare size={16}/> Select All Matching</button><button onClick={() => applyBulkFilterSelection(false)} className="px-5 py-3 bg-white text-slate-500 border border-slate-200 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2"><Square size={16}/> Deselect All Matching</button></div>
           </div>
        </div>
      )}

      {viewMode === 'catalog' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in relative pb-24">
          {filteredStyles.map(style => {
            const isSelected = selectedStyleIds.includes(style.id);
            return (
              <div key={style.id} className={`bg-white rounded-2xl border shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col ${isBulkMode && isSelected ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200'}`}>
                <div className="p-6 flex-1 cursor-pointer relative" onClick={() => isBulkMode ? toggleSelectStyle(style.id) : setViewingStyle(style)}>
                  {isBulkMode && <div className="absolute top-4 right-4 z-10">{isSelected ? <CheckSquare className="text-indigo-600"/> : <Square className="text-slate-300"/>}</div>}
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                      <div className="bg-slate-100 px-3 py-1 rounded-full text-[10px] font-black text-slate-500 uppercase tracking-widest">{style.garment_type}</div>
                      <div className="bg-indigo-50 px-3 py-1 rounded-full text-[10px] font-black text-indigo-500 uppercase tracking-widest">{style.demographic}</div>
                    </div>
                    {!isBulkMode && <div className="flex gap-2" onClick={e => e.stopPropagation()}><button onClick={() => handlePrint(style)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Printer size={16}/></button><button onClick={() => handleDelete(style.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"><Trash2 size={16}/></button></div>}
                  </div>
                  <div className="flex items-center justify-between group/title"><h3 className="text-2xl font-black text-slate-800 tracking-tight mb-2 group-hover/title:text-indigo-600 transition-colors">{style.style_number}</h3><ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600 transition-all transform group-hover:translate-x-1" /></div>
                  <p className="text-slate-500 text-xs font-medium line-clamp-2 leading-relaxed mb-4">{style.style_text || 'No description provided.'}</p>
                </div>
                {!isBulkMode && (
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex gap-2">
                    <button onClick={() => { setIsEditing(style); setEditTarget(null); }} className="flex-1 py-2.5 bg-white border border-slate-200 rounded-xl text-xs font-black text-slate-700 hover:border-indigo-500 hover:text-indigo-600 transition-all flex items-center justify-center gap-2"><Edit3 size={14}/> Edit</button>
                    <button onClick={() => handleCopyStyle(style)} className="p-2.5 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-indigo-600 hover:border-indigo-600 transition-all" title="Create Copy"><Copy size={16}/></button>
                    <button onClick={() => { if (compareList.find(s => s.id === style.id)) setCompareList(prev => prev.filter(s => s.id !== style.id)); else { setCompareList(prev => [...prev, style]); setViewMode('compare'); } }} className={`p-2.5 rounded-xl border transition-all ${compareList.find(s => s.id === style.id) ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-500 hover:text-indigo-600'}`}><ArrowLeftRight size={18}/></button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {isBulkMode && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-slide-up">
           <div className="bg-slate-900 text-white rounded-full px-8 py-4 shadow-2xl flex items-center gap-6 border border-white/10">
              <div className="flex flex-col"><span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Bulk Actions</span><span className="text-xl font-black">{selectedStyleIds.length} Selected</span></div>
              <div className="h-10 w-px bg-white/20"></div>
              <div className="flex items-center gap-3">
                {selectedStyleIds.length > 0 && <button onClick={() => setIsBulkUpdateModalOpen(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><Edit3 size={18}/> Edit technical fields</button>}
                <button onClick={() => bulkFileRef.current?.click()} className="bg-orange-600 hover:bg-orange-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><FileUp size={18}/> Create Bulk (CSV)</button>
                <input type="file" min-h-[600px] ref={bulkFileRef} accept=".csv" className="hidden" onChange={handleCSVImport} />
              </div>
              <button onClick={() => { setSelectedStyleIds([]); setIsBulkMode(false); }} className="text-slate-400 hover:text-white transition-colors ml-2"><X/></button>
           </div>
        </div>
      )}

      {viewMode === 'compare' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-x-auto min-h-[600px] animate-fade-in">{compareList.length === 0 ? (<div className="p-20 text-center text-slate-400"><ArrowLeftRight size={48} className="mx-auto mb-4 opacity-20"/><p className="text-xl font-bold">Desk Empty</p><button onClick={() => setViewMode('catalog')} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold">Back to Catalog</button></div>) : (<div className="p-8 inline-flex gap-8">{compareList.map(style => (<div key={style.id} className="w-96 shrink-0 bg-slate-50/50 rounded-3xl border border-slate-200 flex flex-col shadow-inner overflow-hidden"><div className="p-6 bg-white border-b border-slate-200 sticky top-0 z-10"><div className="flex justify-between items-start"><h3 className="text-2xl font-black text-slate-800">{style.style_number}</h3><button onClick={() => setCompareList(prev => prev.filter(s => s.id !== style.id))} className="p-1 text-slate-300 hover:text-red-500 transition-colors"><X size={20}/></button></div><div className="mt-4 flex flex-wrap gap-2"><span className="text-[10px] font-black bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full uppercase">{style.category}</span><span className="text-[10px] font-black bg-slate-100 text-slate-700 px-3 py-1 rounded-full uppercase">{style.garment_type}</span></div></div><div className="p-6 space-y-8 overflow-y-auto">{template?.config.filter(c => c.name !== "General Info").map(cat => (<div key={cat.name}><h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest border-b border-indigo-100 pb-2 mb-4">{cat.name}</h4><div className="space-y-6">{cat.fields.map(field => { const item = style.tech_pack[cat.name]?.[field] || { text: '---', attachments: [] }; return (<div key={field}><div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{field}</div>{!item.variants ? (<div className="text-sm font-medium text-slate-700 whitespace-pre-wrap">{item.text}</div>) : (<div className="space-y-4">{item.variants.map((v, vIdx) => (<div key={vIdx} className="bg-white border rounded-xl p-3 shadow-sm"><div className="flex flex-wrap gap-1 mb-2">{v.colors.map(c => <span key={c} className="bg-indigo-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded uppercase">{c}</span>)}</div><div className="text-xs text-slate-700">{v.text}</div></div>))}</div>)}</div>); })}</div></div>))}</div></div>))}</div>)}</div>
      )}

      {isEditing && (
        <EditorModal 
          isEditing={isEditing} styles={styles} template={template} 
          setIsEditing={setIsEditing} handleSaveStyle={handleSaveStyle} handleCopyStyle={handleCopyStyle} 
          handleFileUpload={handleFileUpload} editTarget={editTarget}
          garmentTypeOptions={garmentTypeOptions} setGarmentTypeOptions={setGarmentTypeOptions}
          demographicOptions={demographicOptions} setDemographicOptions={setDemographicOptions}
          isUploading={isUploading}
        />
      )}

      {isAuditViewOpen && (
        <AuditMatrixModal 
          styles={styles} template={template} onClose={() => setIsAuditViewOpen(false)} 
          onCellClick={handleMatrixCellClick} checkCompleteness={checkCompleteness} 
        />
      )}

      {isBulkUpdateModalOpen && (
        <BulkUpdateModal 
          styles={styles} template={template} selectedStyleIds={selectedStyleIds} 
          bulkUpdateMeta={bulkUpdateMeta} setBulkUpdateMeta={setBulkUpdateMeta} 
          bulkFieldValues={bulkFieldValues} setBulkFieldValues={setBulkFieldValues}
          isUploading={isUploading} setIsUploading={setIsUploading}
          onClose={() => setIsBulkUpdateModalOpen(false)} onExecute={handleBulkUpdate}
          unionColors={unionColors}
          unionSizes={unionSizes}
        />
      )}

      {isBulkImportModalOpen && (
        <BulkImportModal 
          bulkImportData={bulkImportData} isUploading={isUploading} 
          onClose={() => setIsBulkImportModalOpen(false)} onExecute={handleExecuteBulkImport} 
        />
      )}

      {isBulkAttributeUpdateOpen && (
        <BulkAttributeUpdateModal 
          styles={styles} 
          template={template} 
          onClose={() => setIsBulkAttributeUpdateOpen(false)} 
          onRefresh={loadData}
        />
      )}
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { fetchStyles, upsertStyle, fetchStyleTemplate, deleteStyle, uploadOrderAttachment, fetchOrders } from '../services/db';
import { Style, StyleTemplate, Attachment, TechPackItem, ConsumptionType, Order } from '../types';
import { 
  Plus, Search, Grid, Copy, Trash2, Settings, ArrowLeftRight, CheckSquare, Square, FileUp, Table, BookOpen, ChevronRight, Edit3, Printer, X, FileSpreadsheet
} from 'lucide-react';

// Imported modular components
import { StyleFullView } from '../components/style-db/StyleFullView';
import { AuditMatrixModal } from '../components/style-db/AuditMatrixModal';
import { BulkUpdateModal } from '../components/style-db/BulkUpdateModal';
import { BulkImportModal } from '../components/style-db/BulkImportModal';
import { EditorModal } from '../components/style-db/EditorModal';
import { BulkAttributeUpdateModal } from '../components/style-db/BulkAttributeUpdateModal';

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<Style[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [template, setTemplate] = useState<StyleTemplate | null>(null);
  const [viewMode, setViewMode] = useState<'catalog' | 'compare'>('catalog');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<Style | null>(null);
  const [viewingStyle, setViewingStyle] = useState<Style | null>(null);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [compareList, setCompareList] = useState<Style[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [garmentTypeOptions, setGarmentTypeOptions] = useState(['Pant', 'Trackpant', 'Shorts', 'T-shirt']);
  const [demographicOptions, setDemographicOptions] = useState(['Men', 'Boys']);
  const [isAuditViewOpen, setIsAuditViewOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<{ category?: string, field?: string } | null>(null);

  // Bulk Mode States
  const [isBulkMode, setIsBulkMode] = useState(false);
  const [selectedStyleIds, setSelectedStyleIds] = useState<string[]>([]);
  const [isBulkUpdateModalOpen, setIsBulkUpdateModalOpen] = useState(false);
  const [isBulkImportModalOpen, setIsBulkImportModalOpen] = useState(false);
  const [isBulkAttributeUpdateOpen, setIsBulkAttributeUpdateOpen] = useState(false);
  const [bulkImportData, setBulkImportData] = useState<any[]>([]);
  const bulkFileRef = useRef<HTMLInputElement>(null);

  // Bulk Selection Filters
  const [bulkSelFilter, setBulkSelFilter] = useState({ garment: '', demographic: '', category: '' });

  // Revised Bulk Update Form Structure
  const [bulkUpdateMeta, setBulkUpdateMeta] = useState<{
    strategy: 'overwrite' | 'append';
  }>({
    strategy: 'overwrite'
  });

  const [bulkFieldValues, setBulkFieldValues] = useState<Record<string, {
    isEnabled: boolean;
  } & TechPackItem>>({});

  const loadData = async () => {
    const [s, t, o] = await Promise.all([fetchStyles(), fetchStyleTemplate(), fetchOrders()]);
    setStyles(s);
    setTemplate(t);
    setOrders(o);
    const existingGarments = Array.from(new Set([...garmentTypeOptions, ...s.map(style => style.garment_type).filter(Boolean) as string[]]));
    const existingDemos = Array.from(new Set([...demographicOptions, ...s.map(style => style.demographic).filter(Boolean) as string[]]));
    setGarmentTypeOptions(existingGarments);
    setDemographicOptions(existingDemos);

    if (t) {
      const initialValues: Record<string, any> = {};
      t.config.forEach(cat => {
        cat.fields.forEach(f => {
          initialValues[`${cat.name}|${f}`] = { isEnabled: false, text: '', attachments: [] };
        });
      });
      setBulkFieldValues(initialValues);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredStyles = styles.filter(s => 
    s.style_number.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.garment_type && s.garment_type.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const handleSaveStyle = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    setIsUploading(true);
    const payload: Partial<Style> = { ...isEditing };
    if (!payload.id || payload.id === "") delete payload.id;
    const { error } = await upsertStyle(payload);
    setIsUploading(false);
    if (!error) { 
      setIsEditing(null); 
      setEditTarget(null);
      loadData(); 
    } else { 
      alert(error); 
    }
  };

  const handleNewStyle = () => {
    setIsEditing({ 
      id: '', style_number: '', category: 'Casuals', packing_type: 'pouch', pcs_per_box: 0, 
      style_text: '', garment_type: 'T-shirt', demographic: 'Men', 
      available_colors: [''], available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL'], 
      size_type: 'letter', tech_pack: {} 
    });
    setEditTarget(null);
  };

  const handleCopyStyle = (sourceStyle: Style) => {
    const copy = JSON.parse(JSON.stringify(sourceStyle));
    copy.id = ''; 
    copy.style_number = `${sourceStyle.style_number} (Copy)`;
    setIsEditing(copy);
    setEditTarget(null);
  };

  const handleDelete = async (id: string) => { 
    if (confirm("Permanently delete this style?")) { await deleteStyle(id); loadData(); setViewingStyle(null); } 
  };

  const handleFileUpload = async (category: string, field: string, files: FileList | null, vIdx?: number, svIdx?: number) => {
    if (!files || !isEditing) return;
    setIsUploading(true);
    const updated = { ...isEditing };
    if (!updated.tech_pack[category]) updated.tech_pack[category] = {};
    if (!updated.tech_pack[category][field]) updated.tech_pack[category][field] = { text: '', attachments: [] };

    let target: Attachment[];
    if (vIdx !== undefined) {
      const variant = updated.tech_pack[category][field].variants![vIdx];
      if (svIdx !== undefined) target = variant.sizeVariants![svIdx].attachments;
      else target = variant.attachments;
    } else {
      target = updated.tech_pack[category][field].attachments;
    }

    const filesArr = Array.from(files) as File[];
    for (const file of filesArr) {
      const url = await uploadOrderAttachment(file);
      if (url) target.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
    }
    setIsEditing(updated);
    setIsUploading(false);
  };

  const handleCSVImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      const splitCSV = (row: string) => {
          const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
          return row.split(regex).map(val => {
              let cleaned = val.trim();
              if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
                  cleaned = cleaned.substring(1, cleaned.length - 1);
              }
              return cleaned;
          });
      };
      const headers = splitCSV(lines[0]).map(h => h.trim());
      const parsedData = lines.slice(1).map(line => {
        const values = splitCSV(line);
        if (values.length < headers.length) return null;
        const entry: any = {};
        headers.forEach((header, i) => entry[header] = values[i]);
        return entry;
      }).filter(Boolean);
      setBulkImportData(parsedData);
      setIsBulkImportModalOpen(true);
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleExecuteBulkImport = async () => {
    setIsUploading(true);
    try {
      for (const row of bulkImportData) {
        const styleNum = row['Style No.'] || row['Style No'] || row['StyleNo'];
        const gType = row['GarmentType'] || row['Garment Type'] || row['Garment'];
        const demo = row['Demographic'] || row['Demo'];
        const cat = row['Category'] || row['Cat'];
        const desc = row['Short description'] || row['Description'] || row['Short Description'];
        const cols = row['Available colours'] || row['Available colors'] || row['Colours'] || row['Colors'];
        const sizes = row['size variants'] || row['Size variants'] || row['Sizes'];
        const fabricValue = row['fabric'] || row['Fabric'];

        const newStyle: Partial<Style> = {
          style_number: styleNum || 'NEW-STYLE',
          garment_type: gType || 'T-shirt',
          demographic: demo || 'Men',
          category: cat || 'Casuals',
          style_text: desc || '',
          available_colors: (cols || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          available_sizes: (sizes || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          packing_type: 'pouch',
          pcs_per_box: 1,
          tech_pack: {},
          size_type: (sizes || '').match(/[a-zA-Z]/) ? 'letter' : 'number'
        };

        if (fabricValue) {
          const fabricNote = `Fabrication: ${fabricValue}`;
          newStyle.style_text = newStyle.style_text ? `${newStyle.style_text}\n${fabricNote}` : fabricNote;
        }
        await upsertStyle(newStyle);
      }
      alert(`Successfully created ${bulkImportData.length} new styles.`);
      setIsBulkImportModalOpen(false);
      setIsBulkMode(false);
      loadData();
    } catch (err) {
      alert("Import failed: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const handleBulkUpdate = async () => {
    if (selectedStyleIds.length === 0) return;
    setIsUploading(true);
    try {
      const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
      const enabledUpdates = (Object.entries(bulkFieldValues) as [string, typeof bulkFieldValues[string]][]).filter(([_, val]) => val.isEnabled);
      if (enabledUpdates.length === 0) {
        alert("Please select at least one field to update.");
        setIsUploading(false);
        return;
      }

      for (const style of selectedStyles) {
        const updatedStyle = JSON.parse(JSON.stringify(style));
        const { strategy } = bulkUpdateMeta;

        for (const [key, fieldData] of enabledUpdates) {
          const [category, field] = key.split('|');
          if (!updatedStyle.tech_pack[category]) updatedStyle.tech_pack[category] = {};

          const mergeText = (current: string, next: string) => strategy === 'overwrite' ? next : (current ? current + '\n' + next : next);
          const mergeAttachments = (current: Attachment[], next: Attachment[]) => strategy === 'overwrite' ? next : [...(current || []), ...next];

          // Use the TechPackItem structure directly from bulkFieldValues
          const bulkItem = { ...fieldData };
          delete (bulkItem as any).isEnabled;

          const currentItem = updatedStyle.tech_pack[category][field] || { text: '', attachments: [] };

          if (!bulkItem.variants) {
            // Global Update
            currentItem.text = mergeText(currentItem.text, bulkItem.text);
            currentItem.attachments = mergeAttachments(currentItem.attachments, bulkItem.attachments);
            if (bulkItem.consumption_type) currentItem.consumption_type = bulkItem.consumption_type;
            if (bulkItem.consumption_val !== undefined) currentItem.consumption_val = bulkItem.consumption_val;
            if (strategy === 'overwrite') delete (currentItem as any).variants;
          } else {
            // Variant-Based Update
            if (strategy === 'overwrite') {
               currentItem.variants = [];
               delete (currentItem as any).text;
               delete (currentItem as any).attachments;
            } else if (!currentItem.variants) {
               currentItem.variants = [];
            }

            bulkItem.variants.forEach(bulkVar => {
              // Filter colors to only those the style possesses
              const validColors = bulkVar.colors.filter(c => updatedStyle.available_colors?.includes(c));
              if (validColors.length === 0) return; // Skip if no colors match union selection

              let targetVar = currentItem.variants!.find(v => JSON.stringify(v.colors.sort()) === JSON.stringify(validColors.sort()));
              if (!targetVar) {
                targetVar = { colors: validColors, text: '', attachments: [] };
                currentItem.variants!.push(targetVar);
              }

              if (!bulkVar.sizeVariants) {
                targetVar.text = mergeText(targetVar.text, bulkVar.text);
                targetVar.attachments = mergeAttachments(targetVar.attachments, bulkVar.attachments);
                if (bulkVar.consumption_type) targetVar.consumption_type = bulkVar.consumption_type;
                if (bulkVar.consumption_val !== undefined) targetVar.consumption_val = bulkVar.consumption_val;
                if (strategy === 'overwrite') delete (targetVar as any).sizeVariants;
              } else {
                if (strategy === 'overwrite') {
                  targetVar.sizeVariants = [];
                  delete (targetVar as any).text;
                  delete (targetVar as any).attachments;
                } else if (!targetVar.sizeVariants) {
                  targetVar.sizeVariants = [];
                }

                bulkVar.sizeVariants.forEach(bulkSizeVar => {
                  const validSizes = bulkSizeVar.sizes.filter(s => updatedStyle.available_sizes?.includes(s));
                  if (validSizes.length === 0) return;

                  let targetSizeVar = targetVar!.sizeVariants!.find(sv => JSON.stringify(sv.sizes.sort()) === JSON.stringify(validSizes.sort()));
                  if (!targetSizeVar) {
                    targetSizeVar = { sizes: validSizes, text: '', attachments: [] };
                    targetVar!.sizeVariants!.push(targetSizeVar);
                  }

                  targetSizeVar.text = mergeText(targetSizeVar.text, bulkSizeVar.text);
                  targetSizeVar.attachments = mergeAttachments(targetSizeVar.attachments, bulkSizeVar.attachments);
                  if (bulkSizeVar.consumption_type) targetSizeVar.consumption_type = bulkSizeVar.consumption_type;
                  if (bulkSizeVar.consumption_val !== undefined) targetSizeVar.consumption_val = bulkSizeVar.consumption_val;
                });
              }
            });
          }
          updatedStyle.tech_pack[category][field] = currentItem;
        }
        await upsertStyle(updatedStyle);
      }
      alert("Bulk update completed successfully.");
      setIsBulkUpdateModalOpen(false);
      setIsBulkMode(false);
      setSelectedStyleIds([]);
      loadData();
    } catch (err) {
      alert("Error during bulk update: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const toggleSelectStyle = (id: string) => {
    setSelectedStyleIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const applyBulkFilterSelection = (isSelecting: boolean) => {
    const matchingIds = styles.filter(s => {
      const matchesGarment = !bulkSelFilter.garment || s.garment_type === bulkSelFilter.garment;
      const matchesDemographic = !bulkSelFilter.demographic || s.demographic === bulkSelFilter.demographic;
      const matchesCategory = !bulkSelFilter.category || s.category === bulkSelFilter.category;
      return matchesGarment && matchesDemographic && matchesCategory;
    }).map(s => s.id);
    if (isSelecting) setSelectedStyleIds(prev => Array.from(new Set([...prev, ...matchingIds])));
    else setSelectedStyleIds(prev => prev.filter(id => !matchingIds.includes(id)));
  };

  const handleMatrixCellClick = (style: Style, catName: string, fieldName?: string) => {
    setIsEditing(style);
    setEditTarget({ category: catName, field: fieldName });
    setIsAuditViewOpen(false);
  };

  const checkCompleteness = (style: Style, cat: string, field: string) => {
    const item = style.tech_pack[cat]?.[field];
    if (!item) return false;
    return !!( (item.text && item.text.trim() !== '') || (item.attachments && item.attachments.length > 0) || (item.variants && item.variants.length > 0) );
  };

  const handlePrint = (style: Style) => {
    const win = window.open('', 'StylePrint', 'width=1000,height=800');
    if (!win || !template) return;

    // Helper to render attachments in a grid for the printout
    const renderAttachmentsHtml = (attachments: Attachment[]) => {
      if (!attachments || attachments.length === 0) return '';
      const images = attachments.filter(a => a.type === 'image');
      const docs = attachments.filter(a => a.type === 'document');

      let html = '<div style="margin-top: 15px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px;">';
      images.forEach(img => {
        html += `
          <div style="border: 1px solid #e2e8f0; border-radius: 8px; overflow: hidden; break-inside: avoid; background: #fff;">
            <img src="${img.url}" style="width: 100%; display: block;"/>
            <div style="padding: 6px; font-size: 8px; font-weight: bold; background: #fff; text-align: center; color: #64748b; border-top: 1px solid #e2e8f0;">${img.name}</div>
          </div>`;
      });
      html += '</div>';

      if (docs.length > 0) {
        html += '<div style="margin-top: 8px; font-size: 9px; color: #4f46e5; font-weight: bold; padding-left: 5px;">';
        docs.forEach(doc => {
          html += `<div>• DOCUMENT: ${doc.name}</div>`;
        });
        html += '</div>';
      }
      return html;
    };

    const techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
        const fields = cat.fields.map(f => {
            const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
            let contentHtml = '';
            if (item.variants) {
                contentHtml = item.variants.map(v => {
                    let sizeHtml = '';
                    if (v.sizeVariants) {
                        sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                            <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px; break-inside:avoid;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                    ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:16px;">SIZE: ${sz}</span>`).join('')}
                                    ${sv.consumption_type ? `<span style="background:#f1f5f9; color:#1e293b; padding:4px 10px; border-radius:6px; font-weight:bold; font-size:12px;">Ratio: ${sv.consumption_val} ${sv.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</span>` : ''}
                                </div>
                                <div style="font-size:18px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                                ${renderAttachmentsHtml(sv.attachments)}
                            </div>
                        `).join('')}</div>`;
                    }
                    return `
                      <div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;">
                        <div style="margin-bottom:10px; display: flex; justify-content: space-between; align-items: center;">
                          <div>${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div>
                          ${v.consumption_type ? `<div style="font-size: 10px; font-weight: bold; color: #4f46e5;">RATIO: ${v.consumption_val} ${v.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                        </div>
                        <div style="font-size:20px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>
                        ${renderAttachmentsHtml(v.attachments)}
                        ${sizeHtml}
                      </div>`;
                }).join('');
            } else {
              contentHtml = `
                <div style="break-inside:avoid;">
                  <div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">
                    ${item.text || '---'}
                    ${item.consumption_type ? `<div style="margin-top: 10px; font-size: 12px; font-weight: bold; color: #4f46e5; background: #fff; padding: 5px 10px; border-radius: 6px; display: inline-block; border: 1px solid #e2e8f0;">Global Ratio: ${item.consumption_val} ${item.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                  </div>
                  ${renderAttachmentsHtml(item.attachments)}
                </div>`;
            }
            return `
                <div style="margin-bottom:30px; border-bottom:1px solid #eee; padding-bottom:15px; break-inside:avoid;">
                    <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:6px; letter-spacing: 1px;">${f}</div>
                    ${contentHtml}
                </div>`;
        }).join('');
        return `
            <div style="margin-top:40px; page-break-before:always;">
                <h3 style="background:#1e293b; color:#fff; padding:12px 20px; font-size:14px; text-transform:uppercase; letter-spacing:2px; border-radius: 8px;">${cat.name}</h3>
                <div style="padding:15px;">${fields}</div>
            </div>`;
    }).join('');

    win.document.write(`
      <html>
        <head>
          <title>Tech Pack - ${style.style_number}</title>
          <style>
            body { font-family: 'Segoe UI', system-ui, -apple-system, Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; line-height: 1.4; background: #fff; }
            .header { text-align: center; border-bottom: 5px solid #1e293b; padding-bottom: 25px; margin-bottom: 35px; }
            .brand { font-size: 36px; font-weight: 900; text-transform: uppercase; margin: 0; color: #1e293b; }
            .title { font-size: 18px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #64748b; letter-spacing: 2px; }
            .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; }
            .box { padding: 15px; border: 2px solid #e2e8f0; border-radius: 12px; background: #fcfcfc; }
            .label { font-size: 10px; text-transform: uppercase; color: #94a3b8; font-weight: 900; letter-spacing: 1px; }
            .value { font-size: 16px; font-weight: 900; color: #1e293b; margin-top: 4px; }
            .section-title { font-size: 20px; font-weight: 900; border-bottom: 4px solid #1e293b; padding-bottom: 8px; margin-top: 45px; margin-bottom: 20px; text-transform: uppercase; letter-spacing: 1px; color: #1e293b; }
            .summary-box { padding: 25px; border: 2px solid #e2e8f0; min-height: 80px; background:#f8fafc; border-radius:15px; font-size:18px; font-weight: bold; color: #475569; line-height: 1.5; white-space: pre-wrap; }
            @media print {
              body { padding: 20px; }
              @page { margin: 1.5cm; }
            }
          </style>
        </head>
        <body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Master Technical Specification Package</div>
          </div>

          <div class="grid">
            <div class="box"><span class="label">Style Number</span><div class="value">${style.style_number}</div></div>
            <div class="box"><span class="label">Garment Category</span><div class="value">${style.category}</div></div>
            <div class="box"><span class="label">Style Specification</span><div class="value">${style.garment_type || 'N/A'}</div></div>
            <div class="box"><span class="label">Market Segment</span><div class="value">${style.demographic || 'N/A'}</div></div>
            <div class="box"><span class="label">Packing Specs</span><div class="value">${style.packing_type} (${style.pcs_per_box} pcs)</div></div>
            <div class="box"><span class="label">Issue Date</span><div class="value">${new Date().toLocaleDateString()}</div></div>
          </div>

          <div class="section-title">Color & Size Blueprint</div>
          <div style="display: flex; gap: 20px; margin-bottom: 40px;">
            <div style="flex: 1; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
              <span class="label">Approved Palette</span>
              <div style="margin-top: 10px; display: flex; flex-wrap: wrap; gap: 6px;">
                ${(style.available_colors || []).filter(c => c).map(c => `<span style="background:#f1f5f9; color:#1e293b; font-size:10px; font-weight:bold; padding:4px 10px; border-radius:6px; border: 1px solid #e2e8f0; text-transform: uppercase;">${c}</span>`).join('')}
              </div>
            </div>
            <div style="flex: 1; padding: 20px; border: 1px solid #e2e8f0; border-radius: 12px;">
              <span class="label">Size Grid (${style.size_type})</span>
              <div style="margin-top: 10px; display: flex; flex-wrap: wrap; gap: 6px;">
                ${(style.available_sizes || []).map(s => `<span style="background:#4f46e5; color:#fff; font-size:10px; font-weight:bold; padding:4px 10px; border-radius:6px; text-transform: uppercase;">${s}</span>`).join('')}
              </div>
            </div>
          </div>

          <div class="section-title">Global Construction Summary</div>
          <div class="summary-box">
            ${style.style_text || "Standard technical construction procedures apply. No specific summary provided."}
          </div>

          ${techPackHtml}

          <div style="margin-top: 60px; text-align: center; border-top: 1px solid #eee; padding-top: 30px;">
            <div style="font-size: 10px; color: #94a3b8; text-transform: uppercase; font-weight: bold; letter-spacing: 1px;">
              Internal Document Control: Tintura SST Automated Engineering System
            </div>
            <div style="font-size: 8px; color: #cbd5e1; margin-top: 5px;">
              Blueprint ID: ${style.id} | Page 1 of Content
            </div>
          </div>

          <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
        </body>
      </html>`);
    win.document.close();
  };

  const unionColors = Array.from(new Set(styles.flatMap(s => s.available_colors || []))).filter(Boolean).sort();
  const unionSizes = Array.from(new Set(styles.flatMap(s => s.available_sizes || []))).filter(Boolean).sort();

  if (viewingStyle) return <StyleFullView style={viewingStyle} template={template} onBack={() => setViewingStyle(null)} onEdit={() => { setIsEditing(viewingStyle); setViewingStyle(null); }} onPrint={() => handlePrint(viewingStyle)} onDelete={() => handleDelete(viewingStyle.id)} />;

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row justify-between xl:items-center gap-4">
        <div><h2 className="text-3xl font-black text-slate-800 flex items-center gap-3"><div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><BookOpen size={28}/></div>Style Technical Database</h2><p className="text-slate-500 text-sm mt-1">Master Tech-Packs and Design Blueprint Management</p></div>
        <div className="flex items-center gap-3">
          <div className="bg-white p-1 rounded-xl border border-slate-200 shadow-sm flex">
            <button onClick={() => setViewMode('catalog')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'catalog' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><Grid size={18}/> Catalog</button>
            <button onClick={() => setViewMode('compare')} className={`flex items-center gap-2 px-5 py-2 rounded-lg text-sm font-bold transition-all ${viewMode === 'compare' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ArrowLeftRight size={18}/> Compare</button>
          </div>
          <div className="h-8 w-px bg-slate-200 mx-2"></div>

          <button onClick={() => setIsBulkAttributeUpdateOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-green-600 hover:border-green-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Sync Specific Values via CSV"><FileSpreadsheet size={20}/> Sync Values (CSV)</button>

          <button onClick={() => setIsAuditViewOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 hover:border-indigo-500 rounded-xl transition-all flex items-center gap-2 font-bold text-sm" title="Data Completeness Matrix"><Table size={20}/> Matrix Audit</button>
          <button onClick={() => { setIsBulkMode(!isBulkMode); setSelectedStyleIds([]); }} className={`p-3 rounded-xl border transition-all flex items-center gap-2 font-bold text-sm ${isBulkMode ? 'bg-orange-600 text-white border-orange-600 shadow-lg' : 'bg-white border-slate-200 text-slate-500 hover:border-orange-500 hover:text-orange-600'}`}><CheckSquare size={20}/> {isBulkMode ? 'Exit Bulk Mode' : 'Bulk Selection'}</button>
          <button onClick={() => setIsConfigOpen(true)} className="p-3 bg-white border border-slate-200 text-slate-500 hover:text-indigo-600 rounded-xl transition-all"><Settings size={20}/></button>
          <button onClick={handleNewStyle} className="bg-indigo-600 text-white px-6 py-3 rounded-xl flex items-center gap-2 font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><Plus size={20}/> New Style</button>
        </div>
      </div>

      <div className="relative"><input type="text" placeholder="Search by Style Number, Category, or Garment Type..." className="w-full pl-12 pr-4 py-4 rounded-2xl border-2 border-slate-100 focus:border-indigo-500 outline-none transition-all font-bold shadow-sm bg-white text-black" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/><Search className="absolute left-4 top-4 text-slate-400" size={24}/></div>

      {isBulkMode && (
        <div className="bg-slate-900/5 p-6 rounded-3xl border-2 border-dashed border-indigo-200 animate-fade-in">
           <div className="flex flex-col md:flex-row items-end gap-4">
              <div className="flex-1 grid grid-cols-1 md:grid-cols-3 gap-4">
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Garment Type Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.garment} onChange={e => setBulkSelFilter({...bulkSelFilter, garment: e.target.value})}><option value="">All Garment Types</option>{garmentTypeOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Demographic Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.demographic} onChange={e => setBulkSelFilter({...bulkSelFilter, demographic: e.target.value})}><option value="">All Demographics</option>{demographicOptions.map(opt => <option key={opt} value={opt}>{opt}</option>)}</select></div>
                 <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Category Filter</label><select className="w-full border-2 border-slate-100 rounded-xl p-3 bg-white font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-500" value={bulkSelFilter.category} onChange={e => setBulkSelFilter({...bulkSelFilter, category: e.target.value})}><option value="">All Categories</option><option value="Casuals">Casuals</option><option value="Lite">Lite</option><option value="Sportz">Sportz</option></select></div>
              </div>
              <div className="flex gap-2 shrink-0"><button onClick={() => applyBulkFilterSelection(true)} className="px-5 py-3 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all flex items-center gap-2"><CheckSquare size={16}/> Select All Matching</button><button onClick={() => applyBulkFilterSelection(false)} className="px-5 py-3 bg-white text-slate-500 border border-slate-200 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2"><Square size={16}/> Deselect All Matching</button></div>
           </div>
        </div>
      )}

      {viewMode === 'catalog' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in relative pb-24">
          {filteredStyles.map(style => {
            const isSelected = selectedStyleIds.includes(style.id);
            return (
              <div key={style.id} className={`bg-white rounded-2xl border shadow-sm hover:shadow-xl transition-all group overflow-hidden flex flex-col ${isBulkMode && isSelected ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200'}`}>
                <div className="p-6 flex-1 cursor-pointer relative" onClick={() => isBulkMode ? toggleSelectStyle(style.id) : setViewingStyle(style)}>
                  {isBulkMode && <div className="absolute top-4 right-4 z-10">{isSelected ? <CheckSquare className="text-indigo-600"/> : <Square className="text-slate-300"/>}</div>}
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex gap-2">
                      <div className="bg-slate-100 px-3 py-1 rounded-full text-[10px] font-black text-slate-500 uppercase tracking-widest">{style.garment_type}</div>
                      <div className="bg-indigo-50 px-3 py-1 rounded-full text-[10px] font-black text-indigo-500 uppercase tracking-widest">{style.demographic}</div>
                    </div>
                    {!isBulkMode && <div className="flex gap-2" onClick={e => e.stopPropagation()}><button onClick={() => handlePrint(style)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-all"><Printer size={16}/></button><button onClick={() => handleDelete(style.id)} className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"><Trash2 size={16}/></button></div>}
                  </div>
                  <div className="flex items-center justify-between group/title"><h3 className="text-2xl font-black text-slate-800 tracking-tight mb-2 group-hover/title:text-indigo-600 transition-colors">{style.style_number}</h3><ChevronRight size={20} className="text-slate-300 group-hover:text-indigo-600 transition-all transform group-hover:translate-x-1" /></div>
                  <p className="text-slate-500 text-xs font-medium line-clamp-2 leading-relaxed mb-4">{style.style_text || 'No description provided.'}</p>
                </div>
                {!isBulkMode && (
                  <div className="p-4 bg-slate-50 border-t border-slate-100 flex gap-2">
                    <button onClick={() => { setIsEditing(style); setEditTarget(null); }} className="flex-1 py-2.5 bg-white border border-slate-200 rounded-xl text-xs font-black text-slate-700 hover:border-indigo-500 hover:text-indigo-600 transition-all flex items-center justify-center gap-2"><Edit3 size={14}/> Edit</button>
                    <button onClick={(() => handleCopyStyle(style))} className="p-2.5 bg-white text-slate-400 border border-slate-200 rounded-xl hover:text-indigo-600 hover:border-indigo-600 transition-all" title="Create Copy"><Copy size={16}/></button>
                    <button onClick={() => { if (compareList.find(s => s.id === style.id)) setCompareList(prev => prev.filter(s => s.id !== style.id)); else { setCompareList(prev => [...prev, style]); setViewMode('compare'); } }} className={`p-2.5 rounded-xl border transition-all ${compareList.find(s => s.id === style.id) ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-400 border border-slate-200 hover:border-indigo-500 hover:text-indigo-600'}`}><ArrowLeftRight size={18}/></button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {isBulkMode && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-50 animate-slide-up">
           <div className="bg-slate-900 text-white rounded-full px-8 py-4 shadow-2xl flex items-center gap-6 border border-white/10">
              <div className="flex flex-col"><span className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Bulk Actions</span><span className="text-xl font-black">{selectedStyleIds.length} Selected</span></div>
              <div className="h-10 w-px bg-white/20"></div>
              <div className="flex items-center gap-3">
                {selectedStyleIds.length > 0 && <button onClick={() => setIsBulkUpdateModalOpen(true)} className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><Edit3 size={18}/> Edit technical fields</button>}
                <button onClick={() => bulkFileRef.current?.click()} className="bg-orange-600 hover:bg-orange-700 text-white px-6 py-2.5 rounded-full font-black text-sm transition-all active:scale-95 shadow-lg flex items-center gap-2"><FileUp size={18}/> Create Bulk (CSV)</button>
                <input type="file" ref={bulkFileRef} accept=".csv" className="hidden" onChange={handleCSVImport} />
              </div>
              <button onClick={() => { setSelectedStyleIds([]); setIsBulkMode(false); }} className="text-slate-400 hover:text-white transition-colors ml-2"><X/></button>
           </div>
        </div>
      )}

      {viewMode === 'compare' && (
        <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-x-auto min-h-[600px] animate-fade-in">{compareList.length === 0 ? (<div className="p-20 text-center text-slate-400"><ArrowLeftRight size={48} className="mx-auto mb-4 opacity-20"/><p className="text-xl font-bold">Desk Empty</p><button onClick={() => setViewMode('catalog')} className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-xl font-bold">Back to Catalog</button></div>) : (<div className="p-8 inline-flex gap-8">{compareList.map(style => (<div key={style.id} className="w-96 shrink-0 bg-slate-50/50 rounded-3xl border border-slate-200 flex flex-col shadow-inner overflow-hidden"><div className="p-6 bg-white border-b border-slate-200 sticky top-0 z-10"><div className="flex justify-between items-start"><h3 className="text-2xl font-black text-slate-800">{style.style_number}</h3><button onClick={() => setCompareList(prev => prev.filter(s => s.id !== style.id))} className="p-1 text-slate-300 hover:text-red-500 transition-colors"><X size={20}/></button></div><div className="mt-4 flex flex-wrap gap-2"><span className="text-[10px] font-black bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full uppercase">{style.category}</span><span className="text-[10px] font-black bg-slate-100 text-slate-700 px-3 py-1 rounded-full uppercase">{style.garment_type}</span></div></div><div className="p-6 space-y-8 overflow-y-auto">{template?.config.filter(c => c.name !== "General Info").map(cat => (<div key={cat.name}><h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest border-b border-indigo-100 pb-2 mb-4">{cat.name}</h4><div className="space-y-6">{cat.fields.map(field => { const item = style.tech_pack[cat.name]?.[field] || { text: '---', attachments: [] }; return (<div key={field}><div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{field}</div>{!item.variants ? (<div className="text-sm font-medium text-slate-700 whitespace-pre-wrap">{item.text}</div>) : (<div className="space-y-4">{item.variants.map((v, vIdx) => (<div key={vIdx} className="bg-white border rounded-xl p-3 shadow-sm"><div className="flex flex-wrap gap-1 mb-2">{v.colors.map(c => <span key={c} className="bg-indigo-600 text-white text-[8px] font-black px-1.5 py-0.5 rounded uppercase">{c}</span>)}</div><div className="text-xs text-slate-700">{v.text}</div></div>))}</div>)}</div>); })}</div></div>))}</div></div>))}</div>)}</div>
      )}

      {isEditing && (
        <EditorModal 
          isEditing={isEditing} styles={styles} template={template} 
          setIsEditing={setIsEditing} handleSaveStyle={handleSaveStyle} handleCopyStyle={handleCopyStyle} 
          handleFileUpload={handleFileUpload} editTarget={editTarget}
          garmentTypeOptions={garmentTypeOptions} setGarmentTypeOptions={setGarmentTypeOptions}
          demographicOptions={demographicOptions} setDemographicOptions={setDemographicOptions}
          isUploading={isUploading}
        />
      )}

      {isAuditViewOpen && (
        <AuditMatrixModal 
          styles={styles} template={template} onClose={() => setIsAuditViewOpen(false)} 
          onCellClick={handleMatrixCellClick} checkCompleteness={checkCompleteness} 
        />
      )}

      {isBulkUpdateModalOpen && (
        <BulkUpdateModal 
          styles={styles} template={template} selectedStyleIds={selectedStyleIds} 
          bulkUpdateMeta={bulkUpdateMeta} setBulkUpdateMeta={setBulkUpdateMeta} 
          bulkFieldValues={bulkFieldValues} setBulkFieldValues={setBulkFieldValues}
          isUploading={isUploading} setIsUploading={setIsUploading}
          onClose={() => setIsBulkUpdateModalOpen(false)} onExecute={handleBulkUpdate}
          unionColors={unionColors}
          unionSizes={unionSizes}
          orders={orders}
        />
      )}

      {isBulkImportModalOpen && (
        <BulkImportModal 
          bulkImportData={bulkImportData} isUploading={isUploading} 
          onClose={() => setIsBulkImportModalOpen(false)} onExecute={handleExecuteBulkImport} 
        />
      )}

      {isBulkAttributeUpdateOpen && (
        <BulkAttributeUpdateModal 
          styles={styles} 
          template={template} 
          onClose={() => setIsBulkAttributeUpdateOpen(false)} 
          onRefresh={loadData}
        />
      )}
    </div>
  );
};

import React, { useMemo } from 'react';
import { X, RefreshCcw, FilePlus, CheckSquare, Square, Info, Save, Loader2, Plus, Split, Scan, ImageIcon, Trash2, LayoutGrid, Calculator } from 'lucide-react';
import { Style, StyleTemplate, Attachment, TechPackItem, Order, SizeBreakdown } from '../../types';
import { ConsumptionInput } from './ConsumptionInput';
import { uploadOrderAttachment } from '../../services/db';

interface BulkUpdateModalProps {
  styles: Style[];
  template: StyleTemplate | null;
  selectedStyleIds: string[];
  bulkUpdateMeta: {
    strategy: 'overwrite' | 'append';
  };
  setBulkUpdateMeta: (meta: any) => void;
  bulkFieldValues: Record<string, { isEnabled: boolean } & TechPackItem>;
  setBulkFieldValues: (vals: any) => void;
  isUploading: boolean;
  setIsUploading: (val: boolean) => void;
  onClose: () => void;
  onExecute: () => void;
  unionColors: string[];
  unionSizes: string[];
  orders: Order[];
}

export const BulkUpdateModal: React.FC<BulkUpdateModalProps> = ({ 
  styles, 
  template, 
  selectedStyleIds, 
  bulkUpdateMeta, 
  setBulkUpdateMeta, 
  bulkFieldValues, 
  setBulkFieldValues, 
  isUploading, 
  setIsUploading, 
  onClose, 
  onExecute,
  unionColors,
  unionSizes,
  orders
}) => {

  const handleFieldChange = (key: string, updates: Partial<TechPackItem>) => {
    setBulkFieldValues((prev: any) => ({
      ...prev,
      [key]: { ...prev[key], ...updates }
    }));
  };

  const handleSplitColor = (key: string) => {
    const current = bulkFieldValues[key];
    if (!current.variants) {
      handleFieldChange(key, {
        variants: [{ colors: [], text: current.text || '', attachments: current.attachments || [], consumption_type: current.consumption_type, consumption_val: current.consumption_val }]
      });
    } else {
      handleFieldChange(key, {
        variants: [...current.variants, { colors: [], text: '', attachments: [] }]
      });
    }
  };

  const handleAddSizeGroup = (key: string, vIdx: number) => {
    const current = { ...bulkFieldValues[key] };
    const variant = current.variants![vIdx];
    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }
    setBulkFieldValues((prev: any) => ({ ...prev, [key]: current }));
  };

  const handleUnsplit = (key: string) => {
    const current = bulkFieldValues[key];
    if (current.variants) {
      handleFieldChange(key, {
        text: current.variants[0].text,
        attachments: current.variants[0].attachments,
        consumption_type: current.variants[0].consumption_type,
        consumption_val: current.variants[0].consumption_val,
        variants: undefined
      });
    }
  };

  // --- Aggregate Order Data ---
  const productionAggregate = useMemo(() => {
    const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
    const selectedStyleNums = selectedStyles.map(s => s.style_number.toLowerCase());

    // Filter relevant orders (matching any of selected styles)
    const relevantOrders = orders.filter(o => {
      const baseStyleNum = o.style_number.split(' - ')[0].trim().toLowerCase();
      return selectedStyleNums.includes(baseStyleNum);
    });

    const matrix: Record<string, Record<string, number>> = {};
    unionColors.forEach(c => {
      matrix[c] = {};
      unionSizes.forEach(s => {
        matrix[c][s] = 0;
      });
    });

    relevantOrders.forEach(order => {
      const isNumeric = order.size_format === 'numeric';
      const sizeMap = isNumeric 
        ? { 's': '65', 'm': '70', 'l': '75', 'xl': '80', 'xxl': '85', 'xxxl': '90' }
        : { 's': 'S', 'm': 'M', 'l': 'L', 'xl': 'XL', 'xxl': 'XXL', 'xxxl': '3XL' };

      order.size_breakdown?.forEach(row => {
        if (matrix[row.color]) {
          Object.entries(sizeMap).forEach(([key, label]) => {
            if (matrix[row.color][label] !== undefined) {
              matrix[row.color][label] += (row as any)[key] || 0;
            }
          });
        }
      });
    });

    return matrix;
  }, [selectedStyleIds, styles, orders, unionColors, unionSizes]);

  const totalProductionCount = useMemo(() => {
    let total = 0;
    Object.values(productionAggregate).forEach(row => {
      Object.values(row).forEach(val => total += val);
    });
    return total;
  }, [productionAggregate]);

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-[90vw] overflow-hidden animate-scale-up border border-slate-200 flex flex-col max-h-[95vh]">
        <div className="p-8 border-b bg-orange-50 flex justify-between items-center shrink-0">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-orange-600 text-white rounded-2xl shadow-lg">
              <RefreshCcw size={32}/>
            </div>
            <div>
              <h3 className="text-2xl font-black text-orange-900 uppercase tracking-tight">Bulk Blueprint Synchronizer</h3>
              <p className="text-orange-700 text-xs font-bold uppercase tracking-widest mt-1">Applying technical updates to {selectedStyleIds.length} blueprints</p>
            </div>
          </div>
          <button onClick={onClose} className="text-orange-300 hover:text-orange-600 transition-colors p-2"><X size={32}/></button>
        </div>

        <div className="p-8 flex-1 overflow-y-auto space-y-8 bg-slate-50/50">

           {/* NEW: PRODUCTION VOLUME AGGREGATE MATRIX */}
           {totalProductionCount > 0 && (
             <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden animate-fade-in">
                <div className="p-5 border-b bg-slate-900 text-white flex justify-between items-center">
                   <div className="flex items-center gap-3">
                      <LayoutGrid size={20} className="text-indigo-400"/>
                      <h4 className="font-black uppercase tracking-widest text-sm">Aggregated Order Volume (Unit 1 → All)</h4>
                   </div>
                   <div className="flex items-center gap-4">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Batch Volume</span>
                      <span className="text-2xl font-black text-indigo-400">{totalProductionCount} PCS</span>
                   </div>
                </div>
                <div className="overflow-x-auto">
                   <table className="w-full text-center text-xs border-collapse">
                      <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[9px] tracking-widest border-b">
                         <tr>
                            <th className="p-4 text-left border-r sticky left-0 bg-slate-50">Color Variant</th>
                            {unionSizes.map(sz => <th key={sz} className="p-4 border-r">{sz}</th>)}
                            <th className="p-4 bg-slate-100 font-black">Sum</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                         {unionColors.map(color => {
                           const row = productionAggregate[color];
                           const rowTotal = Object.values(row).reduce((a,b) => a+b, 0);
                           if (rowTotal === 0) return null; // Skip empty rows for cleaner view
                           return (
                             <tr key={color} className="hover:bg-indigo-50/30 transition-colors">
                                <td className="p-4 text-left font-black text-slate-800 border-r sticky left-0 bg-white group-hover:bg-indigo-50/30">{color}</td>
                                {unionSizes.map(sz => (
                                  <td key={sz} className={`p-4 border-r tabular-nums font-bold ${row[sz] > 0 ? 'text-indigo-600 bg-indigo-50/20' : 'text-slate-200'}`}>
                                    {row[sz] || '-'}
                                  </td>
                                ))}
                                <td className="p-4 font-black text-slate-900 bg-slate-50 tabular-nums">{rowTotal}</td>
                             </tr>
                           );
                         })}
                      </tbody>
                   </table>
                </div>
             </div>
           )}

           <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="flex-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Merge Strategy</label>
                <div className="flex bg-orange-100/50 p-1 rounded-xl border border-orange-100 max-w-md">
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'overwrite'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'overwrite' ? 'bg-orange-600 text-white shadow-md' : 'text-orange-500 hover:bg-orange-100'}`}>
                    <RefreshCcw size={14}/> Overwrite
                  </button>
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'append'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'append' ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-500 hover:bg-indigo-50'}`}>
                    <FilePlus size={14}/> Append to existing
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-3 text-indigo-500 bg-indigo-50 p-4 rounded-2xl border border-indigo-100 max-w-sm">
                <Info size={24}/>
                <p className="text-[10px] font-bold uppercase leading-relaxed">Splits are based on a union of all database attributes. Attributes not present in a specific style will be ignored during sync.</p>
              </div>
           </div>

           {template?.config.map(cat => (
             <div key={cat.name} className="space-y-4">
                <div className="flex items-center gap-3 px-4">
                  <div className="h-px flex-1 bg-slate-200"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{cat.name}</span>
                  <div className="h-px flex-1 bg-slate-200"></div>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {cat.fields.map(f => {
                    const fieldKey = `${cat.name}|${f}`;
                    const fieldData = bulkFieldValues[fieldKey];
                    if (!fieldData) return null;
                    const isSplit = !!fieldData.variants;

                    return (
                      <div key={f} className={`bg-white rounded-3xl border transition-all duration-300 ${fieldData.isEnabled ? 'border-indigo-500 ring-4 ring-indigo-50 shadow-xl' : 'border-slate-200 opacity-60 grayscale'}`}>
                         <div className="p-6 flex items-center justify-between border-b border-slate-50">
                            <div className="flex items-center gap-4">
                               <button 
                                  onClick={() => setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: { ...prev[fieldKey], isEnabled: !prev[fieldKey].isEnabled } }))}
                                  className={`p-2 rounded-xl transition-all ${fieldData.isEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                               >
                                  {fieldData.isEnabled ? <CheckSquare size={24}/> : <Square size={24}/>}
                               </button>
                               <div>
                                  <h5 className="font-black text-slate-800 uppercase tracking-tight">{f}</h5>
                                  <p className="text-[10px] text-slate-400 font-bold uppercase">Toggle to sync this attribute</p>
                               </div>
                            </div>

                            {fieldData.isEnabled && (
                              <div className="flex items-center gap-4">
                                {!isSplit ? (
                                  <>
                                    <ConsumptionInput 
                                      type={fieldData.consumption_type}
                                      value={fieldData.consumption_val}
                                      onChange={(t, v) => handleFieldChange(fieldKey, { consumption_type: t, consumption_val: v })}
                                      onClear={() => handleFieldChange(fieldKey, { consumption_type: undefined, consumption_val: undefined })}
                                    />
                                    <button type="button" onClick={() => handleSplitColor(fieldKey)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                                  </>
                                ) : (
                                  <button type="button" onClick={() => handleUnsplit(fieldKey)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                                )}
                              </div>
                            )}
                         </div>

                         {fieldData.isEnabled && (
                           <div className="p-6 space-y-6 animate-fade-in bg-slate-50/20">
                              {!isSplit ? (
                                <div className="space-y-4">
                                  <textarea 
                                    className="w-full border-2 border-slate-100 rounded-2xl p-4 h-32 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium bg-white shadow-sm"
                                    placeholder={bulkUpdateMeta.strategy === 'append' ? `Content to append...` : `Content to overwrite...`}
                                    value={fieldData.text || ''}
                                    onChange={e => handleFieldChange(fieldKey, { text: e.target.value })}
                                  />
                                  <div className="flex flex-wrap gap-2">
                                    {fieldData.attachments?.map((a: Attachment, idx: number) => (
                                      <div key={idx} className="flex items-center gap-1.5 bg-indigo-50 px-3 py-1.5 rounded-lg text-[9px] font-black text-indigo-700 border border-indigo-100">
                                        <ImageIcon size={10}/> {a.name} <button onClick={() => handleFieldChange(fieldKey, { attachments: fieldData.attachments.filter((_: any, i: number) => i !== idx) })}><X size={10}/></button>
                                      </div>
                                    ))}
                                    <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-4 py-2 rounded-xl text-[10px] font-black cursor-pointer flex items-center gap-2 transition-all">
                                      <Plus size={14}/> Add File
                                      <input 
                                        type="file" multiple className="hidden" 
                                        onChange={async (e) => {
                                          if (!e.target.files) return;
                                          setIsUploading(true);
                                          const newAtts = [];
                                          const files = Array.from(e.target.files) as File[];
                                          for (const file of files) {
                                            const url = await uploadOrderAttachment(file);
                                            if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                          }
                                          handleFieldChange(fieldKey, { attachments: [...(fieldData.attachments || []), ...newAtts] });
                                          setIsUploading(false);
                                        }}
                                      />
                                    </label>
                                  </div>
                                </div>
                              ) : (
                                <div className="space-y-6">
                                  {fieldData.variants?.map((v, vIdx) => (
                                    <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group/var">
                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants?.splice(vIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover/var:opacity-100 transition-opacity"><X size={16}/></button>

                                      <div className="mb-6 flex flex-col md:flex-row md:items-start justify-between gap-6">
                                        <div className="flex-1">
                                          <div className="flex items-center gap-3 mb-3">
                                            <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Global Attribute Union (Colors)</label>
                                            <div className="flex gap-1 ml-2">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = [...unionColors]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 hover:bg-indigo-100 transition-colors">All</button>
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-slate-500 bg-white px-2 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                            </div>
                                            {!v.sizeVariants && (
                                              <ConsumptionInput 
                                                type={v.consumption_type}
                                                value={v.consumption_val}
                                                onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx] = { ...v, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].consumption_type; delete updated.variants![vIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />
                                            )}
                                          </div>
                                          <div className="flex flex-wrap gap-1.5 max-h-32 overflow-y-auto p-1">
                                            {unionColors.map(color => {
                                              const isSel = v.colors.includes(color);
                                              return (
                                                <button key={color} type="button" onClick={() => { const updated = { ...fieldData }; const varObj = updated.variants![vIdx]; if (isSel) varObj.colors = varObj.colors.filter(c => c !== color); else varObj.colors.push(color); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSel ? 'bg-indigo-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'}`}>{color}</button>
                                              );
                                            })}
                                          </div>
                                        </div>
                                        {!v.sizeVariants && (
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                                        )}
                                      </div>

                                      {!v.sizeVariants ? (
                                        <div className="space-y-4">
                                          <textarea 
                                            className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50/50"
                                            placeholder="Instructions for selected color union..."
                                            value={v.text}
                                            onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                          />
                                          <div className="flex flex-wrap gap-2">
                                            {v.attachments.map((a, aIdx) => (
                                              <div key={aIdx} className="flex items-center gap-1 bg-indigo-50 text-indigo-700 px-2 py-1 rounded text-[9px] font-black border border-indigo-100">
                                                {a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button>
                                              </div>
                                            ))}
                                            <label className="bg-white border-2 border-dashed border-slate-200 text-slate-400 px-3 py-1 rounded-lg text-[10px] font-black cursor-pointer hover:bg-slate-50 transition-all">
                                              + File
                                              <input type="file" multiple className="hidden" onChange={async (e) => {
                                                if (!e.target.files) return;
                                                setIsUploading(true);
                                                const newAtts = [];
                                                const files = Array.from(e.target.files) as File[];
                                                for (const file of files) {
                                                  const url = await uploadOrderAttachment(file);
                                                  if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                }
                                                const updated = { ...fieldData };
                                                updated.variants![vIdx].attachments = [...(updated.variants![vIdx].attachments || []), ...newAtts];
                                                setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                setIsUploading(false);
                                              }}/>
                                            </label>
                                          </div>
                                        </div>
                                      ) : (
                                        <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2">
                                          <div className="flex justify-between items-center"><h6 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Nested Size Sub-Splits</h6><button type="button" onClick={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500">Discard Splits</button></div>
                                          {v.sizeVariants.map((sv, svIdx) => (
                                            <div key={svIdx} className="p-4 bg-blue-50/20 rounded-2xl border border-blue-100 space-y-4 relative group/size">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants?.splice(svIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                                                <div className="flex-1">
                                                  <div className="flex items-center gap-3 mb-2">
                                                    <label className="block text-[9px] font-black text-blue-400 uppercase tracking-widest">Apply to Sizes (Union Selection)</label>
                                                    <div className="flex gap-1">
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = [...unionSizes]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-blue-600 bg-white px-1.5 py-0.5 rounded border border-blue-100 hover:bg-blue-50 transition-colors">All</button>
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-slate-400 bg-white px-1.5 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                                    </div>
                                                  </div>
                                                  <div className="flex flex-wrap gap-1">
                                                    {unionSizes.map(sz => {
                                                      const isSzSel = sv.sizes.includes(sz);
                                                      return (
                                                        <button key={sz} type="button" onClick={() => { const updated = { ...fieldData }; const sVar = updated.variants![vIdx].sizeVariants![svIdx]; if (isSzSel) sVar.sizes = sVar.sizes.filter(s => s !== sz); else sVar.sizes.push(sz); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSzSel ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-blue-300 border border-blue-100 hover:bg-blue-50'}`}>{sz}</button>
                                                      );
                                                    })}
                                                  </div>
                                                </div>
                                                <ConsumptionInput 
                                                  type={sv.consumption_type}
                                                  value={sv.consumption_val}
                                                  onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                  onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_type; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                />
                                              </div>

                                              <textarea 
                                                className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[60px]"
                                                placeholder="Instructions for selected size union..."
                                                value={sv.text}
                                                onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />

                                              <div className="flex flex-wrap gap-2">
                                                {sv.attachments.map((a, aIdx) => (
                                                  <div key={aIdx} className="flex items-center gap-1 bg-white border border-blue-50 px-2 py-1 rounded text-[9px] font-black text-blue-700">{a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button></div>
                                                ))}
                                                <label className="bg-white border-2 border-dashed border-blue-100 text-blue-300 px-3 py-1 rounded-lg text-[9px] font-black cursor-pointer hover:bg-blue-50 transition-all">+ File <input type="file" multiple className="hidden" onChange={async (e) => {
                                                  if (!e.target.files) return;
                                                  setIsUploading(true);
                                                  const newAtts = [];
                                                  const files = Array.from(e.target.files) as File[];
                                                  for (const file of files) {
                                                    const url = await uploadOrderAttachment(file);
                                                    if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                  }
                                                  const updated = { ...fieldData };
                                                  updated.variants![vIdx].sizeVariants![svIdx].attachments = [...(updated.variants![vIdx].sizeVariants![svIdx].attachments || []), ...newAtts];
                                                  setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                  setIsUploading(false);
                                                }}/></label>
                                              </div>
                                            </div>
                                          ))}
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50">+ Add Size Sub-Split</button>
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                  <button type="button" onClick={() => handleSplitColor(fieldKey)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 transition-all">+ Add Bulk Color Group Variant</button>
                                </div>
                              )}
                           </div>
                         )}
                      </div>
                    );
                  })}
                </div>
             </div>
           ))}
        </div>

        <div className="p-8 border-t bg-white flex justify-between items-center shadow-2xl shrink-0">
          <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
          <button 
            onClick={onExecute} 
            disabled={isUploading}
            className="px-12 py-4 bg-orange-600 text-white rounded-2xl font-black shadow-2xl shadow-orange-200 flex items-center gap-3 active:scale-95 disabled:opacity-50 uppercase text-xs"
          >
            {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Save size={20}/>} Sync Selected Blueprint Fields
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo } from 'react';
import { X, RefreshCcw, FilePlus, CheckSquare, Square, Info, Save, Loader2, Plus, Split, Scan, ImageIcon, Trash2, LayoutGrid, Calculator } from 'lucide-react';
import { Style, StyleTemplate, Attachment, TechPackItem, Order, SizeBreakdown } from '../../types';
import { ConsumptionInput } from './ConsumptionInput';
import { uploadOrderAttachment } from '../../services/db';

interface BulkUpdateModalProps {
  styles: Style[];
  template: StyleTemplate | null;
  selectedStyleIds: string[];
  bulkUpdateMeta: {
    strategy: 'overwrite' | 'append';
  };
  setBulkUpdateMeta: (meta: any) => void;
  bulkFieldValues: Record<string, { isEnabled: boolean } & TechPackItem>;
  setBulkFieldValues: (vals: any) => void;
  isUploading: boolean;
  setIsUploading: (val: boolean) => void;
  onClose: () => void;
  onExecute: () => void;
  unionColors: string[];
  unionSizes: string[];
  orders: Order[];
}

export const BulkUpdateModal: React.FC<BulkUpdateModalProps> = ({ 
  styles, 
  template, 
  selectedStyleIds, 
  bulkUpdateMeta, 
  setBulkUpdateMeta, 
  bulkFieldValues, 
  setBulkFieldValues, 
  isUploading, 
  setIsUploading, 
  onClose, 
  onExecute,
  unionColors,
  unionSizes,
  orders
}) => {

  const handleFieldChange = (key: string, updates: Partial<TechPackItem>) => {
    setBulkFieldValues((prev: any) => ({
      ...prev,
      [key]: { ...prev[key], ...updates }
    }));
  };

  const handleSplitColor = (key: string) => {
    const current = bulkFieldValues[key];
    if (!current.variants) {
      handleFieldChange(key, {
        variants: [{ colors: [], text: current.text || '', attachments: current.attachments || [], consumption_type: current.consumption_type, consumption_val: current.consumption_val }]
      });
    } else {
      handleFieldChange(key, {
        variants: [...current.variants, { colors: [], text: '', attachments: [] }]
      });
    }
  };

  const handleAddSizeGroup = (key: string, vIdx: number) => {
    const current = { ...bulkFieldValues[key] };
    const variant = current.variants![vIdx];
    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }
    setBulkFieldValues((prev: any) => ({ ...prev, [key]: current }));
  };

  const handleUnsplit = (key: string) => {
    const current = bulkFieldValues[key];
    if (current.variants) {
      handleFieldChange(key, {
        text: current.variants[0].text,
        attachments: current.variants[0].attachments,
        consumption_type: current.variants[0].consumption_type,
        consumption_val: current.variants[0].consumption_val,
        variants: undefined
      });
    }
  };

  // --- Aggregate Order Data ---
  const productionAggregate = useMemo(() => {
    const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
    const selectedStyleNums = selectedStyles.map(s => s.style_number.toLowerCase());

    // Filter relevant orders (matching any of selected styles)
    const relevantOrders = orders.filter(o => {
      const baseStyleNum = o.style_number.split(' - ')[0].trim().toLowerCase();
      return selectedStyleNums.includes(baseStyleNum);
    });

    const matrix: Record<string, Record<string, number>> = {};
    unionColors.forEach(c => {
      matrix[c] = {};
      unionSizes.forEach(s => {
        matrix[c][s] = 0;
      });
    });

    relevantOrders.forEach(order => {
      const isNumeric = order.size_format === 'numeric';
      const sizeMap = isNumeric 
        ? { 's': '65', 'm': '70', 'l': '75', 'xl': '80', 'xxl': '85', 'xxxl': '90' }
        : { 's': 'S', 'm': 'M', 'l': 'L', 'xl': 'XL', 'xxl': 'XXL', 'xxxl': '3XL' };

      order.size_breakdown?.forEach(row => {
        if (matrix[row.color]) {
          Object.entries(sizeMap).forEach(([key, label]) => {
            if (matrix[row.color][label] !== undefined) {
              matrix[row.color][label] += (row as any)[key] || 0;
            }
          });
        }
      });
    });

    return matrix;
  }, [selectedStyleIds, styles, orders, unionColors, unionSizes]);

  const totalProductionCount = useMemo(() => {
    let total = 0;
    Object.values(productionAggregate).forEach(row => {
      // Fix for Type Error on Operator '+': Explicitly casting val as number
      Object.values(row).forEach(val => total += (val as number));
    });
    return total;
  }, [productionAggregate]);

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-[90vw] overflow-hidden animate-scale-up border border-slate-200 flex flex-col max-h-[95vh]">
        <div className="p-8 border-b bg-orange-50 flex justify-between items-center shrink-0">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-orange-600 text-white rounded-2xl shadow-lg">
              <RefreshCcw size={32}/>
            </div>
            <div>
              <h3 className="text-2xl font-black text-orange-900 uppercase tracking-tight">Bulk Blueprint Synchronizer</h3>
              <p className="text-orange-700 text-xs font-bold uppercase tracking-widest mt-1">Applying technical updates to {selectedStyleIds.length} blueprints</p>
            </div>
          </div>
          <button onClick={onClose} className="text-orange-300 hover:text-orange-600 transition-colors p-2"><X size={32}/></button>
        </div>

        <div className="p-8 flex-1 overflow-y-auto space-y-8 bg-slate-50/50">

           {/* NEW: PRODUCTION VOLUME AGGREGATE MATRIX */}
           {totalProductionCount > 0 && (
             <div className="bg-white rounded-3xl border border-slate-200 shadow-xl overflow-hidden animate-fade-in">
                <div className="p-5 border-b bg-slate-900 text-white flex justify-between items-center">
                   <div className="flex items-center gap-3">
                      <LayoutGrid size={20} className="text-indigo-400"/>
                      <h4 className="font-black uppercase tracking-widest text-sm">Aggregated Order Volume (Unit 1 → All)</h4>
                   </div>
                   <div className="flex items-center gap-4">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Batch Volume</span>
                      <span className="text-2xl font-black text-indigo-400">{totalProductionCount} PCS</span>
                   </div>
                </div>
                <div className="overflow-x-auto">
                   <table className="w-full text-center text-xs border-collapse">
                      <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[9px] tracking-widest border-b">
                         <tr>
                            <th className="p-4 text-left border-r sticky left-0 bg-slate-50">Color Variant</th>
                            {unionSizes.map(sz => <th key={sz} className="p-4 border-r">{sz}</th>)}
                            <th className="p-4 bg-slate-100 font-black">Sum</th>
                         </tr>
                      </thead>
                      <tbody className="divide-y divide-slate-100">
                         {unionColors.map(color => {
                           const row = productionAggregate[color];
                           // Fix for Type Error on Operator '+': Explicitly casting Object.values to number array
                           const rowTotal = (Object.values(row) as number[]).reduce((a,b) => a+b, 0);
                           if (rowTotal === 0) return null; // Skip empty rows for cleaner view
                           return (
                             <tr key={color} className="hover:bg-indigo-50/30 transition-colors">
                                <td className="p-4 text-left font-black text-slate-800 border-r sticky left-0 bg-white group-hover:bg-indigo-50/30">{color}</td>
                                {unionSizes.map(sz => (
                                  <td key={sz} className={`p-4 border-r tabular-nums font-bold ${row[sz] > 0 ? 'text-indigo-600 bg-indigo-50/20' : 'text-slate-200'}`}>
                                    {row[sz] || '-'}
                                  </td>
                                ))}
                                <td className="p-4 font-black text-slate-900 bg-slate-50 tabular-nums">{rowTotal}</td>
                             </tr>
                           );
                         })}
                      </tbody>
                   </table>
                </div>
             </div>
           )}

           <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row items-center justify-between gap-8">
              <div className="flex-1">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Merge Strategy</label>
                <div className="flex bg-orange-100/50 p-1 rounded-xl border border-orange-100 max-w-md">
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'overwrite'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'overwrite' ? 'bg-orange-600 text-white shadow-md' : 'text-orange-500 hover:bg-orange-100'}`}>
                    <RefreshCcw size={14}/> Overwrite
                  </button>
                  <button onClick={() => setBulkUpdateMeta({...bulkUpdateMeta, strategy: 'append'})} className={`flex-1 py-2 rounded-lg text-[10px] font-black uppercase transition-all flex items-center justify-center gap-2 ${bulkUpdateMeta.strategy === 'append' ? 'bg-indigo-600 text-white shadow-md' : 'text-indigo-500 hover:bg-indigo-50'}`}>
                    <FilePlus size={14}/> Append to existing
                  </button>
                </div>
              </div>
              <div className="flex items-center gap-3 text-indigo-500 bg-indigo-50 p-4 rounded-2xl border border-indigo-100 max-w-sm">
                <Info size={24}/>
                <p className="text-[10px] font-bold uppercase leading-relaxed">Splits are based on a union of all database attributes. Attributes not present in a specific style will be ignored during sync.</p>
              </div>
           </div>

           {template?.config.map(cat => (
             <div key={cat.name} className="space-y-4">
                <div className="flex items-center gap-3 px-4">
                  <div className="h-px flex-1 bg-slate-200"></div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em]">{cat.name}</span>
                  <div className="h-px flex-1 bg-slate-200"></div>
                </div>

                <div className="grid grid-cols-1 gap-6">
                  {cat.fields.map(f => {
                    const fieldKey = `${cat.name}|${f}`;
                    const fieldData = bulkFieldValues[fieldKey];
                    if (!fieldData) return null;
                    const isSplit = !!fieldData.variants;

                    return (
                      <div key={f} className={`bg-white rounded-3xl border transition-all duration-300 ${fieldData.isEnabled ? 'border-indigo-500 ring-4 ring-indigo-50 shadow-xl' : 'border-slate-200 opacity-60 grayscale'}`}>
                         <div className="p-6 flex items-center justify-between border-b border-slate-50">
                            <div className="flex items-center gap-4">
                               <button 
                                  onClick={() => setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: { ...prev[fieldKey], isEnabled: !prev[fieldKey].isEnabled } }))}
                                  className={`p-2 rounded-xl transition-all ${fieldData.isEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400'}`}
                               >
                                  {fieldData.isEnabled ? <CheckSquare size={24}/> : <Square size={24}/>}
                               </button>
                               <div>
                                  <h5 className="font-black text-slate-800 uppercase tracking-tight">{f}</h5>
                                  <p className="text-[10px] text-slate-400 font-bold uppercase">Toggle to sync this attribute</p>
                               </div>
                            </div>

                            {fieldData.isEnabled && (
                              <div className="flex items-center gap-4">
                                {!isSplit ? (
                                  <>
                                    <ConsumptionInput 
                                      type={fieldData.consumption_type}
                                      value={fieldData.consumption_val}
                                      onChange={(t, v) => handleFieldChange(fieldKey, { consumption_type: t, consumption_val: v })}
                                      onClear={() => handleFieldChange(fieldKey, { consumption_type: undefined, consumption_val: undefined })}
                                    />
                                    <button type="button" onClick={() => handleSplitColor(fieldKey)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                                  </>
                                ) : (
                                  <button type="button" onClick={() => handleUnsplit(fieldKey)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                                )}
                              </div>
                            )}
                         </div>

                         {fieldData.isEnabled && (
                           <div className="p-6 space-y-6 animate-fade-in bg-slate-50/20">
                              {!isSplit ? (
                                <div className="space-y-4">
                                  <textarea 
                                    className="w-full border-2 border-slate-100 rounded-2xl p-4 h-32 focus:ring-2 focus:ring-indigo-500 outline-none text-sm font-medium bg-white shadow-sm"
                                    placeholder={bulkUpdateMeta.strategy === 'append' ? `Content to append...` : `Content to overwrite...`}
                                    value={fieldData.text || ''}
                                    onChange={e => handleFieldChange(fieldKey, { text: e.target.value })}
                                  />
                                  <div className="flex flex-wrap gap-2">
                                    {fieldData.attachments?.map((a: Attachment, idx: number) => (
                                      <div key={idx} className="flex items-center gap-1.5 bg-indigo-50 px-3 py-1.5 rounded-lg text-[9px] font-black text-indigo-700 border border-indigo-100">
                                        <ImageIcon size={10}/> {a.name} <button onClick={() => handleFieldChange(fieldKey, { attachments: fieldData.attachments.filter((_: any, i: number) => i !== idx) })}><X size={10}/></button>
                                      </div>
                                    ))}
                                    <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-4 py-2 rounded-xl text-[10px] font-black cursor-pointer flex items-center gap-2 transition-all">
                                      <Plus size={14}/> Add File
                                      <input 
                                        type="file" multiple className="hidden" 
                                        onChange={async (e) => {
                                          if (!e.target.files) return;
                                          setIsUploading(true);
                                          const newAtts = [];
                                          const files = Array.from(e.target.files) as File[];
                                          for (const file of files) {
                                            const url = await uploadOrderAttachment(file);
                                            if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                          }
                                          handleFieldChange(fieldKey, { attachments: [...(fieldData.attachments || []), ...newAtts] });
                                          setIsUploading(false);
                                        }}
                                      />
                                    </label>
                                  </div>
                                </div>
                              ) : (
                                <div className="space-y-6">
                                  {fieldData.variants?.map((v, vIdx) => (
                                    <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group/var">
                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants?.splice(vIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover/var:opacity-100 transition-opacity"><X size={16}/></button>

                                      <div className="mb-6 flex flex-col md:flex-row md:items-start justify-between gap-6">
                                        <div className="flex-1">
                                          <div className="flex items-center gap-3 mb-3">
                                            <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Global Attribute Union (Colors)</label>
                                            <div className="flex gap-1 ml-2">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = [...unionColors]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100 hover:bg-indigo-100 transition-colors">All</button>
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].colors = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[8px] font-black uppercase text-slate-500 bg-white px-2 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                            </div>
                                            {!v.sizeVariants && (
                                              <ConsumptionInput 
                                                type={v.consumption_type}
                                                value={v.consumption_val}
                                                onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx] = { ...v, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].consumption_type; delete updated.variants![vIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />
                                            )}
                                          </div>
                                          <div className="flex flex-wrap gap-1.5 max-h-32 overflow-y-auto p-1">
                                            {unionColors.map(color => {
                                              const isSel = v.colors.includes(color);
                                              return (
                                                <button key={color} type="button" onClick={() => { const updated = { ...fieldData }; const varObj = updated.variants![vIdx]; if (isSel) varObj.colors = varObj.colors.filter(c => c !== color); else varObj.colors.push(color); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSel ? 'bg-indigo-600 text-white shadow-sm' : 'bg-slate-50 text-slate-400 border border-slate-100 hover:bg-slate-100'}`}>{color}</button>
                                              );
                                            })}
                                          </div>
                                        </div>
                                        {!v.sizeVariants && (
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                                        )}
                                      </div>

                                      {!v.sizeVariants ? (
                                        <div className="space-y-4">
                                          <textarea 
                                            className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none bg-slate-50/50"
                                            placeholder="Instructions for selected color union..."
                                            value={v.text}
                                            onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                          />
                                          <div className="flex flex-wrap gap-2">
                                            {v.attachments.map((a, aIdx) => (
                                              <div key={aIdx} className="flex items-center gap-1 bg-indigo-50 text-indigo-700 px-2 py-1 rounded text-[9px] font-black border border-indigo-100">
                                                {a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button>
                                              </div>
                                            ))}
                                            <label className="bg-white border-2 border-dashed border-slate-200 text-slate-400 px-3 py-1 rounded-lg text-[10px] font-black cursor-pointer hover:bg-slate-50 transition-all">
                                              + File
                                              <input type="file" multiple className="hidden" onChange={async (e) => {
                                                if (!e.target.files) return;
                                                setIsUploading(true);
                                                const newAtts = [];
                                                const files = Array.from(e.target.files) as File[];
                                                for (const file of files) {
                                                  const url = await uploadOrderAttachment(file);
                                                  if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                }
                                                const updated = { ...fieldData };
                                                updated.variants![vIdx].attachments = [...(updated.variants![vIdx].attachments || []), ...newAtts];
                                                setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                setIsUploading(false);
                                              }}/>
                                            </label>
                                          </div>
                                        </div>
                                      ) : (
                                        <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2">
                                          <div className="flex justify-between items-center"><h6 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Nested Size Sub-Splits</h6><button type="button" onClick={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500">Discard Splits</button></div>
                                          {v.sizeVariants.map((sv, svIdx) => (
                                            <div key={svIdx} className="p-4 bg-blue-50/20 rounded-2xl border border-blue-100 space-y-4 relative group/size">
                                              <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants?.splice(svIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                                                <div className="flex-1">
                                                  <div className="flex items-center gap-3 mb-2">
                                                    <label className="block text-[9px] font-black text-blue-400 uppercase tracking-widest">Apply to Sizes (Union Selection)</label>
                                                    <div className="flex gap-1">
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = [...unionSizes]; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-blue-600 bg-white px-1.5 py-0.5 rounded border border-blue-100 hover:bg-blue-50 transition-colors">All</button>
                                                      <button type="button" onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].sizes = []; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className="text-[7px] font-black uppercase text-slate-400 bg-white px-1.5 py-0.5 rounded border border-slate-200 hover:bg-slate-50 transition-colors">None</button>
                                                    </div>
                                                  </div>
                                                  <div className="flex flex-wrap gap-1">
                                                    {unionSizes.map(sz => {
                                                      const isSzSel = sv.sizes.includes(sz);
                                                      return (
                                                        <button key={sz} type="button" onClick={() => { const updated = { ...fieldData }; const sVar = updated.variants![vIdx].sizeVariants![svIdx]; if (isSzSel) sVar.sizes = sVar.sizes.filter(s => s !== sz); else sVar.sizes.push(sz); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }} className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isSzSel ? 'bg-blue-600 text-white shadow-sm' : 'bg-white text-blue-300 border border-blue-100 hover:bg-blue-50'}`}>{sz}</button>
                                                      );
                                                    })}
                                                  </div>
                                                </div>
                                                <ConsumptionInput 
                                                  type={sv.consumption_type}
                                                  value={sv.consumption_val}
                                                  onChange={(t, val) => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: val }; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                  onClear={() => { const updated = { ...fieldData }; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_type; delete updated.variants![vIdx].sizeVariants![svIdx].consumption_val; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                                />
                                              </div>

                                              <textarea 
                                                className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[60px]"
                                                placeholder="Instructions for selected size union..."
                                                value={sv.text}
                                                onChange={e => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].text = e.target.value; setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}
                                              />

                                              <div className="flex flex-wrap gap-2">
                                                {sv.attachments.map((a, aIdx) => (
                                                  <div key={aIdx} className="flex items-center gap-1 bg-white border border-blue-50 px-2 py-1 rounded text-[9px] font-black text-blue-700">{a.name} <button onClick={() => { const updated = { ...fieldData }; updated.variants![vIdx].sizeVariants![svIdx].attachments.splice(aIdx, 1); setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated })); }}><X size={10}/></button></div>
                                                ))}
                                                <label className="bg-white border-2 border-dashed border-blue-100 text-blue-300 px-3 py-1 rounded-lg text-[9px] font-black cursor-pointer hover:bg-blue-50 transition-all">+ File <input type="file" multiple className="hidden" onChange={async (e) => {
                                                  if (!e.target.files) return;
                                                  setIsUploading(true);
                                                  const newAtts = [];
                                                  const files = Array.from(e.target.files) as File[];
                                                  for (const file of files) {
                                                    const url = await uploadOrderAttachment(file);
                                                    if (url) newAtts.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
                                                  }
                                                  const updated = { ...fieldData };
                                                  updated.variants![vIdx].sizeVariants![svIdx].attachments = [...(updated.variants![vIdx].sizeVariants![svIdx].attachments || []), ...newAtts];
                                                  setBulkFieldValues((prev: any) => ({ ...prev, [fieldKey]: updated }));
                                                  setIsUploading(false);
                                                }}/></label>
                                              </div>
                                            </div>
                                          ))}
                                          <button type="button" onClick={() => handleAddSizeGroup(fieldKey, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50">+ Add Size Sub-Split</button>
                                        </div>
                                      )}
                                    </div>
                                  ))}
                                  <button type="button" onClick={() => handleSplitColor(fieldKey)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 transition-all">+ Add Bulk Color Group Variant</button>
                                </div>
                              )}
                           </div>
                         )}
                      </div>
                    );
                  })}
                </div>
             </div>
           ))}
        </div>

        <div className="p-8 border-t bg-white flex justify-between items-center shadow-2xl shrink-0">
          <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
          <button 
            onClick={onExecute} 
            disabled={isUploading}
            className="px-12 py-4 bg-orange-600 text-white rounded-2xl font-black shadow-2xl shadow-orange-200 flex items-center gap-3 active:scale-95 disabled:opacity-50 uppercase text-xs"
          >
            {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Save size={20}/>} Sync Selected Blueprint Fields
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { fetchStyles, upsertStyle, fetchStyleTemplate, deleteStyle, uploadOrderAttachment, fetchOrders } from '../services/db';
import { Style, StyleTemplate, Attachment, TechPackItem, ConsumptionType, Order } from '../types';
import { 
  Plus, Search, Grid, Copy, Trash2, Settings, ArrowLeftRight, CheckSquare, Square, FileUp, Table, BookOpen, ChevronRight, Edit3, Printer, X, FileSpreadsheet
} from 'lucide-react';

// Imported modular components
import { StyleFullView } from '../components/style-db/StyleFullView';
import { AuditMatrixModal } from '../components/style-db/AuditMatrixModal';
import { BulkUpdateModal } from '../components/style-db/BulkUpdateModal';
import { BulkImportModal } from '../components/style-db/BulkImportModal';
import { EditorModal } from '../components/style-db/EditorModal';
import { BulkAttributeUpdateModal } from '../components/style-db/BulkAttributeUpdateModal';

export const StyleDatabase: React.FC = () => {
  const [styles, setStyles] = useState<Style[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [template, setTemplate] = useState<StyleTemplate | null>(null);
  const [viewMode, setViewMode] = useState<'catalog' | 'compare'>('catalog');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<Style | null>(null);
  const [viewingStyle, setViewingStyle] = useState<Style | null>(null);
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [compareList, setCompareList] = useState<Style[]>([]);
  const [isUploading, setIsUploading] = useState(false);
  const [garmentTypeOptions, setGarmentTypeOptions] = useState(['Pant', 'Trackpant', 'Shorts', 'T-shirt']);
  const [demographicOptions, setDemographicOptions] = useState(['Men', 'Boys']);
  const [isAuditViewOpen, setIsAuditViewOpen] = useState(false);
  const [editTarget, setEditTarget] = useState<{ category?: string, field?: string } | null>(null);

  // Bulk Mode States
  const [isBulkMode, setIsBulkMode] = useState(false);
  const [selectedStyleIds, setSelectedStyleIds] = useState<string[]>([]);
  const [isBulkUpdateModalOpen, setIsBulkUpdateModalOpen] = useState(false);
  const [isBulkImportModalOpen, setIsBulkImportModalOpen] = useState(false);
  const [isBulkAttributeUpdateOpen, setIsBulkAttributeUpdateOpen] = useState(false);
  const [bulkImportData, setBulkImportData] = useState<any[]>([]);
  const bulkFileRef = useRef<HTMLInputElement>(null);

  // Bulk Selection Filters
  const [bulkSelFilter, setBulkSelFilter] = useState({ garment: '', demographic: '', category: '' });

  // Revised Bulk Update Form Structure
  const [bulkUpdateMeta, setBulkUpdateMeta] = useState<{
    strategy: 'overwrite' | 'append';
  }>({
    strategy: 'overwrite'
  });

  const [bulkFieldValues, setBulkFieldValues] = useState<Record<string, {
    isEnabled: boolean;
  } & TechPackItem>>({});

  const loadData = async () => {
    const [s, t, o] = await Promise.all([fetchStyles(), fetchStyleTemplate(), fetchOrders()]);
    setStyles(s);
    setTemplate(t);
    setOrders(o);
    const existingGarments = Array.from(new Set([...garmentTypeOptions, ...s.map(style => style.garment_type).filter(Boolean) as string[]]));
    const existingDemos = Array.from(new Set([...demographicOptions, ...s.map(style => style.demographic).filter(Boolean) as string[]]));
    setGarmentTypeOptions(existingGarments);
    setDemographicOptions(existingDemos);

    if (t) {
      const initialValues: Record<string, any> = {};
      t.config.forEach(cat => {
        cat.fields.forEach(f => {
          initialValues[`${cat.name}|${f}`] = { isEnabled: false, text: '', attachments: [] };
        });
      });
      setBulkFieldValues(initialValues);
    }
  };

  useEffect(() => { loadData(); }, []);

  const filteredStyles = styles.filter(s => 
    s.style_number.toLowerCase().includes(searchTerm.toLowerCase()) || 
    s.category.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (s.garment_type && s.garment_type.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const handleSaveStyle = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isEditing) return;
    setIsUploading(true);
    const payload: Partial<Style> = { ...isEditing };
    if (!payload.id || payload.id === "") delete payload.id;
    const { error } = await upsertStyle(payload);
    setIsUploading(false);
    if (!error) { 
      setIsEditing(null); 
      setEditTarget(null);
      loadData(); 
    } else { 
      alert(error); 
    }
  };

  const handleNewStyle = () => {
    setIsEditing({ 
      id: '', style_number: '', category: 'Casuals', packing_type: 'pouch', pcs_per_box: 0, 
      style_text: '', garment_type: 'T-shirt', demographic: 'Men', 
      available_colors: [''], available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL'], 
      size_type: 'letter', tech_pack: {} 
    });
    setEditTarget(null);
  };

  const handleCopyStyle = (sourceStyle: Style) => {
    const copy = JSON.parse(JSON.stringify(sourceStyle));
    copy.id = ''; 
    copy.style_number = `${sourceStyle.style_number} (Copy)`;
    setIsEditing(copy);
    setEditTarget(null);
  };

  const handleDelete = async (id: string) => { 
    if (confirm("Permanently delete this style?")) { await deleteStyle(id); loadData(); setViewingStyle(null); } 
  };

  const handleFileUpload = async (category: string, field: string, files: FileList | null, vIdx?: number, svIdx?: number) => {
    if (!files || !isEditing) return;
    setIsUploading(true);
    const updated = { ...isEditing };
    if (!updated.tech_pack[category]) updated.tech_pack[category] = {};
    if (!updated.tech_pack[category][field]) updated.tech_pack[category][field] = { text: '', attachments: [] };

    let target: Attachment[];
    if (vIdx !== undefined) {
      const variant = updated.tech_pack[category][field].variants![vIdx];
      if (svIdx !== undefined) target = variant.sizeVariants![svIdx].attachments;
      else target = variant.attachments;
    } else {
      target = updated.tech_pack[category][field].attachments;
    }

    const filesArr = Array.from(files) as File[];
    for (const file of filesArr) {
      const url = await uploadOrderAttachment(file);
      if (url) target.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
    }
    setIsEditing(updated);
    setIsUploading(false);
  };

  const handleCSVImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');
      const splitCSV = (row: string) => {
          const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
          return row.split(regex).map(val => {
              let cleaned = val.trim();
              if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
                  cleaned = cleaned.substring(1, cleaned.length - 1);
              }
              return cleaned;
          });
      };
      const headers = splitCSV(lines[0]).map(h => h.trim());
      const parsedData = lines.slice(1).map(line => {
        const values = splitCSV(line);
        if (values.length < headers.length) return null;
        const entry: any = {};
        headers.forEach((header, i) => entry[header] = values[i]);
        return entry;
      }).filter(Boolean);
      setBulkImportData(parsedData);
      setIsBulkImportModalOpen(true);
    };
    reader.readAsText(file);
    e.target.value = ''; 
  };

  const handleExecuteBulkImport = async () => {
    setIsUploading(true);
    try {
      for (const row of bulkImportData) {
        const styleNum = row['Style No.'] || row['Style No'] || row['StyleNo'];
        const gType = row['GarmentType'] || row['Garment Type'] || row['Garment'];
        const demo = row['Demographic'] || row['Demo'];
        const cat = row['Category'] || row['Cat'];
        const desc = row['Short description'] || row['Description'] || row['Short Description'];
        const cols = row['Available colours'] || row['Available colors'] || row['Colours'] || row['Colors'];
        const sizes = row['size variants'] || row['Size variants'] || row['Sizes'];
        const fabricValue = row['fabric'] || row['Fabric'];

        const newStyle: Partial<Style> = {
          style_number: styleNum || 'NEW-STYLE',
          garment_type: gType || 'T-shirt',
          demographic: demo || 'Men',
          category: cat || 'Casuals',
          style_text: desc || '',
          available_colors: (cols || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          available_sizes: (sizes || '').split(',').map((s: string) => s.trim()).filter(Boolean),
          packing_type: 'pouch',
          pcs_per_box: 1,
          tech_pack: {},
          size_type: (sizes || '').match(/[a-zA-Z]/) ? 'letter' : 'number'
        };

        if (fabricValue) {
          const fabricNote = `Fabrication: ${fabricValue}`;
          newStyle.style_text = newStyle.style_text ? `${newStyle.style_text}\n${fabricNote}` : fabricNote;
        }
        await upsertStyle(newStyle);
      }
      alert(`Successfully created ${bulkImportData.length} new styles.`);
      setIsBulkImportModalOpen(false);
      setIsBulkMode(false);
      loadData();
    } catch (err) {
      alert("Import failed: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const handleBulkUpdate = async () => {
    if (selectedStyleIds.length === 0) return;
    setIsUploading(true);
    try {
      const selectedStyles = styles.filter(s => selectedStyleIds.includes(s.id));
      const enabledUpdates = (Object.entries(bulkFieldValues) as [string, typeof bulkFieldValues[string]][]).filter(([_, val]) => val.isEnabled);
      if (enabledUpdates.length === 0) {
        alert("Please select at least one field to update.");
        setIsUploading(false);
        return;
      }

      for (const style of selectedStyles) {
        const updatedStyle = JSON.parse(JSON.stringify(style));
        const { strategy } = bulkUpdateMeta;

        for (const [key, fieldData] of enabledUpdates) {
          const [category, field] = key.split('|');
          if (!updatedStyle.tech_pack[category]) updatedStyle.tech_pack[category] = {};

          const mergeText = (current: string, next: string) => strategy === 'overwrite' ? next : (current ? current + '\n' + next : next);
          const mergeAttachments = (current: Attachment[], next: Attachment[]) => strategy === 'overwrite' ? next : [...(current || []), ...next];

          // Use the TechPackItem structure directly from bulkFieldValues
          const bulkItem = { ...fieldData };
          delete (bulkItem as any).isEnabled;

          const currentItem = updatedStyle.tech_pack[category][field] || { text: '', attachments: [] };

          if (!bulkItem.variants) {
            // Global Update
            currentItem.text = mergeText(currentItem.text, bulkItem.text);
            currentItem.attachments = mergeAttachments(currentItem.attachments, bulkItem.attachments);
            if (bulkItem.consumption_type) currentItem.consumption_type = bulkItem.consumption_type;
            if (bulkItem.consumption_val !== undefined) currentItem.consumption_val = bulkItem.consumption_val;
            if (strategy === 'overwrite') delete (currentItem as any).variants;
          } else {
            // Variant-Based Update
            if (strategy === 'overwrite') {
               currentItem.variants = [];
               delete (currentItem as any).text;
               delete (currentItem as any).attachments;
            } else if (!currentItem.variants) {
               currentItem.variants = [];
            }

            bulkItem.variants.forEach(bulkVar => {
              // Filter colors to only those the style possesses
              const validColors = bulkVar.colors.filter(c => updatedStyle.available_colors?.includes(c));
              if (validColors.length === 0) return; // Skip if no colors match union selection

              let targetVar = currentItem.variants!.find(v => JSON.stringify(v.colors.sort()) === JSON.stringify(validColors.sort()));
              if (!targetVar) {
                targetVar = { colors: validColors, text: '', attachments: [] };
                currentItem.variants!.push(targetVar);
              }

              if (!bulkVar.sizeVariants) {
                targetVar.text = mergeText(targetVar.text, bulkVar.text);
                targetVar.attachments = mergeAttachments(targetVar.attachments, bulkVar.attachments);
                if (bulkVar.consumption_type) targetVar.consumption_type = bulkVar.consumption_type;
                if (bulkVar.consumption_val !== undefined) targetVar.consumption_val = bulkVar.consumption_val;
                if (strategy === 'overwrite') delete (targetVar as any).sizeVariants;
              } else {
                if (strategy === 'overwrite') {
                  targetVar.sizeVariants = [];
                  delete (targetVar as any).text;
                  delete (targetVar as any).attachments;
                } else if (!targetVar.sizeVariants) {
                  targetVar.sizeVariants = [];
                }

                bulkVar.sizeVariants.forEach(bulkSizeVar => {
                  const validSizes = bulkSizeVar.sizes.filter(s => updatedStyle.available_sizes?.includes(s));
                  if (validSizes.length === 0) return;

                  let targetSizeVar = targetVar!.sizeVariants!.find(sv => JSON.stringify(sv.sizes.sort()) === JSON.stringify(validSizes.sort()));
                  if (!targetSizeVar) {
                    targetSizeVar = { sizes: validSizes, text: '', attachments: [] };
                    targetVar!.sizeVariants!.push(targetSizeVar);
                  }

                  targetSizeVar.text = mergeText(targetSizeVar.text, bulkSizeVar.text);
                  targetSizeVar.attachments = mergeAttachments(targetSizeVar.attachments, bulkSizeVar.attachments);
                  if (bulkSizeVar.consumption_type) targetSizeVar.consumption_type = bulkSizeVar.consumption_type;
                  if (bulkSizeVar.consumption_val !== undefined) targetSizeVar.consumption_val = bulkSizeVar.consumption_val;
                });
              }
            });
          }
          updatedStyle.tech_pack[category][field] = currentItem;
        }
        await upsertStyle(updatedStyle);
      }
      alert("Bulk update completed successfully.");
      setIsBulkUpdateModalOpen(false);
      setIsBulkMode(false);
      setSelectedStyleIds([]);
      loadData();
    } catch (err) {
      alert("Error during bulk update: " + err);
    } finally {
      setIsUploading(false);
    }
  };

  const toggleSelectStyle = (id: string) => {
    setSelectedStyleIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const applyBulkFilterSelection = (isSelecting: boolean) => {
    const matchingIds = styles.filter(s => {
      const matchesGarment = !bulkSelFilter.garment || s.garment_type === bulkSelFilter.garment;
      const matchesDemographic = !bulkSelFilter.demographic || s.demographic === bulkSelFilter.demographic;
      const matchesCategory = !bulkSelFilter.category || s.category === bulkSelFilter.category;
      return matchesGarment && matchesDemographic && matchesCategory;
    }).map(s => s.id);
    if (isSelecting) setSelectedStyleIds(prev => Array.from(new Set([...prev, ...matchingIds])));
    else setSelectedStyleIds(prev => prev.filter(id => !matchingIds.includes(id)));
  };

  const handleMatrixCellClick = (style: Style, catName: string, fieldName?: string) => {
    setIsEditing(style);
    setEditTarget({ category: catName, field: fieldName });
    setIsAuditViewOpen(false);
  };

  const checkCompleteness = (style: Style, cat: string, field: string) => {
    const item = style.tech_pack[cat]?.[field];
    if (!item) return false;
    return !!( (item.text && item.text.trim() !== '') || (item.attachments && item.attachments.length > 0) || (item.variants && item.variants.length > 0) );
  };

  const handlePrint = (style: Style) => {
    const win = window.open('', 'StylePrint', 'width=1200,height=900');
    if (!win || !template) return;

    // Enhanced Adaptive Grid for Attachments
    const renderAttachmentsHtml = (attachments: Attachment[]) => {
      if (!attachments || attachments.length === 0) return '';
      const images = attachments.filter(a => a.type === 'image');
      const docs = attachments.filter(a => a.type === 'document');

      let gridCols = '1fr';
      if (images.length === 2) gridCols = '1fr 1fr';
      else if (images.length >= 3) gridCols = '1fr 1fr 1fr';

      let html = `<div style="margin-top: 20px; display: grid; grid-template-columns: ${gridCols}; gap: 15px; width: 100%;">`;
      images.forEach(img => {
        html += `
          <div style="border: 2px solid #e2e8f0; border-radius: 12px; overflow: hidden; break-inside: avoid; background: #fff; width: 100%;">
            <img src="${img.url}" style="width: 100%; display: block; object-fit: contain; max-height: 500px;"/>
            <div style="padding: 10px; font-size: 10px; font-weight: 900; background: #f8fafc; text-align: center; color: #1e293b; border-top: 1px solid #e2e8f0; text-transform: uppercase; letter-spacing: 1px;">
              ${img.name}
            </div>
          </div>`;
      });
      html += '</div>';

      if (docs.length > 0) {
        html += '<div style="margin-top: 12px; font-size: 11px; color: #4f46e5; font-weight: 900; padding: 10px; background: #f0f4ff; border-radius: 8px; border-left: 5px solid #4f46e5;">';
        docs.forEach(doc => {
          html += `<div>• TECHNICAL DOCUMENT: ${doc.name}</div>`;
        });
        html += '</div>';
      }
      return html;
    };

    const techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
        const fields = cat.fields.map(f => {
            const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
            let contentHtml = '';
            if (item.variants) {
                contentHtml = item.variants.map(v => {
                    let sizeHtml = '';
                    if (v.sizeVariants) {
                        sizeHtml = `<div style="margin-top:20px; display:grid; grid-template-columns:1fr; gap:15px;">${v.sizeVariants.map(sv => `
                            <div style="background:#fff; border:2px solid #e2e8f0; border-left:12px solid #2563eb; padding:25px; border-radius:15px; break-inside:avoid; box-shadow: 0 4px 6px -1px rgba(0,0,0,0.1);">
                                <div style="margin-bottom:15px; display:flex; flex-wrap:wrap; gap:10px; align-items: center;">
                                    ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:6px 12px; border-radius:8px; font-weight:900; font-size:18px; letter-spacing:1px;">SIZE: ${sz}</span>`).join('')}
                                    ${sv.consumption_type ? `<span style="background:#f8fafc; color:#1e293b; border: 1px solid #e2e8f0; padding:6px 12px; border-radius:8px; font-weight:900; font-size:12px; text-transform:uppercase;">Ratio: ${sv.consumption_val} ${sv.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</span>` : ''}
                                </div>
                                <div style="font-size:22px; font-weight:900; color:#1e293b; line-height:1.4; letter-spacing: -0.01em;">${sv.text || '---'}</div>
                                ${renderAttachmentsHtml(sv.attachments)}
                            </div>
                        `).join('')}</div>`;
                    }
                    return `
                      <div style="border:3px solid #e2e8f0; padding:30px; border-radius:20px; margin-top:20px; background:#f8fafc; break-inside:avoid; position: relative;">
                        <div style="margin-bottom:20px; display: flex; justify-content: space-between; align-items: center;">
                          <div style="display: flex; gap: 8px;">${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:12px; font-weight:900; padding:6px 15px; border-radius:8px; text-transform:uppercase; letter-spacing:1px;">${c}</span>`).join('')}</div>
                          ${v.consumption_type ? `<div style="font-size: 12px; font-weight: 900; color: #4f46e5; background: #fff; padding: 6px 12px; border-radius: 8px; border: 1px solid #e2e8f0;">MASTER RATIO: ${v.consumption_val} ${v.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                        </div>
                        <div style="font-size:24px; color:#1e293b; font-weight:900; line-height:1.4; margin-bottom: 20px;">${v.text || '---'}</div>
                        ${renderAttachmentsHtml(v.attachments)}
                        ${sizeHtml}
                      </div>`;
                }).join('');
            } else {
              contentHtml = `
                <div style="break-inside:avoid; width: 100%;">
                  <div style="font-size:28px; font-weight:900; color:#1e293b; background:#f8fafc; padding:35px; border-radius:20px; border:3px solid #e2e8f0; line-height:1.4; width: 100%; box-sizing: border-box;">
                    ${item.text || '---'}
                    ${item.consumption_type ? `<div style="margin-top: 15px; font-size: 14px; font-weight: 900; color: #4f46e5; background: #fff; padding: 8px 15px; border-radius: 8px; display: inline-block; border: 1px solid #e2e8f0; text-transform: uppercase;">Global Yield: ${item.consumption_val} ${item.consumption_type === 'items_per_pc' ? 'Items/PC' : 'PCS/Item'}</div>` : ''}
                  </div>
                  ${renderAttachmentsHtml(item.attachments)}
                </div>`;
            }
            return `
                <div style="margin-bottom:40px; border-bottom:2px solid #f1f5f9; padding-bottom:30px; break-inside:avoid; width: 100%;">
                    <div style="font-size:14px; font-weight:900; color:#94a3b8; text-transform:uppercase; margin-bottom:12px; letter-spacing: 2px;">${f}</div>
                    ${contentHtml}
                </div>`;
        }).join('');
        return `
            <div style="margin-top:50px; page-break-before:always; width: 100%;">
                <h3 style="background:#1e293b; color:#fff; padding:15px 25px; font-size:18px; text-transform:uppercase; letter-spacing:3px; border-radius: 12px; margin-bottom: 30px;">${cat.name}</h3>
                <div style="padding:0 10px;">${fields}</div>
            </div>`;
    }).join('');

    win.document.write(`
      <html>
        <head>
          <title>Tech Pack - ${style.style_number}</title>
          <style>
            @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;700;900&display=swap');
